var job_ch_6_Verses = [
  {num:1,words:[["Ua tali atu Iopu, ua fapea atu, E!", "But Job answered and said,"]]},
  {num:2,words:[["Ana matuā fuatia lo'u tiga;", "Oh that my grief were throughly weighed,"], ["ana avae foi faatasi lo'u malaia i le fua faatautau.", "and my calamity laid in the balances together!"]]},
  {num:3,words:[["Po o pe na ua iloa ua sili lona mamafa i le oneone o le sami;", "For now it would be heavier than the sand of the sea:"], ["o le mea lea ua soona fai ai a'u upu.", "therefore my words are swallowed up."]]},
  {num:4,words:[["Aua o loo i totonu ia te au o u fanafana a Le e ona le malosi uma lava;", "For the arrows of the Almighty are within me,"], ["o le mea oona o i ai e inumia ai lo'u agaga;", "the poison whereof drinketh up my spirit:"], ["o loo pae tau mai ia te au o mea matautia mai le Atua.", "the terrors of God do set themselves in array against me."]]},
  {num:5,words:[["Pe tagi ea le asini o le vao ina o iai i le vao mu'a? Pe tagi foi le povi ua i ona luma ana mea e 'ai?", "Doth the wild ass bray when he hath grass? or loweth the ox over his fodder?"]]},
  {num:6,words:[["Pe 'aina ea le mea ua le namumea pe a le ināia i le masima? Pe ai ea se manogi i le niu o le fuāmoa?", "Can that which is unsavoury be eaten without salt? or is there any taste in the white of an egg?"]]},
  {num:7,words:[["O mea sa ou le mafai ona tago i ai, ua avea ia ma a'u mea e 'ai e peiseai ua leaga.", "The things that my soul refused to touch are as my sorrowful meat."]]},
  {num:8,words:[["E! Ana maua le mea na ou faatoga i ai;", "Oh that I might have my request;"], ["ana foaiina mai foi e le Atua le mea na ou naunau i ai;", "and that God would grant me the thing that I long for!"]]},
  {num:9,words:[["ia finagalo le Atua e tu'imomomo ia te au,", "Even that it would please God to destroy me;"], ["ia tuu mai e ia lona aao,", "that he would let loose his hand,"], ["ma vavaeeseina a'u.", "and cut me off!"]]},
  {num:10,words:[["Ona i ai pea lea sina o'u faamatalaloto;", "Then should I yet have comfort;"], ["ou te olioli foi i le tiga;", "yea,"], ["aua na te faasaoina;", "I would harden myself in sorrow: let him not spare;"], ["auā sa ou le natia afioga a le Paia.", "for I have not concealed the words of the Holy One."]]},
  {num:11,words:[["Po o le a ea lo'u malosi,", "What is my strength,"], ["ou te faamoemoe ai i se mea? Po o le a foi lo'u iuga,", "that I should hope? and what is mine end,"], ["ou te faatoatoa ai pea?", "that I should prolong my life?"]]},
  {num:12,words:[["O le malosi o maa o lo'u malosi ea lea? O lo'u tino o le 'apa memea ea lea?", "Is my strength the strength of stones? or is my flesh of brass?"]]},
  {num:13,words:[["Aue! E leai so'u fesoasoani ia te au lava; ua sola ese foi ia te au le faaolataga.", "Is not my help in me? and is wisdom driven quite from me?"]]},
  {num:14,words:[["O le ua tigaina e tatau ona alofagia o ia e lana uo;", "To him that is afflicted pity should be shewed from his friend;"], ["a ua tuua e ia le mata'u i Le e ona le malosi uma lava.", "but he forsaketh the fear of the Almighty."]]},
  {num:15,words:[["Ua faa'ole'ole o'u uso e pei o le alia,", "My brethren have dealt deceitfully as a brook,"], ["ua mavae atu i latou e pei o tafe o alia.", "and as the stream of brooks they pass away;"]]},
  {num:16,words:[["Ua suaeleele ia ona o le vaito'a;", "Which are blackish by reason of the ice,"], ["ua lilo ai le kiona.", "and wherein the snow is hid:"]]},
  {num:17,words:[["O ona po e maui ai,", "What time they wax warm,"], ["e mamate ai lava;", "they vanish:"], ["pe a velasia,", "when it is hot,"], ["ona pe ai lea i mea sa i ai.", "they are consumed out of their place."]]},
  {num:18,words:[["Ua tuua e malaga lo latou ala ua afe,", "The paths of their way are turned aside;"], ["ua o ae i le vao,", "they go to nothing,"], ["ona fano ai lea o i latou.", "and perish."]]},
  {num:19,words:[["Na vaavaai atu malaga a sa Temā,", "The troops of Tema looked,"], ["na faamoemoe i ai malaga a Seepa.", "the companies of Sheba waited for them."]]},
  {num:20,words:[["Na masiasi i latou,", "They were confounded because they had hoped;"], ["auā na latou faatuatua i ai; na oo atu i ai,", "they came thither,"], ["ona latou fememeai ai lea.", "and were ashamed."]]},
  {num:21,words:[["Auā ua avea nei outou e pei o ia mea;", "For now ye are nothing;"], ["ua vaavaai mai outou i lo'u malaia,", "ye see my casting down,"], ["ma outou fefefe ai.", "and are afraid."]]},
  {num:22,words:[["Pe na ou fai atu ea,", "Did I say, Bring unto me? or,"], ["Ia outou aumaia se mea ia te au? Pe aumai ia se mea alofa ia te au ai a outou oloa? Pe,", "Give a reward for me of your substance?"]]},
  {num:23,words:[["Laveai mai ia ia te au ai le lima o le ua ita mai? Pe,", "Or, Deliver me from the enemy's hand? or,"], ["Faaola mai ia outou ia te au ai lima o e ua faasaua?", "Redeem me from the hand of the mighty?"]]},
  {num:24,words:[["Ina a'oa'o mai ia outou ia te au,", "Teach me,"], ["ona ou faalologo ai lea;", "and I will hold my tongue:"], ["ia outou faasino mai foi ia te au se mea ua ou sese ai.", "and cause me to understand wherein I have erred."]]},
  {num:25,words:[["E matuā maamaai upu tonu. A e peitai se a se mea ua faatonuina i la outou aoaiga?", "How forcible are right words! but what doth your arguing reprove?"]]},
  {num:26,words:[["Po ua outou manatu ea e aoaiina o upu? O upu a le ua totoai e tusa ia ma le matagi.", "Do ye imagine to reprove words, and the speeches of one that is desperate, which are as wind?"]]},
  {num:27,words:[["Ua outou feosofi mai i le ua mātuaoti,", "Yea, ye overwhelm the fatherless,"], ["ua outou elia foi le lua mo la outou uo.", "and ye dig a pit for your friend."]]},
  {num:28,words:[["A o lenei,", "Now therefore be content,"], ["ia outou finagalo e silasila mai ia te au;", "look upon me;"], ["ona outou silafia lea pe afai ou te tala pepelo.", "for it is evident unto you if I lie."]]},
  {num:29,words:[["Ina foi mai ia o outou,", "Return, I pray you,"], ["aua ne'i i ai se amio leaga;", "let it not be iniquity;"], ["ina toe foi mai ia o outou,", "yea,"], ["ua i ai i lenei mea la'u amiotonu.", "return again, my righteousness is in it."]]},
  {num:30,words:[["Po ua i ai ea se agasala i lo'u laulaufaiva? Pe le iloga ea i lo'u gutu le mea leaga?", "Is there iniquity in my tongue? cannot my taste discern perverse things?"]]},
];
