var job_ch_8_Verses = [
  {num:1,words:[["Ona tali mai ai lea o Pilitati le Sua,", "Then answered Bildad the Shuhite,"], ["ua faapea mai,", "and said,"]]},
  {num:2,words:[["E te tautala i na upu seia afea? E fai foi ma matagi tetele o upu a lou fofoga seia afea?", "How long wilt thou speak these things? and how long shall the words of thy mouth be like a strong wind?"]]},
  {num:3,words:[["Pe faapiopioina ea e le Atua le faamasinoga? Pe faapiopioina ea mea tonu e Le e ona le malosi uma lava?", "Doth God pervert judgment? or doth the Almighty pervert justice?"]]},
  {num:4,words:[["Afai na agasala atu lau fanau ia te ia,", "If thy children have sinned against him,"], ["ma ua lafoaiina i latou e ia i a latou solitulafono?", "and he have cast them away for their transgression;"]]},
  {num:5,words:[["Afai e te matuā saili atu i le Atua,", "If thou wouldest seek unto God betimes,"], ["ma aioi atu i Le e ona le malosi uma lava;", "and make thy supplication to the Almighty;"]]},
  {num:6,words:[["afai ua e lelei ma e amio sa'o,", "If thou wert pure and upright;"], ["e maleifua mai lava nei o ia ona o oe,", "surely now he would awake for thee,"], ["e faasaogalemu foi e ia le fale e fai ai lau amiotonu.", "and make the habitation of thy righteousness prosperous."]]},
  {num:7,words:[["E ui lava ina itiiti lou amataga,", "Though thy beginning was small,"], ["a e matuā faateleina lou aiga.", "yet thy latter end should greatly increase."]]},
  {num:8,words:[["Auā ina e fesili atu ia i le tupulaga na muamua,", "For enquire, I pray thee,"], ["ma ia e matuā suesue i o latou mātua.", "of the former age, and prepare thyself to the search of their fathers:"]]},
  {num:9,words:[["Auā o i tatou o tagata ananafi,", "(For we are but of yesterday,"], ["ua tatou le iloa;", "and know nothing, because our days upon earth are a shadow:"], ["auā o tatou aso i le lalolagi o le ata ia.", ")"]]},
  {num:10,words:[["Latou te le a'oa'o mai ea ia te oe,", "Shall not they teach thee,"], ["ma ta'u mai ia te oe,", "and tell thee,"], ["ma fai mai upu ai o latou loto?", "and utter words out of their heart?"]]},
  {num:11,words:[["Pe tupu mai ea le kome a le o iai se palapala? Pe tupu mai ea le utuutu a le o iai se vai?", "Can the rush grow up without mire? can the flag grow without water?"]]},
  {num:12,words:[["A o lauolaola,", "Whilst it is yet in his greenness,"], ["ma le le salaina,", "and not cut down,"], ["e muamua ona mamae i vao iti uma.", "it withereth before any other herb."]]},
  {num:13,words:[["E faapea lava ala o i latou uma o e faagalogalo i le Atua;", "So are the paths of all that forget God;"], ["e faaumatia foi le faamoemoe o le tagata faalemata'u.", "and the hypocrite's hope shall perish:"]]},
  {num:14,words:[["E vavaeeseina lona faamoemoe,", "Whose hope shall be cut off,"], ["o lona faatuatuaga foi o le fale o le apogaleveleve lea.", "and whose trust shall be a spider's web."]]},
  {num:15,words:[["E faalagolago o ia i lona fale,", "He shall lean upon his house,"], ["a e le mau;", "but it shall not stand:"], ["e taofimauina ai e ia,", "he shall hold it fast,"], ["a e le tumau.", "but it shall not endure."]]},
  {num:16,words:[["Ua tupu olaola o ia, a o le laina,", "He is green before the sun,"], ["ua tupu foi ona tatupu i lana faatoaga.", "and his branch shooteth forth in his garden."]]},
  {num:17,words:[["Ua feuiuiai ona aa i le faaputugāmaa,", "His roots are wrapped about the heap,"], ["ua iloa foi le mea o i ai maa.", "and seeth the place of stones."]]},
  {num:18,words:[["E faaumatia lava o ia ai le mea o i ai o ia,", "If he destroy him from his place,"], ["ona faafiti ai lea ia te ia,", "then it shall deny him,"], ["e faapea atu ,", "saying,"], ["Ou te le iloa oe.", "I have not seen thee."]]},
  {num:19,words:[["Faauta,", "Behold,"], ["o le olioli lea i lona ala,", "this is the joy of his way,"], ["e tutupu foi nisi mai le eleele.", "and out of the earth shall others grow."]]},
  {num:20,words:[["Faauta,", "Behold,"], ["e le lafoaiina e le Atua le ua sao lana amio,", "God will not cast away a perfect man,"], ["na te le taofia ae foi lima o e amio leaga.", "neither will he help the evil doers:"]]},
  {num:21,words:[["Seia faatumuina e ia lou fofoga i le 'ata'ata,", "Till he fill thy mouth with laughing,"], ["ma ou laufofoga i le alaga fiafia.", "and thy lips with rejoicing."]]},
  {num:22,words:[["E faaofuina i le mā o e ua 'ino'ino mai ia te oe, o le fale ie o e amio leaga,", "They that hate thee shall be clothed with shame;"], ["e leai lea.", "and the dwelling place of the wicked shall come to nought."]]},
];
renderVerseSet(job_ch_8_Verses, 'job-ch8-verses');

var job_ch_9_Verses = [
  {num:1,words:[["Ona tali atu lea o Iopu, ua faapea atu,", "Then Job answered and said,"]]},
  {num:2,words:[["Ua ou iloa e moni lava, o loo faapea;", "I know it is so of a truth:"], ["a e faapefea ona amiotonu o le tagata i luma o le Atua?", "but how should man be just with God?"]]},
  {num:3,words:[["Afai e finagalo o ia ona finau ma ia,", "If he will contend with him,"], ["e le mafai ona tali atu o ia ia te ia se upu e tasi i le afe o upu .", "he cannot answer him one of a thousand."]]},
  {num:4,words:[["E poto lona finagalo,", "He is wise in heart, and mighty in strength:"], ["e malosi foi lona mana. Po o ai ea se ua faamaaa lona loto e tetee atu ia te ia a e sao ai.", "who hath hardened himself against him, and hath prospered?"]]},
  {num:5,words:[["O le na te siitia mauga,", "Which removeth the mountains,"], ["a e lei iloa e i latou,", "and they know not:"], ["o le na te fulisia i latou i lona toasa.", "which overturneth them in his anger."]]},
  {num:6,words:[["O le ua lulueseina le lalolagi i le mea sa i ai,", "Which shaketh the earth out of her place,"], ["ona gagau ai lea o ona pou tu.", "and the pillars thereof tremble."]]},
  {num:7,words:[["O lē fetalai atu i le la,", "Which commandeth the sun,"], ["ona le alu ae ai lea,", "and it riseth not;"], ["ma na faamaufaailogaina fetu.", "and sealeth up the stars."]]},
  {num:8,words:[["O lē fofola le lagi, na o ia lava,", "Which alone spreadeth out the heavens,"], ["ma savali atu i luga o peau o le sami.", "and treadeth upon the waves of the sea."]]},
  {num:9,words:[["O lē na faia Asa,", "Which maketh Arcturus,"], ["ma Kisila,", "Orion,"], ["ma Kima,", "and Pleiades,"], ["atoa ma ana o i le itu i toga.", "and the chambers of the south."]]},
  {num:10,words:[["O le ua faia mea tetele e le masuesueina,", "Which doeth great things past finding out; yea,"], ["ma vavega e le mafai ona faitaulia.", "and wonders without number."]]},
  {num:11,words:[["Faauta,", "Lo,"], ["ua afio ane o ia i o'u luma,", "he goeth by me,"], ["a ou te le iloa o ia;", "and I see him not:"], ["ua afio atu foi o ia,", "he passeth on also,"], ["a ou te le iloa o ia.", "but I perceive him not."]]},
  {num:12,words:[["Faauta,", "Behold,"], ["e faoa e ia,", "he taketh away,"], ["po o ai ea sē faafoi atu ia te ia? Po o ai ea e fai atu ia te ia,", "who can hinder him? who will say unto him,"], ["O le a ea le mea ua e faia?", "What doest thou?"]]},
  {num:13,words:[["E le faafoisia e le Atua lona toasa;", "If God will not withdraw his anger,"], ["e ifo i lalo ia te ia o fesoasoani faamaualuga.", "the proud helpers do stoop under him."]]},
  {num:14,words:[["A e faapefea a'u nei ona ou tali atu ia te ia,", "How much less shall I answer him,"], ["ma a'u filifilia ni upu e fai atu ia te ia?", "and choose out my words to reason with him?"]]},
  {num:15,words:[["Ana ou amiotonu po ua ou le tali atu ia te ia,", "Whom, though I were righteous,"], ["a e faatoga atu i lo'u faamasino.", "yet would I not answer, but I would make supplication to my judge."]]},
  {num:16,words:[["Ana ou valaau atu,", "If I had called,"], ["ma ua tali mai o ia ia te au,", "and he had answered me;"], ["ua ou le manatu ua faafofogaina mai e ia lo'u leo.", "yet would I not believe that he had hearkened unto my voice."]]},
  {num:17,words:[["Auā na te tu'imomomoina a'u i le afā,", "For he breaketh me with a tempest,"], ["ma faateleina fua o'u manua.", "and multiplieth my wounds without cause."]]},
  {num:18,words:[["Na te le tuuina mai a'u, seia ou mānava ifo,", "He will not suffer me to take my breath,"], ["a ua na faama'onaina mai a'u i mea oona.", "but filleth me with bitterness."]]},
  {num:19,words:[["Afai ou te tautala i le malosi,", "If I speak of strength,"], ["faauta mai,", "lo,"], ["ua malosi lava o ia;", "he is strong:"], ["afai foi ou te tautala i le faamasinoga,", "and if of judgment,"], ["o ia ea se na te atofaina se aso mo a'u?", "who shall set me a time to plead?"]]},
  {num:20,words:[["Afai ou te ta'uamiotonuina a'u e a'u,", "If I justify myself,"], ["e faasalaina a'u i lo'u lava gutu;", "mine own mouth shall condemn me:"], ["afai ou te fai atu ,", "if I say,"], ["ua sao la'u nei amio,", "I am perfect,"], ["e ta'ua ai a'u o le faapiopio.", "it shall also prove me perverse."]]},
  {num:21,words:[["Afai ou te fai atu ,", "Though I were perfect,"], ["o a'u nei ua sao, ou te le iloa ai lo'u agaga,", "yet would I not know my soul:"], ["ou te 'ino'ino i lo'u ola.", "I would despise my life."]]},
  {num:22,words:[["E tasi lea mea,", "This is one thing,"], ["o le mea lea na ou fai atu ai,", "therefore I said it,"], ["O loo faaumatia e ia o le ua sao lana amio atoa ma le ua amio leaga.", "He destroyeth the perfect and the wicked."]]},
  {num:23,words:[["Afai e fasioti faafuasei le sasa,", "If the scourge slay suddenly,"], ["e 'ata ai o ia i le tofotofoga o e ua le sala.", "he will laugh at the trial of the innocent."]]},
  {num:24,words:[["Ua tuuina mai le lalolagi i le lima o lē amio leaga;", "The earth is given into the hand of the wicked:"], ["e ufitia e ia o mata o faamasino o i ai;", "he covereth the faces of the judges thereof;"], ["afai ua le faapea,", "if not, where,"], ["po o fea o i ai o ia? po o ai ea o ia?", "and who is he?"]]},
  {num:25,words:[["Ua tele vavave o'u aso e sili i le ua momo'e;", "Now my days are swifter than a post: they flee away,"], ["ua mavae atu ia ma le le iloa se mea lelei.", "they see no good."]]},
  {num:26,words:[["Ua mavae atu e pei o vaa tele vavave;", "They are passed away as the swift ships:"], ["e pei o le aeto foi ua lele tele vave i lana mea e 'ai.", "as the eagle that hasteth to the prey."]]},
  {num:27,words:[["Afai ou te fai atu,", "If I say,"], ["ou te faagalogaloina lo'u tagi,", "I will forget my complaint,"], ["ou te le toe mata faanoanoa ,", "I will leave off my heaviness,"], ["a e ou te mata fiafia.", "and comfort myself:"]]},
  {num:28,words:[["Ua ou fefe i o'u tiga uma, ua ou iloa,", "I am afraid of all my sorrows,"], ["e te le ta'usaoina a'u.", "I know that thou wilt not hold me innocent."]]},
  {num:29,words:[["Ua ou amio leaga,", "If I be wicked,"], ["se a ea le mea ou te tautiga fua ai a'u?", "why then labour I in vain?"]]},
  {num:30,words:[["Afai ou te taele i le suāvai kiona,", "If I wash myself with snow water,"], ["ma ou faamamāina o'u lima i le moli;", "and make my hands never so clean;"]]},
  {num:31,words:[["a e te fufui ia te au i le lua;", "Yet shalt thou plunge me in the ditch,"], ["e faainosia foi a'u i o'u lava ofu.", "and mine own clothes shall abhor me."]]},
  {num:32,words:[["Auā e le se tagata o ia ,", "For he is not a man,"], ["e pei o a'u,", "as I am,"], ["ou te tali atu ai ia te ia,", "that I should answer him,"], ["ma te o faatasi ai i le faamasinoga.", "and we should come together in judgment."]]},
  {num:33,words:[["E le o i ai foi se faamasino i lo ma va,", "Neither is there any daysman betwixt us,"], ["e tago mai lona lima ia te i maua.", "that might lay his hand upon us both."]]},
  {num:34,words:[["Ia aveeseina e ia o lana sasa ia te au,", "Let him take his rod away from me,"], ["aua ne'i faamatautia foi a'u i lona matautia.", "and let not his fear terrify me:"]]},
  {num:35,words:[["Ona ou tautala atu ai lea ma le le fefe ia te ia;", "Then would I speak,"], ["a o a'u,", "and not fear him;"], ["o loo le faapea ia te au.", "but it is not so with me."]]},
];
renderVerseSet(job_ch_9_Verses, 'job-ch9-verses');

var job_ch_10_Verses = [
  {num:1,words:[["Ua musu lo'u loto i lo'u ola;", "My soul is weary of my life;"], ["ou te tuuina atu a'u ia tagi pea;", "I will leave my complaint upon myself;"], ["ou te tautala i le tiga o lo'u loto.", "I will speak in the bitterness of my soul."]]},
  {num:2,words:[["Ou te fai atu i le Atua,", "I will say unto God,"], ["Aua e te faasala mai ia te au,", "Do not condemn me;"], ["ia e faailoa mai ia te au le mea e te finau mai ai ia te au.", "shew me wherefore thou contendest with me."]]},
  {num:3,words:[["Pe lelei ea ia te oe ina e faasaua,", "Is it good unto thee that thou shouldest oppress,"], ["ma e 'ino'ino i le galuega a ou aao,", "that thou shouldest despise the work of thine hands,"], ["ma e faamanuia le pule a e amio leaga?", "and shine upon the counsel of the wicked?"]]},
  {num:4,words:[["Ua e fofoga ea i mata o tagata? po ua e silasila ea e pei o le vaai o tagata?", "Hast thou eyes of flesh? or seest thou as man seeth?"]]},
  {num:5,words:[["O ou aso ea e pei o aso o tagata? po ou tausaga ea e pei o aso o tagata?", "Are thy days as the days of man? are thy years as man's days,"]]},
  {num:6,words:[["Ina ua e saili mai i la'u amio leaga,", "That thou enquirest after mine iniquity,"], ["ma suesue i la'u agasala.", "and searchest after my sin?"]]},
  {num:7,words:[["Ua e silafia lava, ua ou le amio leaga;", "Thou knowest that I am not wicked;"], ["e leai foi se laveai mai i lou aao.", "and there is none that can deliver out of thine hand."]]},
  {num:8,words:[["Na saunia ma faia a'u atoa uma e ou aao;", "Thine hands have made me and fashioned me together round about;"], ["a ua e fasioti ia te au.", "yet thou dost destroy me."]]},
  {num:9,words:[["Se'i e manatu,", "Remember,"], ["na e faia a'u e pei o le omea;", "I beseech thee, that thou hast made me as the clay;"], ["e te toe faafoisia ea a'u i le efuefu?", "and wilt thou bring me into dust again?"]]},
  {num:10,words:[["Na e le sasaaina ea a'u e pei o le suāsusu,", "Hast thou not poured me out as milk,"], ["ma faato'aina a'u e pei o le suāsusu to'a?", "and curdled me like cheese?"]]},
  {num:11,words:[["Na e faaofuina a'u i le pa'u ma le aano,", "Thou hast clothed me with skin and flesh,"], ["na e faamalosia foi a'u i ivi ma ua.", "and hast fenced me with bones and sinews."]]},
  {num:12,words:[["Na e foaiina mai ia te au le ola ma le alofa,", "Thou hast granted me life and favour,"], ["o lou leoleo mai foi na tausia ai lo'u agaga.", "and thy visitation hath preserved my spirit."]]},
  {num:13,words:[["Ua e natia foi nei mea i lou finagalo;", "And these things hast thou hid in thine heart:"], ["ua ou iloa o loo ia te oe lenei mea.", "I know that this is with thee."]]},
  {num:14,words:[["Afai ou te agasala,", "If I sin,"], ["ua e silasila mai ai pea ia te au,", "then thou markest me,"], ["e te le faamagalo mai foi ia te au i la'u amio leaga.", "and thou wilt not acquit me from mine iniquity."]]},
  {num:15,words:[["Afai ua ou amio leaga,", "If I be wicked,"], ["oi talofa ia te au! afai foi ua ou amiotonu,", "woe unto me;"], ["e le ea i luga lo'u ulu; ua tumu a'u i le mā,", "and if I be righteous,"], ["ua ou iloa foi lo'u puapuaga;", "yet will I not lift up my head. I am full of confusion;"], ["mona ua tupu pea.", "therefore see thou mine affliction;"]]},
  {num:16,words:[["Ua e tuli mai ia te au, e pei o le leona;", "For it increaseth. Thou huntest me as a fierce lion:"], ["ua e toe faia ia te au mea e ofo ai.", "and again thou shewest thyself marvellous upon me."]]},
  {num:17,words:[["Ua e faafouina mai o au molimau ia te au,", "Thou renewest thy witnesses against me,"], ["ma ua e faateleina mai lou toasa ia te au;", "and increasest thine indignation upon me;"], ["e auauai 'au ia te au.", "changes and war are against me."]]},
  {num:18,words:[["Se a le mea na e aumai ai a'u i le manava? E! ana ou oti ma ia le iloa a'u e se tasi,", "Wherefore then hast thou brought me forth out of the womb? Oh that I had given up the ghost, and no eye had seen me!"]]},
  {num:19,words:[["po o pe na ua avea a'u e peiseai na ou le ola mai;", "I should have been as though I had not been;"], ["po ua aveina atu a'u ai le manava i le tuugamau.", "I should have been carried from the womb to the grave."]]},
  {num:20,words:[["E le itiiti ea o'u aso? Ina soia,", "Are not my days few? cease then,"], ["tuu mai pea ia o a'u,", "and let me alone,"], ["seia ou muai malolo ane teisi,", "that I may take comfort a little,"]]},
  {num:21,words:[["i lo'u alu atu ai i le mea ou te le toe foi mai ai,", "Before I go whence I shall not return,"], ["o le nuu o le pouliuli ma le ata o le oti;", "even to the land of darkness and the shadow of death;"]]},
  {num:22,words:[["o le nuu o le pouliuli,", "A land of darkness,"], ["e tusa lava ma le pouliuli tele;", "as darkness itself;"], ["o le ata o le oti,", "and of the shadow of death,"], ["e le i ai ni mea tonu;", "without any order,"], ["o lona pupula mai e tusa ma le pouliuli tele.", "and where the light is as darkness."]]},
];
renderVerseSet(job_ch_10_Verses, 'job-ch10-verses');

var job_ch_11_Verses = [
  {num:1,words:[["Ona tali mai ai lea o Sofara le Naama,", "Then answered Zophar the Naamathite,"], ["ua faapea mai,", "and said,"]]},
  {num:2,words:[["A le talia ea upu ua tele? Pe ta'uamiotonuina ea le tagata tautala soo?", "Should not the multitude of words be answered? and should a man full of talk be justified?"]]},
  {num:3,words:[["O lou tautala faaletatau e faalologo ai ea tagata? E te tauemu mai ea,", "Should thy lies make men hold their peace? and when thou mockest,"], ["ae leai se tasi e faamaina atu oe?", "shall no man make thee ashamed?"]]},
  {num:4,words:[["Sa e faapea mai,", "For thou hast said,"], ["Ua tonu la'u mataupu,", "My doctrine is pure,"], ["ou te mamā foi a'u i ou luma.", "and I am clean in thine eyes."]]},
  {num:5,words:[["A e peitai, e lelei pe a tŭlei mai le siufofoga o le Atua,", "But oh that God would speak,"], ["ma fetalai mai o ia ia te oe;", "and open his lips against thee;"]]},
  {num:6,words:[["ma faaali mai e ia ia te oe mea lilo o le poto, auā ua sili lava i mea ua faailoa mai;", "And that he would shew thee the secrets of wisdom,"], ["ona iloa ai lea e oe ua fagalogaloina e le Atua mo oe o isi au agasala.", "that they are double to that which is! Know therefore that God exacteth of thee less than thine iniquity deserveth."]]},
  {num:7,words:[["O le suesue e te maua ai ea le Atua? E te maua atoatoa ai ea Le e ona le malosi uma lava?", "Canst thou by searching find out God? canst thou find out the Almighty unto perfection?"]]},
  {num:8,words:[["Ua maualuga i le lagi;", "It is as high as heaven;"], ["se a se mea e te faia? Ua sili ona loloto i seoli;", "what canst thou do? deeper than hell;"], ["se a se mea e te iloa ai?", "what canst thou know?"]]},
  {num:9,words:[["O lona umi ua sili lea i le lalolagi,", "The measure thereof is longer than the earth,"], ["ua sili foi lona lautele i le sami.", "and broader than the sea."]]},
  {num:10,words:[["Afai e oso mai o ia,", "If he cut off,"], ["ma puipui mai,", "and shut up,"], ["ma faapotopoto mai,", "or gather together,"], ["po o ai ea na te faafoi ia te ia?", "then who can hinder him?"]]},
  {num:11,words:[["Auā ua silafia e ia tagata amio leaga;", "For he knoweth vain men:"], ["ua silasila mai foi o ia i le agasala,", "he seeth wickedness also;"], ["pe na te le mafaufau foi ea i ai?", "will he not then consider it?"]]},
  {num:12,words:[["A e leai se atamai i le tagata valea,", "For vain man would be wise,"], ["a ua fanau le tagata ua tusa ma le tamai asini o le vao.", "though man be born like a wild ass's colt."]]},
  {num:13,words:[["Afai e te saunia lou loto,", "If thou prepare thine heart,"], ["ma faaloaloa atu ou lima ia te ia;", "and stretch out thine hands toward him;"]]},
  {num:14,words:[["afai ua i lou lima se amioletonu,", "If iniquity be in thine hand,"], ["ia e avemamaoina;", "put it far away,"], ["aua ne'i tumau pea le agasala i ou fale ie.", "and let not wickedness dwell in thy tabernacles."]]},
  {num:15,words:[["Ona ea ai lea i luga o ou mata e leai se mea e pona ai;", "For then shalt thou lift up thy face without spot;"], ["e te faamalosi foi,", "yea, thou shalt be stedfast,"], ["ma e le fefe lava.", "and shalt not fear:"]]},
  {num:16,words:[["Auā e galo ia te oe le puapuaga,", "Because thou shalt forget thy misery,"], ["e te manatua foi e pei o le vai ua tafe atu.", "and remember it as waters that pass away:"]]},
  {num:17,words:[["E oo mai foi ou aso e sili ona malamalama i le aoauli;", "And thine age shall be clearer than the noonday;"], ["ua e i ai nei i le pouliuli,", "thou shalt shine forth,"], ["a e avea oe e pei o lea taeao.", "thou shalt be as the morning."]]},
  {num:18,words:[["E fai sou faatuatua,", "And thou shalt be secure,"], ["auā o loo i ai le faamoemoe;", "because there is hope;"], ["o loo e mā nei oe,", "yea, thou shalt dig about thee,"], ["a e te toato ma le filemu.", "and thou shalt take thy rest in safety."]]},
  {num:19,words:[["E te taoto foi,", "Also thou shalt lie down,"], ["a e leai se na te faamatau mai;", "and none shall make thee afraid; yea,"], ["e toatele foi e ole atu ia te oe.", "many shall make suit unto thee."]]},
  {num:20,words:[["A e fole mata o e amio leaga,", "But the eyes of the wicked shall fail,"], ["e faaumatia foi se mea latou te sosola i ai;", "and they shall not escape,"], ["o lo latou faamoemoe foi ua se mānava ua mavae atu.", "and their hope shall be as the giving up of the ghost."]]},
];
renderVerseSet(job_ch_11_Verses, 'job-ch11-verses');

var job_ch_12_Verses = [
  {num:1,words:[["Ona tali atu lea o Iopu, ua faapea atu,", "And Job answered and said,"]]},
  {num:2,words:[["E moni, o le nuu lava outou,", "No doubt but ye are the people,"], ["e mavae faatasi ma outou le poto.", "and wisdom shall die with you."]]},
  {num:3,words:[["O ia te au foi le mafaufau e tusa ma outou,", "But I have understanding as well as you;"], ["ou te le faatauvaa a'u ia te outou;", "I am not inferior to you: yea,"], ["o ai ea foi se ua le i ai mea faapena?", "who knoweth not such things as these?"]]},
  {num:4,words:[["O le ua tauemua e lana uo,", "I am as one mocked of his neighbour,"], ["o a'u lea o le ua valaau atu i le Atua,", "who calleth upon God,"], ["ona tali mai ai lea o ia ia te ia, ua tauemua le tagata amiotonu,", "and he answereth him:"], ["o le ua sao lana amio.", "the just upright man is laughed to scorn."]]},
  {num:5,words:[["O le sulu ua inosia i le manatu o lē nofo ma le filemu, o le tagata lea o le a mapeva lona vae.", "He that is ready to slip with his feet is as a lamp despised in the thought of him that is at ease."]]},
  {num:6,words:[["E saogalemu fale ie o e ua fao mea,", "The tabernacles of robbers prosper,"], ["ua saogalemu foi i latou o e faaonoono i le Atua;", "and they that provoke God are secure;"], ["o e ua tuuina mai i ai mea e le Atua i o latou lima.", "into whose hand God bringeth abundantly."]]},
  {num:7,words:[["A e peitai ina e fesili ia i manu vaefa,", "But ask now the beasts,"], ["latou te a'oa'o mai ia te oe;", "and they shall teach thee;"], ["ma manu felelei,", "and the fowls of the air,"], ["latou le faailoa mai ia te oe.", "and they shall tell thee:"]]},
  {num:8,words:[["Pe ia e tautala i le laueleele,", "Or speak to the earth,"], ["e a'oa'o mai ai o ia ia te oe;", "and it shall teach thee:"], ["e faamatala mai foi ia te oe e i'a o le sami.", "and the fishes of the sea shall declare unto thee."]]},
  {num:9,words:[["Po o ai ea e le iloa i nei mea uma ua faia ia mea e le aao o Ieova?", "Who knoweth not in all these that the hand of the LORD hath wrought this?"]]},
  {num:10,words:[["Ua iai i lona aao o le ola o meaola uma,", "In whose hand is the soul of every living thing,"], ["ma le mānava a tagata ola uma lava.", "and the breath of all mankind."]]},
  {num:11,words:[["E le faamasino ea e le taliga i upu? E le tofotofo ea foi e le gutu i ana mea e 'ai?", "Doth not the ear try words? and the mouth taste his meat?"]]},
  {num:12,words:[["O loo iai le poto i e ua toeaina;", "With the ancient is wisdom;"], ["o le faalevaleva foi o aso e i ai le faautauta.", "and in length of days understanding."]]},
  {num:13,words:[["O loo ia te ia le poto ma le malosi,", "With him is wisdom and strength,"], ["o loo ia te ia le mafaufau ma le faautauta.", "he hath counsel and understanding."]]},
  {num:14,words:[["Faauta,", "Behold,"], ["e lepetia e ia,", "he breaketh down,"], ["a e le mafai ona toe atiina ae;", "and it cannot be built again:"], ["e puipuia e ia le tagata,", "he shutteth up a man,"], ["a e le toe tatalaina.", "and there can be no opening."]]},
  {num:15,words:[["Faauta,", "Behold,"], ["e taofia e ia le vai,", "he withholdeth the waters,"], ["ona pe ai lea;", "and they dry up:"], ["na te tuuina mai ai foi,", "also he sendeth them out,"], ["ona olopalaina ai lea o le nuu.", "and they overturn the earth."]]},
  {num:16,words:[["O loo ia te ia le malosi ma le poto;", "With him is strength and wisdom:"], ["o loo ia te ia o le ua faaseseina atoa ma le na te faasese ia te ia.", "the deceived and the deceiver are his."]]},
  {num:17,words:[["Na te ta'ita'iina faipule faatagataotaua,", "He leadeth counsellors away spoiled,"], ["na te faavāleaina foi faamasino.", "and maketh the judges fools."]]},
  {num:18,words:[["Na te tatalaina le noanoaga a tupu,", "He looseth the bond of kings,"], ["na te fusia foi o latou sulugatiti i le fusi.", "and girdeth their loins with a girdle."]]},
  {num:19,words:[["Na te ta'ita'iina ositaulaga faatagataotaua,", "He leadeth princes away spoiled,"], ["na te lafotu foi i e malolosi.", "and overthroweth the mighty."]]},
  {num:20,words:[["Na te avea le tautalaga ai e ua faamaoni,", "He removeth away the speech of the trusty,"], ["na te avea foi le mafaufau o toeaina.", "and taketh away the understanding of the aged."]]},
  {num:21,words:[["Na te faainosia alii,", "He poureth contempt upon princes,"], ["na te tatalaina foi le fusi o e malolosi.", "and weakeneth the strength of the mighty."]]},
  {num:22,words:[["Na te faaalia mea loloto ai le pouliuli,", "He discovereth deep things out of darkness,"], ["na te aumaia foi le ata o le oti i le malamalama.", "and bringeth out to light the shadow of death."]]},
  {num:23,words:[["Na te faatoateleina nuu,", "He increaseth the nations,"], ["na te faaumatia foi;", "and destroyeth them:"], ["na te faalauteleina nuu,", "he enlargeth the nations,"], ["na te faalauitiitia foi.", "and straiteneth them again."]]},
  {num:24,words:[["Na te aveesea loto o alii sili o nuu le lalolagi, ma faaseseina i latou i le mea gaogao,", "He taketh away the heart of the chief of the people of the earth,"], ["e le o i ai se ala.", "and causeth them to wander in a wilderness where there is no way."]]},
  {num:25,words:[["E tautago i latou i le pouliuli, e leai se malamalama;", "They grope in the dark without light,"], ["na te faaseseina foi i latou pei o le ua onā.", "and he maketh them to stagger like a drunken man."]]},
];
renderVerseSet(job_ch_12_Verses, 'job-ch12-verses');

var job_ch_13_Verses = [
  {num:1,words:[["-2 Faauta, ua iloa e o'u mata nei mea uma,", "Lo,"], ["ua faalogo ai o'u taliga ma lagona ai. O mea ua iloa e outou,", "mine eye hath seen all this,"], ["ou te iloa foi a'u; ou te le faatauvaa a'u ia te outou.", "mine ear hath heard and understood it."]]},
  {num:2,words:[["O mea ua iloa e outou,", "What ye know,"], ["ou te iloa foi e a'u;", "the same do I know also:"], ["Ou te le faatauvaa a'u ia te outou.", "I am not inferior unto you."]]},
  {num:3,words:[["A e peitai a'u, ou te fia tautala i Le e ona le malosi uma lava,", "Surely I would speak to the Almighty,"], ["ou te loto lava ina ia ma filifili ma le Atua.", "and I desire to reason with God."]]},
  {num:4,words:[["Auā ua outou fatu fua lava tala pepelo,", "But ye are forgers of lies,"], ["o fomai le aoga lava outou uma.", "ye are all physicians of no value."]]},
  {num:5,words:[["E! A na matuā faalologo outou, po ua avea lea ma poto ia te outou.", "O that ye would altogether hold your peace! and it should be your wisdom."]]},
  {num:6,words:[["Ia outou faalogologo mai lava i la'u faatonu atu,", "Hear now my reasoning,"], ["ina liliu mai o outou taliga i a'u finauga.", "and hearken to the pleadings of my lips."]]},
  {num:7,words:[["Tou te tautala ea ma le le tonu mo le Atua? Tou te tautala faa'ole'ole ea mo ia?", "Will ye speak wickedly for God? and talk deceitfully for him?"]]},
  {num:8,words:[["Tou te faailogaina ea o ia? Tou te finau ea mo le Atua?", "Will ye accept his person? will ye contend for God?"]]},
  {num:9,words:[["Pe lelei ea ina ia suesue mai o ia ia te outou? Pe tou te pelogia ea o ia,", "Is it good that he should search you out? or as one man mocketh another,"], ["e pei ona pelogia o le tagata e le tasi?", "do ye so mock him?"]]},
  {num:10,words:[["E matuā aoai o ia ia te outou,", "He will surely reprove you,"], ["pe a outou faailogaina faalilolilo nisi.", "if ye do secretly accept persons."]]},
  {num:11,words:[["Pe le faamatautia ea outou i lona silisili? Pe le oo atu ea lona matautia ia te outou?", "Shall not his excellency make you afraid? and his dread fall upon you?"]]},
  {num:12,words:[["O a outou upu faamanatu o faatusa lefulefu ia,", "Your remembrances are like unto ashes,"], ["o outou 'olo o 'olo omea ia.", "your bodies to bodies of clay."]]},
  {num:13,words:[["Soia tou te tautala ia te au,", "Hold your peace,"], ["so'u tautala atu a'u,", "let me alone, that I may speak,"], ["ona faitalia lea se mea e oo mai ia te au.", "and let come on me what will."]]},
  {num:14,words:[["Faitalia se mea e oo mai ou te u lo'u tino i o'u nifo,", "Wherefore do I take my flesh in my teeth,"], ["ma ou tuu lo'u ola i lo'u lima.", "and put my life in mine hand?"]]},
  {num:15,words:[["E ui lava ina fasioti o ia ia te au,", "Though he slay me,"], ["ou te faamoemoe pea ia te ia;", "yet will I trust in him:"], ["a e peitai ou te faatonu atu o'u ala i ona luma.", "but I will maintain mine own ways before him."]]},
  {num:16,words:[["E fai lava o ia mo'u faaolataga;", "He also shall be my salvation:"], ["auā e le alu atu se tagata faalematau i ona luma.", "for an hypocrite shall not come before him."]]},
  {num:17,words:[["Ina matuā faalogologo mai ia i la'u upu ma la'u faamatalaga i o outou taliga.", "Hear diligently my speech, and my declaration with your ears."]]},
  {num:18,words:[["Faauta mai ea,", "Behold now,"], ["ua ou sauni i le faamasinoga; ua ou iloa,", "I have ordered my cause;"], ["e ta'uamiotonuina lava a'u.", "I know that I shall be justified."]]},
  {num:19,words:[["Po o ai ea o ia ma te fefinauai? Auā o le a ou faalologo nei,", "Who is he that will plead with me? for now, if I hold my tongue,"], ["ma ou oti.", "I shall give up the ghost."]]},
  {num:20,words:[["Tau o mea e lua aua e te faia ia te au,", "Only do not two things unto me:"], ["ona ou le lafi ai lea i ou luma.", "then will I not hide myself from thee."]]},
  {num:21,words:[["Ia mamao lou aao ia te au,", "Withdraw thine hand far from me:"], ["aua foi ne'i faafefe ia te au i lou matautia.", "and let not thy dread make me afraid."]]},
  {num:22,words:[["I le ia e valaau mai,", "Then call thou,"], ["ona ou tali atu ai lea;", "and I will answer:"], ["po ou te tauala atu,", "or let me speak,"], ["ona e tali mai ai lea ia te au.", "and answer thou me."]]},
  {num:23,words:[["E fia ea a'u amio leaga ma a'u agasala? Ina faailoa mai ia ia te au lo'u solitulafono ma la'u agasala.", "How many are mine iniquities and sins? make me to know my transgression and my sin."]]},
  {num:24,words:[["Se a ea le mea ua 'alo ai ou fofoga ma e faia a'u mou fili?", "Wherefore hidest thou thy face, and holdest me for thine enemy?"]]},
  {num:25,words:[["E te faamatau ea le laumea ua lelea? Ma e tuliloaina ea tagutugutu o saito ua mamago?", "Wilt thou break a leaf driven to and fro? and wilt thou pursue the dry stubble?"]]},
  {num:26,words:[["Auā ua e tusi mai mea mamafa ia te au;", "For thou writest bitter things against me,"], ["ua e faia foi mo'u tofi o agasala na ou faia ina ou taulealea.", "and makest me to possess the iniquities of my youth."]]},
  {num:27,words:[["Ua e tuu foi o'u vae i laau faamau,", "Thou puttest my feet also in the stocks,"], ["ua e lamalama foi i o'u ala uma;", "and lookest narrowly unto all my paths;"], ["ua e puipuia o'u alofivae.", "thou settest a print upon the heels of my feet."]]},
  {num:28,words:[["E palagia lava o ia e pei o le mea ua pala,", "And he, as a rotten thing,"], ["e pei o se ofu ua atia e le mogamoga.", "consumeth, as a garment that is moth eaten."]]},
];
renderVerseSet(job_ch_13_Verses, 'job-ch13-verses');

var job_ch_14_Verses = [
  {num:1,words:[["O le tagata ua fanau mai i le fafine, ua saasaa ona aso,", "Man that is born of a woman is of few days,"], ["mona ua tumu i le atuatuvale.", "and full of trouble."]]},
  {num:2,words:[["E tupu ae o ia e pei o le fuga,", "He cometh forth like a flower,"], ["a e salaeseina;", "and is cut down:"], ["e mavae atu foi o ia e pei o le ata,", "he fleeth also as a shadow,"], ["ma ua le tumau.", "and continueth not."]]},
  {num:3,words:[["Se tagata faapena ea e silasila i ai ou fofoga,", "And dost thou open thine eyes upon such an one,"], ["ma e au mai ia te au e faamasinoina faatasi ma oe?", "and bringest me into judgment with thee?"]]},
  {num:4,words:[["Po o ai ea e aumai se mea mamā nai le mea eleelea? E leai se tasi.", "Who can bring a clean thing out of an unclean? not one."]]},
  {num:5,words:[["Faauta,", "Seeing his days are determined,"], ["ua tuupoina ona aso; o loo ia te oe le faitau o ona masina;", "the number of his months are with thee,"], ["ua e tuuina lona tuaoi e le sopoia e ia.", "thou hast appointed his bounds that he cannot pass;"]]},
  {num:6,words:[["O lea ia e silasila ese ai ia te ia,", "Turn from him, that he may rest,"], ["ia mapu ai o ia,", "till he shall accomplish,"], ["seia faaatoaina e ia lona aso e pei o le ua galue i le taui.", "as an hireling, his day."]]},
  {num:7,words:[["Auā a tā le laau,", "For there is hope of a tree,"], ["e faamoemoe i ai e toe tupu,", "if it be cut down, that it will sprout again,"], ["e le aunoa foi ma ona tatupu.", "and that the tender branch thereof will not cease."]]},
  {num:8,words:[["E ui lava ina ua leva ona aa i le eleele,", "Though the root thereof wax old in the earth,"], ["ma ua mate lona tafue i le eleele,", "and the stock thereof die in the ground;"]]},
  {num:9,words:[["a e toe tupu ae i le susū o le vai, ma tutupu ona la,", "Yet through the scent of water it will bud,"], ["e pei o le laau tupu.", "and bring forth boughs like a plant."]]},
  {num:10,words:[["A o le tagata e oti o ia,", "But man dieth,"], ["ma taatia,", "and wasteth away:"], ["e to foi le mānava a le tagata,", "yea, man giveth up the ghost,"], ["ona ifea lea o ia?", "and where is he?"]]},
  {num:11,words:[["E pe le suāvai nai le vai, e mate foi le vaitafe,", "As the waters fail from the sea,"], ["ma ua matutu.", "and the flood decayeth and drieth up:"]]},
  {num:12,words:[["E taoto foi le tagata a e le toe tulai,", "So man lieth down,"], ["seia mavae le lagi,", "and riseth not:"], ["latou te le ala,", "till the heavens be no more, they shall not awake,"], ["e le fagua foi i latou i lo latou moe.", "nor be raised out of their sleep."]]},
  {num:13,words:[["E! Fia natia a'u e oe i le tuugamau ma ia e faaliloina a'u,", "O that thou wouldest hide me in the grave,"], ["seia mavae atu lou toasa;", "that thou wouldest keep me secret,"], ["ia e atofaina mai se aso mo a'u,", "until thy wrath be past, that thou wouldest appoint me a set time,"], ["ma ia e manatua mai ai a'u.", "and remember me!"]]},
  {num:14,words:[["Afai e oti le tagata,", "If a man die,"], ["e toe ola mai ea o ia? Ou te faatalitali atu i aso uma o le taua ua tofia ai a'u,", "shall he live again? all the days of my appointed time will I wait,"], ["seia oo ina suia o a'u.", "till my change come."]]},
  {num:15,words:[["Ia e valaau mai,", "Thou shalt call,"], ["ona ou tali atu ai lea ia te oe;", "and I will answer thee:"], ["ia e finagalo alofa i le galuega a ou aao.", "thou wilt have a desire to the work of thine hands."]]},
  {num:16,words:[["Auā ua e faitaulia nei o'u laasaga,", "For now thou numberest my steps:"], ["e le ua e lamalama ea i a'u agasala?", "dost thou not watch over my sin?"]]},
  {num:17,words:[["Ua faamaufaailogaina lo'u solitulafono i le taga,", "My transgression is sealed up in a bag,"], ["ma e faaopoopoina faatasi la'u amioletonu.", "and thou sewest up mine iniquity."]]},
  {num:18,words:[["E moni e mavae le mauga ua solo,", "And surely the mountain falling cometh to nought,"], ["e siitia foi le papa ai le mea sa i ai.", "and the rock is removed out of his place."]]},
  {num:19,words:[["E aia maa e le vai;", "The waters wear the stones:"], ["e tāfea e le lolo le eleele o le fanua;", "thou washest away the things which grow out of the dust of the earth;"], ["e te faaumatia foi le faamoemoe o le tagata.", "and thou destroyest the hope of man."]]},
  {num:20,words:[["E te manumalo pea lava ia te ia,", "Thou prevailest for ever against him,"], ["e alu ese ai foi o ia;", "and he passeth:"], ["ua e liua ona mata,", "thou changest his countenance,"], ["ona e auina atu ai lea o ia.", "and sendest him away."]]},
  {num:21,words:[["E oo ina mamalu ona atalii,", "His sons come to honour,"], ["a e le iloa e ia;", "and he knoweth it not;"], ["e faaleaogaina foi i latou,", "and they are brought low,"], ["a e le lagona ai e ia.", "but he perceiveth it not of them."]]},
  {num:22,words:[["A e tigaina lona lava tino,", "But his flesh upon him shall have pain,"], ["ma faanoanoa lona lava loto.", "and his soul within him shall mourn."]]},
];
renderVerseSet(job_ch_14_Verses, 'job-ch14-verses');

var job_ch_15_Verses = [
  {num:1,words:[["Ona tali mai ai lea o Elifasa le Timanu,", "Then answered Eliphaz the Temanite,"], ["ua faapea mai,", "and said,"]]},
  {num:2,words:[["E ono ea i le tagata poto ona tali atu ma le poto e le aoga,", "Should a wise man utter vain knowledge,"], ["ma faatumuina lona manava i le matagi mai sasae?", "and fill his belly with the east wind?"]]},
  {num:3,words:[["E aoai atu ea o ia i upu e le aoga, ma lauga e le tupu ai se lelei?", "Should he reason with unprofitable talk? or with speeches wherewith he can do no good?"]]},
  {num:4,words:[["A o oe,", "Yea,"], ["ua e faaleaogaina le mata'u,", "thou castest off fear,"], ["ma ua e faaleaogaina le tatalo i luma o le Atua.", "and restrainest prayer before God."]]},
  {num:5,words:[["Auā ua faailoa e lou lava gutu lau amioletonu,", "For thy mouth uttereth thine iniquity,"], ["ma ua e filifilia le laulaufaiva o e fai togafiti.", "and thou choosest the tongue of the crafty."]]},
  {num:6,words:[["Ua faasalaina oe e lou lava gutu,", "Thine own mouth condemneth thee,"], ["a e le o a'u;", "and not I: yea,"], ["ua molimau foi ou laugutu ia te oe.", "thine own lips testify against thee."]]},
  {num:7,words:[["O oe ea le uluai tagata na fanau mai? Pe na fanaua ea oe e muamua i mauga?", "Art thou the first man that was born? or wast thou made before the hills?"]]},
  {num:8,words:[["Ua e faalogologo ea i le pulega a le Atua? Ua e taofia ea le poto mo oe lava?", "Hast thou heard the secret of God? and dost thou restrain wisdom to thyself?"]]},
  {num:9,words:[["Se a se mea ua e iloa,", "What knowest thou,"], ["e le iloa foi e i matou? Se a se mea ua e poto ai,", "that we know not? what understandest thou,"], ["e le o ia te i matou foi?", "which is not in us?"]]},
  {num:10,words:[["O loo ia te i matou ē ulusinā atoa ma toeaina,", "With us are both the grayheaded and very aged men,"], ["e sili ona matutua i lou tamā.", "much elder than thy father."]]},
  {num:11,words:[["Ua faatauvaa ea ia te oe o faamafanafanaga mai le Atua, atoa ma upu mālie ua fai atu ia te oe?", "Are the consolations of God small with thee? is there any secret thing with thee?"]]},
  {num:12,words:[["Se a le mea ua ta'ita'ieseina ai oe e lou loto? Pe se a foi le mea ua e mata faasiasia ai?", "Why doth thine heart carry thee away? and what do thy eyes wink at,"]]},
  {num:13,words:[["Auā ua e liliu lou loto e tetee i le Atua,", "That thou turnest thy spirit against God,"], ["ma ua e faapunaia upu ai lou gutu.", "and lettest such words go out of thy mouth?"]]},
  {num:14,words:[["Se a ea le tagata,", "What is man,"], ["ia mamā ai o ia,", "that he should be clean? and he which is born of a woman,"], ["ma ia amiotonu lē ua fanau mai le fafine?", "that he should be righteous?"]]},
  {num:15,words:[["Faauta,", "Behold,"], ["ua le faatuatua o ia i lona au paia;", "he putteth no trust in his saints; yea,"], ["ua le mamā foi le lagi i lana silafaga.", "the heavens are not clean in his sight."]]},
  {num:16,words:[["E matuā sili ai ona inosia ma leaga le tagata,", "How much more abominable and filthy is man,"], ["o lē inu i le amio leaga e pei o le vai.", "which drinketh iniquity like water?"]]},
  {num:17,words:[["Ou te faailoa atu ia te oe,", "I will shew thee,"], ["ia e faalogologo mai ia te au;", "hear me;"], ["ou te faamatalaina atu foi le mea ua ou vaaia;", "and that which I have seen I will declare;"]]},
  {num:18,words:[["o le mea na faailoa mai e o popoto, sa iloa ai i latou tamā,", "Which wise men have told from their fathers,"], ["mona ua latou le natia.", "and have not hid it:"]]},
  {num:19,words:[["Sa tuuina mai le lalolagi ia te i latou na o i latou lava;", "Unto whom alone the earth was given,"], ["sa le ui ane foi se tagata ese ia te i latou.", "and no stranger passed among them."]]},
  {num:20,words:[["Ua puapuagatia i ona aso uma le tagata amio leaga;", "The wicked man travaileth with pain all his days,"], ["ua natia foi i le tagata saua le faitau o ona tausaga.", "and the number of years is hidden to the oppressor."]]},
  {num:21,words:[["Ua i ona taliga le leo e mata'u ai;", "A dreadful sound is in his ears:"], ["e oo atu ia te ia le na te faaumatia a o manuia o ia.", "in prosperity the destroyer shall come upon him."]]},
  {num:22,words:[["Ua le manatu o ia e toe foi mai o ia ai le pouliuli;", "He believeth not that he shall return out of darkness,"], ["ua lamatia foi o ia e le pelu.", "and he is waited for of the sword."]]},
  {num:23,words:[["Ua fealualuai o ia e saili i mea e 'ai,", "He wandereth abroad for bread,"], ["ua faapea ane ,", "saying,"], ["Po o ifea o i ai? Ua iloa o ia ua latalata mai lava ia te ia le aso o le pouliuli.", "Where is it? he knoweth that the day of darkness is ready at his hand."]]},
  {num:24,words:[["Ua faamatautia o ia e le puapuaga ma le tiga;", "Trouble and anguish shall make him afraid;"], ["la te manumalo ia te ia,", "they shall prevail against him,"], ["e pei o le tupu ua sauni i le taua.", "as a king ready to the battle."]]},
  {num:25,words:[["Auā ua faaloaloa atu e ia lona lima i le Atua,", "For he stretcheth out his hand against God,"], ["ua faamalosia o ia e ia e tetee atu i Le e ona le malosi uma lava.", "and strengtheneth himself against the Almighty."]]},
  {num:26,words:[["E osofai o ia ia te ia ma le ua maaa ,", "He runneth upon him, even on his neck,"], ["ma tua o ona talita ua putuputu.", "upon the thick bosses of his bucklers:"]]},
  {num:27,words:[["Auā e puputa lava ona mata,", "Because he covereth his face with his fatness,"], ["ma matuā puta lava o ia.", "and maketh collops of fat on his flanks."]]},
  {num:28,words:[["O le mea lea e nofo ai o ia i aai ua faaumatia,", "And he dwelleth in desolate cities,"], ["o fale foi ua le āina,", "and in houses which no man inhabiteth,"], ["e lata ona avea ma faupuegāmaa.", "which are ready to become heaps."]]},
  {num:29,words:[["E le mauoa o ia,", "He shall not be rich,"], ["e le tumau foi lona oloa,", "neither shall his substance continue,"], ["e le faateleina lava e ia a latou mea i le nuu.", "neither shall he prolong the perfection thereof upon the earth."]]},
  {num:30,words:[["E le alu ese o ia i le pouliuli;", "He shall not depart out of darkness;"], ["e faamamagoina ona tatupu i le afi mumū,", "the flame shall dry up his branches,"], ["e avea foi o ia e le mānava o lona fofoga.", "and by the breath of his mouth shall he go away."]]},
  {num:31,words:[["O le ua faaseseina, aua le faatuatua o ia i le mea faatauvaa;", "Let not him that is deceived trust in vanity:"], ["auā e fai mona taui le mea faatauvaa.", "for vanity shall be his recompence."]]},
  {num:32,words:[["Na te le aulia le atoatoa o ona aso,", "It shall be accomplished before his time,"], ["e le lauolaola foi ona la.", "and his branch shall not be green."]]},
  {num:33,words:[["Na te saaluuina ona fua moto, e pei o le vine,", "He shall shake off his unripe grape as the vine,"], ["ma lafoa ona fuga, e pei o le olive.", "and shall cast off his flower as the olive."]]},
  {num:34,words:[["Auā e autagatā le aiga o le tagata faalematau;", "For the congregation of hypocrites shall be desolate,"], ["e susunuina foi i le afi fale ie o e tali taui.", "and fire shall consume the tabernacles of bribery."]]},
  {num:35,words:[["Ua totō i latou i amio leaga,", "They conceive mischief,"], ["ua fananau foi e i latou le agasala,", "and bring forth vanity,"], ["ua sauniuni fo e o latou loto mea faa'ole'ole.", "and their belly prepareth deceit."]]},
];
renderVerseSet(job_ch_15_Verses, 'job-ch15-verses');

var job_ch_16_Verses = [
  {num:1,words:[["Ona tali atu ai lea o Iopu, ua faapea atu,", "Then Job answered and said,"]]},
  {num:2,words:[["Ua ou faalogo atu i mea faapena e tele;", "I have heard many such things:"], ["o tagata faamafanafana faasoesa o outou uma.", "miserable comforters are ye all."]]},
  {num:3,words:[["E i ai ea se iuga o upu faatauvaa? Pe se a foi se mea ua faaoso ia te oe, ina ua e tali mai?", "Shall vain words have an end? or what emboldeneth thee that thou answerest?"]]},
  {num:4,words:[["O a'u nei foi,", "I also could speak as ye do:"], ["ou te mafaia ona tautala e pei o outou,", "if your soul were in my soul's stead,"], ["pe ana fesuiaiina outou ma a'u; ou te mafaia ona faasosooina atu o upu ia te outou,", "I could heap up words against you,"], ["ma lialiai atu lo'u ulu ia te outou.", "and shake mine head at you."]]},
  {num:5,words:[["A ou te faamalosi atu ia te outou i lo'u gutu,", "But I would strengthen you with my mouth,"], ["o le tautala foi a o'u laugutu e faafeoloolo ai o outou tiga .", "and the moving of my lips should asswage your grief."]]},
  {num:6,words:[["Afai ou te tautala atu e le feoloolo ai lo'u tiga;", "Though I speak,"], ["afai ou te faalologo,", "my grief is not asswaged: and though I forbear,"], ["se a ea se tiga e te'a ai ia te au?", "what am I eased?"]]},
  {num:7,words:[["A o lenei, ua ia faavaivaia mai o a'u;", "But now he hath made me weary:"], ["ua e faaumatia lo'u aiga uma.", "thou hast made desolate all my company."]]},
  {num:8,words:[["Ua e fusifusia a'u,", "And thou hast filled me with wrinkles,"], ["ua fai lea ma molimau ia te au;", "which is a witness against me:"], ["ua tulai mai foi ia te au lo'u tino vale e molimau i o'u lava luma.", "and my leanness rising up in me beareth witness to my face."]]},
  {num:9,words:[["Ua ia saeia a'u i lona toasa,", "He teareth me in his wrath,"], ["ma ua tuliloa mai ia te au;", "who hateth me:"], ["ua li ona nifo ia te au;", "he gnasheth upon me with his teeth;"], ["ua pulatoa mai ia te au o lē ua fai a'u mona fili.", "mine enemy sharpeneth his eyes upon me."]]},
  {num:10,words:[["Ua latou faamaga o latou gutu ia te au;", "They have gaped upon me with their mouth;"], ["ua latou taia mai lo'u alafau e fai ma luma;", "they have smitten me upon the cheek reproachfully;"], ["ua latou faapotopoto faatasi e agaleaga ia te au.", "they have gathered themselves together against me."]]},
  {num:11,words:[["Ua tuuina a'u e le Atua i e ua amioletonu,", "God hath delivered me to the ungodly,"], ["ua ia tuulafoaiina a'u i lima o e amio leaga.", "and turned me over into the hands of the wicked."]]},
  {num:12,words:[["Sa ou filemu,", "I was at ease,"], ["a ua ia tu'imomomoina a'u;", "but he hath broken me asunder:"], ["ua ia pue mai foi i lo'u ua,", "he hath also taken me by my neck,"], ["ma nutininii ia te au;", "and shaken me to pieces,"], ["ua na faatuina foi a'u e fai ma manulauti ia te ia.", "and set me up for his mark."]]},
  {num:13,words:[["Ua siosiomia a'u e ana 'au e fanafana u;", "His archers compass me round about,"], ["ua ia ati i o'u fatuga'o,", "he cleaveth my reins asunder,"], ["ua le faasaoina foi e ia;", "and doth not spare;"], ["ua ia sasaaina atu lo'u au oona i le eleele.", "he poureth out my gall upon the ground."]]},
  {num:14,words:[["Ua ia fasigaugauina a'u i lea manua ma lea manua,", "He breaketh me with breach upon breach,"], ["ua ia osofai mai ia te au e pei o se fitafita.", "he runneth upon me like a giant."]]},
  {num:15,words:[["Ua ou su'ia le ie talatala i lo'u tino,", "I have sewed sackcloth upon my skin,"], ["ma ou faaleagaina lo'u nifo i le eleele.", "and defiled my horn in the dust."]]},
  {num:16,words:[["Ua fulafula o'u mata i le tagi,", "My face is foul with weeping,"], ["o loo i ai foi i o'u laumata le ata o le oti.", "and on my eyelids is the shadow of death;"]]},
  {num:17,words:[["E le ona ua i ai o se saua i o'u lima;", "Not for any injustice in mine hands:"], ["ua mamā foi la'u talosaga.", "also my prayer is pure."]]},
  {num:18,words:[["Le eleele e,", "O earth,"], ["aua e te ufitia lo'u toto,", "cover not thou my blood,"], ["aua ne'i i ai foi se mea mo la'u alaga.", "and let my cry have no place."]]},
  {num:19,words:[["O lenei foi,", "Also now,"], ["faauta,", "behold,"], ["o i le lagi lē molimau ia te au,", "my witness is in heaven,"], ["o i lugā foi lē ua i ai le mau ia te au.", "and my record is on high."]]},
  {num:20,words:[["Ua tauemu mai a'u uo ia te au;", "My friends scorn me:"], ["a ua sisina ifo loimata i o'u mata i luma o le Atua.", "but mine eye poureth out tears unto God."]]},
  {num:21,words:[["E! A na mafaia ona finau o le tagata ma le Atua,", "O that one might plead for a man with God,"], ["e pei ona finau o le tagata ma lana uo.", "as a man pleadeth for his neighbour!"]]},
  {num:22,words:[["Auā e mavae mai nai tausaga ua faitaulia,", "When a few years are come,"], ["ona ou alu atu ai lea i le ala ou te le toe foi mai ai.", "then I shall go the way whence I shall not return."]]},
];
renderVerseSet(job_ch_16_Verses, 'job-ch16-verses');

var job_ch_17_Verses = [
  {num:1,words:[["Ua itiiti la'u mānava,", "My breath is corrupt,"], ["ua mavae o'u aso,", "my days are extinct,"], ["ua saunia tuugamau mo a'u.", "the graves are ready for me."]]},
  {num:2,words:[["E le o ia te au ea e ua tauemu? E le ua ou vaai pea ea i lo latou finauvale.", "Are there not mockers with me? and doth not mine eye continue in their provocation?"]]},
  {num:3,words:[["Ia e tuu mai se faamaoni ,", "Lay down now,"], ["ina e tuu mai ia se faamaoni ia te au i la ta finauga ma oe;", "put me in a surety with thee;"], ["o ai se ma te fetagofi o ma lima?", "who is he that will strike hands with me?"]]},
  {num:4,words:[["Auā ua e punitia o latou loto ia le mafaufau;", "For thou hast hid their heart from understanding:"], ["o le mea lea e te le faasilisiliina ai i latou.", "therefore shalt thou not exalt them."]]},
  {num:5,words:[["O le na te faasinoina ana uo i e vetea mea,", "He that speaketh flattery to his friends,"], ["e avea mata o ana fanau.", "even the eyes of his children shall fail."]]},
  {num:6,words:[["Ua ia faia foi a'u ma upu faatusa i le nuu;", "He hath made me also a byword of the people;"], ["ua inosia foi a'u i o latou luma.", "and aforetime I was as a tabret."]]},
  {num:7,words:[["Ua puaoa foi o'u mata ona o le faanoanoaga,", "Mine eye also is dim by reason of sorrow,"], ["ma o'u itu tino uma e pei o le ata ia.", "and all my members are as a shadow."]]},
  {num:8,words:[["E fememeai tagata amiotonu i lenei mea,", "Upright men shall be astonied at this,"], ["e tulai atu foi le ua lē sala i le tagata faalematau.", "and the innocent shall stir up himself against the hypocrite."]]},
  {num:9,words:[["O le ua amiotonu e tumau pea o ia i lona ala,", "The righteous also shall hold on his way,"], ["o ia foi ua mamā ona lima e faaopoopoina pea lona malosi.", "and he that hath clean hands shall be stronger and stronger."]]},
  {num:10,words:[["A o outou uma,", "But as for you all,"], ["ina foi mai ia,", "do ye return,"], ["ina o mai ia;", "and come now:"], ["ou te le iloa lava se tagata poto ia te outou.", "for I cannot find one wise man among you."]]},
  {num:11,words:[["Ua mavae atu o'u aso,", "My days are past,"], ["ua faaleiuina o'u mafaufauga,", "my purposes are broken off,"], ["o manatu lava o lo'u loto.", "even the thoughts of my heart."]]},
  {num:12,words:[["Ua latou faia le po ma ao;", "They change the night into day:"], ["ua latalata le malamalama i le pouliuli.", "the light is short because of darkness."]]},
  {num:13,words:[["E moni ou te faatalitali atu i le tuugamau e fai mo'u fale;", "If I wait, the grave is mine house:"], ["ou te fofolaina lo'u moega i le pouliuli.", "I have made my bed in the darkness."]]},
  {num:14,words:[["Ua ou valaau i le pala,", "I have said to corruption,"], ["O lo'u tamā oe;", "Thou art my father:"], ["o le ilo foi,", "to the worm, Thou art my mother,"], ["O lo'u tinā ma lo'u tuafafine lea.", "and my sister."]]},
  {num:15,words:[["O i fea o i ai nei foi lo'u faamoemoe? O lo'u faamoemoe foi,", "And where is now my hope? as for my hope,"], ["po o ai ea na te vaai i ai?", "who shall see it?"]]},
  {num:16,words:[["E o ifo ia i faamau o le tuugamau,", "They shall go down to the bars of the pit,"], ["e mapu lava faatasi i le eleele.", "when our rest together is in the dust."]]},
];
renderVerseSet(job_ch_17_Verses, 'job-ch17-verses');

var job_ch_18_Verses = [
  {num:1,words:[["Ona tali mai ai lea o Pilitati le Sua,", "Then answered Bildad the Shuhite,"], ["ua faapea mai,", "and said,"]]},
  {num:2,words:[["Tou te faaiuina afea a outou upu? Ia outou mafaufau,", "How long will it be ere ye make an end of words? mark,"], ["e mulimuli ane foi matou te tautala atu ai.", "and afterwards we will speak."]]},
  {num:3,words:[["Se a le mea ua ta'umanuvaefa ai i matou,", "Wherefore are we counted as beasts,"], ["ma ua leaga ai i matou i o outou manatu?", "and reputed vile in your sight?"]]},
  {num:4,words:[["O loo saeia o ia e ia i lona ita;", "He teareth himself in his anger:"], ["e tuua ea le lalolagi ona o oe? Pe siitia ea le papa ai le mea o iai?", "shall the earth be forsaken for thee? and shall the rock be removed out of his place?"]]},
  {num:5,words:[["E tineia lava le malamalama o e amio leaga,", "Yea, the light of the wicked shall be put out,"], ["e le pupula foi le mumū o lona afi.", "and the spark of his fire shall not shine."]]},
  {num:6,words:[["E avea le malamalama ma pouliuli i lona fale ie;", "The light shall be dark in his tabernacle,"], ["e tineia foi lona lamepa i ona luga ae.", "and his candle shall be put out with him."]]},
  {num:7,words:[["E faalavelaveina ona laasaga malolosi,", "The steps of his strength shall be straitened,"], ["e lafotuina foi o ia i lana lava pule.", "and his own counsel shall cast him down."]]},
  {num:8,words:[["Auā o ona lava vae ua faaooina ai o ia i le upega,", "For he is cast into a net by his own feet,"], ["ua savali foi o ia i luga o le mailei.", "and he walketh upon a snare."]]},
  {num:9,words:[["E lāvea lona mulivae i le mailei,", "The gin shall take him by the heel,"], ["e taofimauina o ia e le matasele.", "and the robber shall prevail against him."]]},
  {num:10,words:[["Ua tatao i le eleele le matasele mo ia,", "The snare is laid for him in the ground,"], ["ma le mailei mo ia i le ala.", "and a trap for him in the way."]]},
  {num:11,words:[["E faamatautia o ia i itu uma i mea matautia,", "Terrors shall make him afraid on every side,"], ["e tulitataoina ai foi o ia.", "and shall drive him to his feet."]]},
  {num:12,words:[["E faavaivaia lona malosi i le fia 'ai,", "His strength shall be hungerbitten,"], ["e saunia foi le malaia i ona tafatafa.", "and destruction shall be ready at his side."]]},
  {num:13,words:[["E 'aina ona itu tino;", "It shall devour the strength of his skin:"], ["e 'aina lava ona itu tino e le ulumatua a le oti.", "even the firstborn of death shall devour his strength."]]},
  {num:14,words:[["E liaiina lona faatuatuaga ai lona fale ie,", "His confidence shall be rooted out of his tabernacle,"], ["na te aumaia foi o ia i le tupu o mea matautia.", "and it shall bring him to the king of terrors."]]},
  {num:15,words:[["E mau lea i lona fala ie,", "It shall dwell in his tabernacle,"], ["auā ua le toe fai mona;", "because it is none of his:"], ["e luluina le teio i luga o le mea e nofo ai o ia.", "brimstone shall be scattered upon his habitation."]]},
  {num:16,words:[["E mamago ona aa i lalō,", "His roots shall be dried up beneath,"], ["e salaeseina foi ona la i luga.", "and above shall his branch be cut off."]]},
  {num:17,words:[["E faaumatia lona faamanatuga mai le lalolagi,", "His remembrance shall perish from the earth,"], ["e leai foi sona igoa i le malae.", "and he shall have no name in the street."]]},
  {num:18,words:[["E tulia o ia ai le malamalama i le pouliuli,", "He shall be driven from light into darkness,"], ["e tulieseina foi o ia i le lalolagi.", "and chased out of the world."]]},
  {num:19,words:[["E le i ai ia te ia se atalii, e leai foi se atalii o lona atalii i lona nuu,", "He shall neither have son nor nephew among his people,"], ["e leai foi sē toe i mea sa nofo ai o ia.", "nor any remaining in his dwellings."]]},
  {num:20,words:[["E fememeai tupulaga mulimuli i lona aso,", "They that come after him shall be astonied at his day,"], ["faapei ona maua e le matautuia o e na muamua.", "as they that went before were affrighted."]]},
  {num:21,words:[["E faapena lava fale o le ua amio leaga;", "Surely such are the dwellings of the wicked,"], ["e faapea foi le mea e nofo ai le ua le iloa le Atua.", "and this is the place of him that knoweth not God."]]},
];
renderVerseSet(job_ch_18_Verses, 'job-ch18-verses');

var job_ch_19_Verses = [
  {num:1,words:[["Ona tali atu ai lea o Iopu, ua faapea atu,", "Then Job answered and said,"]]},
  {num:2,words:[["Tou te faatigaina ea lo'u loto,", "How long will ye vex my soul,"], ["ma outou tu'imomomoina a'u i upu seia afea?", "and break me in pieces with words?"]]},
  {num:3,words:[["Ua faasefulu lava ona outou faaleagaina o a'u,", "These ten times have ye reproached me:"], ["ua outou le mamā ona outou taia mai o a'u.", "ye are not ashamed that ye make yourselves strange to me."]]},
  {num:4,words:[["Afai foi e moni ua ou sese,", "And be it indeed that I have erred,"], ["ua i ai pea ia te au lava lo'u sese.", "mine error remaineth with myself."]]},
  {num:5,words:[["Afai lava e moni tou te faamaualuga mai ia te au, ma outou ta'uta'u mai ia te au mea e fai mo'u luma;", "If indeed ye will magnify yourselves against me,"], ["ia outou iloa lava;", "and plead against me my reproach:"]]},
  {num:6,words:[["o le Atua ua faaliliuina a'u,", "Know now that God hath overthrown me,"], ["ua na siomia foi a'u i lona upega.", "and hath compassed me with his net."]]},
  {num:7,words:[["Faauta,", "Behold,"], ["ou te alaga atu ona o le saua,", "I cry out of wrong,"], ["a ua le faafofogaina a'u;", "but I am not heard:"], ["ou te uio atu lava,", "I cry aloud,"], ["a e leai se faamasinoga.", "but there is no judgment."]]},
  {num:8,words:[["Ua ia puipuia lo'u ala, ou te le mafai ona sopoia atu lava,", "He hath fenced up my way that I cannot pass,"], ["ua ia tuuina foi le pouliuli i o'u magāala.", "and he hath set darkness in my paths."]]},
  {num:9,words:[["Ua ia aveeseina lo'u mamalu ia te au,", "He hath stripped me of my glory,"], ["ua ia to ese foi le palealii i lo'u ulu.", "and taken the crown from my head."]]},
  {num:10,words:[["Ua ia faaumatia a'u i itu uma;", "He hath destroyed me on every side,"], ["o le a ou alu;", "and I am gone:"], ["ua ia liaiina foi lo'u faamoemoe e pei o le laau.", "and mine hope hath he removed like a tree."]]},
  {num:11,words:[["Ua matuā toasa mai foi o ia ia te au,", "He hath also kindled his wrath against me,"], ["e peiseai foi ua na faia a'u mona fili.", "and he counteth me unto him as one of his enemies."]]},
  {num:12,words:[["Ua o mai faatasi ana 'au,", "His troops come together,"], ["ma latou tanu lo latou ala e tau ma a'u,", "and raise up their way against me,"], ["ma latou to lauapi e siosiomia ai lo'u fale ie.", "and encamp round about my tabernacle."]]},
  {num:13,words:[["Ua ia faamamaoina lava o'u uso ia te au,", "He hath put my brethren far from me,"], ["o e ua matou masani foi ua latou faia a'u ma tagata ese ia te i latou.", "and mine acquaintance are verily estranged from me."]]},
  {num:14,words:[["Ua tuua a'u e i latou matou te tuaoi,", "My kinsfolk have failed,"], ["ua faagalogalo foi ia te au e a'u aumea mamae.", "and my familiar friends have forgotten me."]]},
  {num:15,words:[["O e ua āumau i lo'u fale,", "They that dwell in mine house,"], ["atoa ma a'u auauna fafine,", "and my maids,"], ["ua latou faia a'u ma tagata ese;", "count me for a stranger:"], ["ua fai a'u ma tagata ese i o latou manatu.", "I am an alien in their sight."]]},
  {num:16,words:[["Ua ou valaau i la'u auauna,", "I called my servant,"], ["a ua le tali mai o ia;", "and he gave me no answer;"], ["ua ou aioi atu ia te ia i lo'u lava gutu.", "I intreated him with my mouth."]]},
  {num:17,words:[["E ui lava ina ou aioi atu ona o le fanau a lo'u tino,", "My breath is strange to my wife,"], ["a ua ese la'u mānava i la'u avā.", "though I intreated for the children's sake of mine own body."]]},
  {num:18,words:[["Ua 'ino'ino mai lava tama iti ia te au;", "Yea,"], ["ua ou tulai atu,", "young children despised me; I arose,"], ["a ua latou fai upu mai ia te au.", "and they spake against me."]]},
  {num:19,words:[["Ua inosia a'u e a'u aumea mamae uma;", "All my inward friends abhorred me:"], ["o i latou foi na au alofa i ai ua latou liliu ese ia te au.", "and they whom I loved are turned against me."]]},
  {num:20,words:[["Ua pipii o'u ivi i lo'u pa'u ma lo'u aano,", "My bone cleaveth to my skin and to my flesh,"], ["ua ou sao ma le pa'u o o'u nifo.", "and I am escaped with the skin of my teeth."]]},
  {num:21,words:[["Alofa mai ia outou ia te au,", "Have pity upon me,"], ["ina alofa mai ia ia te au outou o a'u uo;", "have pity upon me, O ye my friends;"], ["auā ua papai mai le aao o le Atua ia te au.", "for the hand of God hath touched me."]]},
  {num:22,words:[["Se a ea le mea tou te tulituliloa mai ai ia te au e pei o le Atua,", "Why do ye persecute me as God,"], ["ma ua outou le maoona i lo'u tino?", "and are not satisfied with my flesh?"]]},
  {num:23,words:[["E, fia tusia lava o a'u upu! E, fia tusia ai i le tusi!", "Oh that my words were now written! oh that they were printed in a book!"]]},
  {num:24,words:[["Ia togitogiina i le peni uamea ma le pulu uamea i le papa e faavavau.", "That they were graven with an iron pen and lead in the rock for ever!"]]},
  {num:25,words:[["Auā ua ou iloa, o loo soifua le na te togiolaina a'u;", "For I know that my redeemer liveth,"], ["o aso amuli foi e tulai mai ai o ia i luga o le eleele.", "and that he shall stand at the latter day upon the earth:"]]},
  {num:26,words:[["E ui lava foi ina faaumatia lenei tino pe a mavae atu lo'u pa'u,", "And though after my skin worms destroy this body,"], ["a e ou te iloa atu le Atua i lo'u tino;", "yet in my flesh shall I see God:"]]},
  {num:27,words:[["ou te iloa atu ia te ia mo a'u lava,", "Whom I shall see for myself,"], ["e vaai atu foi o'u mata ia te ia ,", "and mine eyes shall behold,"], ["a e le o se tasi;", "and not another;"], ["pe a le toe ai o'u manao i totonu ia te au.", "though my reins be consumed within me."]]},
  {num:28,words:[["Auā ua tatau pe ana outou fai mai,", "But ye should say, Why persecute we him,"], ["Se a le mea ua tatou tuliloa atu ai ia te ia? Ina ua iloa mai ia te au le aa o le upu.", "seeing the root of the matter is found in me?"]]},
  {num:29,words:[["Ia outou fefefe i le pelu;", "Be ye afraid of the sword:"], ["auā o le ita, o le agasala lea e oo mai ai le pelu;", "for wrath bringeth the punishments of the sword,"], ["ina ia iloa e outou e fai le faamasinoga.", "that ye may know there is a judgment."]]},
];
renderVerseSet(job_ch_19_Verses, 'job-ch19-verses');

var job_ch_20_Verses = [
  {num:1,words:[["Ona tali mai ai lea o Sofara le Naama,", "Then answered Zophar the Naamathite,"], ["ua faapea mai,", "and said,"]]},
  {num:2,words:[["E moni, o'u mafaufauga lava ou te tali atu ai,", "Therefore do my thoughts cause me to answer,"], ["ona o lo'u popole foi o i totonu ia te au.", "and for this I make haste."]]},
  {num:3,words:[["Ua ou faalogo atu i le aoaiga e faamaina ai a'u,", "I have heard the check of my reproach,"], ["o le faautauta foi o lo'u loto ou te tali atu ai.", "and the spirit of my understanding causeth me to answer."]]},
  {num:4,words:[["Ua e le iloa ea lenei mea talu mai le faavavau,", "Knowest thou not this of old,"], ["talu ona tuuina o le tagata i le lalolagi,", "since man was placed upon earth,"]]},
  {num:5,words:[["e saasaa le alaga fiafia o e amio leaga,", "That the triumphing of the wicked is short,"], ["o le olioli foi o le tagata faalematau o le emo o le mata lea?", "and the joy of the hypocrite but for a moment?"]]},
  {num:6,words:[["E ui lava ina oo ae lona silisili i le lagi,", "Though his excellency mount up to the heavens,"], ["ma papai atu lona ulu i ao,", "and his head reach unto the clouds;"]]},
  {num:7,words:[["e fano o ia e faavavau e pei o lona otaota;", "Yet he shall perish for ever like his own dung:"], ["e fai mai i latou o e na iloa o ia,", "they which have seen him shall say,"], ["O ifea o i ai o ia?", "Where is he?"]]},
  {num:8,words:[["E lele ese o ia e pei o le li'a,", "He shall fly away as a dream,"], ["e le maua foi o ia;", "and shall not be found: yea,"], ["e tulieseina lava o ia e pei o le mea e vaaia i le po.", "he shall be chased away as a vision of the night."]]},
  {num:9,words:[["O mata na vaai ia te ia, e le toe iloa o ia;", "The eye also which saw him shall see him no more;"], ["e le toe iloa foi o ia i le mea sa i ai o ia.", "neither shall his place any more behold him."]]},
  {num:10,words:[["E faalelei atu ona atalii i e matitiva,", "His children shall seek to please the poor,"], ["ma toe avatua e ona lima lona oloa.", "and his hands shall restore their goods."]]},
  {num:11,words:[["Ua tutumu ona ivi i ana agasala na faia ina o taulealea,", "His bones are full of the sin of his youth,"], ["e taooto foi faatasi ma ia i le eleele.", "which shall lie down with him in the dust."]]},
  {num:12,words:[["E ui lava ina suamalie le amio leaga i lona gutu,", "Though wickedness be sweet in his mouth,"], ["ma ua ia natia ai i lalo o lona laulaufaiva;", "though he hide it under his tongue;"]]},
  {num:13,words:[["e ui lava ina faapelepeleina ai e ia,", "Though he spare it,"], ["ma na le lafoaiina;", "and forsake it not;"], ["a e taofia pea i lona gutu;", "but keep it still within his mouth:"]]},
  {num:14,words:[["a e liua ana mea e 'ai i lona manava,", "Yet his meat in his bowels is turned,"], ["e avea ma mea oona a asipi i totonu ia te ia.", "it is the gall of asps within him."]]},
  {num:15,words:[["Na ia foloina le oloa,", "He hath swallowed down riches,"], ["a e toe puai mai ai,", "and he shall vomit them up again:"], ["e faateaina ai e le Atua i lona manava.", "God shall cast them out of his belly."]]},
  {num:16,words:[["E miti e ia le mea oona a asipi,", "He shall suck the poison of asps:"], ["e oti o ia i le laulaufaiva o le gata.", "the viper's tongue shall slay him."]]},
  {num:17,words:[["E le vaai o ia i vaitafe,", "He shall not see the rivers, the floods,"], ["o tafe o alia o le meli ma le suāsusu.", "the brooks of honey and butter."]]},
  {num:18,words:[["E toe avatua e ia o le mea na ia galue ai,", "That which he laboured for shall he restore,"], ["na te le 'ai ai foi;", "and shall not swallow it down:"], ["e pei o oloa e toe avatua,", "according to his substance shall the restitution be,"], ["na te le fiafia i ai .", "and he shall not rejoice therein."]]},
  {num:19,words:[["Auā ua ia faasauaina ma tuulafoaiina e ua matitiva;", "Because he hath oppressed and hath forsaken the poor;"], ["ua ia faoa le fale na ia le faia;", "because he hath violently taken away an house which he builded not;"]]},
  {num:20,words:[["o le mea lea e le iloa ai e ia se filemu i totonu ia te ia,", "Surely he shall not feel quietness in his belly,"], ["e le faasaoina e ia lana mea ua ia manao tele i ai.", "he shall not save of that which he desired."]]},
  {num:21,words:[["E le toe ai sina ana mea e 'ai;", "There shall none of his meat be left;"], ["o le mea lea e le tumau ai lona manuia.", "therefore shall no man look for his goods."]]},
  {num:22,words:[["E puapuagatia o ia a o faulai lava ana mea;", "In the fulness of his sufficiency he shall be in straits:"], ["e oo atu ia te ia lima uma o e ua tigaina.", "every hand of the wicked shall come upon him."]]},
  {num:23,words:[["A o faatumuina lona manava,", "When he is about to fill his belly,"], ["e faaooina e le Atua ia te ia lona toasa tele,", "God shall cast the fury of his wrath upon him,"], ["e faatotō ifo ai foi e ia i luga ia te ia a o 'ai o ia.", "and shall rain it upon him while he is eating."]]},
  {num:24,words:[["E sola ese o ia i le auupega uamea,", "He shall flee from the iron weapon,"], ["e fanaia ia ati i le aufana 'apa memea.", "and the bow of steel shall strike him through."]]},
  {num:25,words:[["E toina ia,", "It is drawn,"], ["e faateaeseina foi i le tino;", "and cometh out of the body;"], ["e alu atu le pelu pupula ai lona au oona;", "yea, the glittering sword cometh out of his gall:"], ["ua i ona luga o mea e matautia.", "terrors are upon him."]]},
  {num:26,words:[["Ua teteu pouliuli uma e fai mona oloa;", "All darkness shall be hid in his secret places:"], ["e 'aina o ia e le afi ua le ulaina;", "a fire not blown shall consume him;"], ["e malaia le ua toe i lona fale ie.", "it shall go ill with him that is left in his tabernacle."]]},
  {num:27,words:[["E faaali e le lagi lana amioleaga;", "The heaven shall reveal his iniquity;"], ["e tulai atu foi le lalolagi e tetee ia te ia.", "and the earth shall rise up against him."]]},
  {num:28,words:[["E avea le oloa o i lona fale,", "The increase of his house shall depart,"], ["e tafea i le aso o lona toasa.", "and his goods shall flow away in the day of his wrath."]]},
  {num:29,words:[["O le tofi lenei o le tagata amio leaga mai le Atua,", "This is the portion of a wicked man from God,"], ["o le tofi foi ua tofia ia te ia e le Atua.", "and the heritage appointed unto him by God."]]},
];
renderVerseSet(job_ch_20_Verses, 'job-ch20-verses');

var job_ch_21_Verses = [
  {num:1,words:[["Ona tali atu ai lea o Iopu, ua faapea atu, Ina matuā faalogologo mai ia outou i la'u upu,", "But Job answered and said,"]]},
  {num:2,words:[["ia faia foi lea ma a outou faamafanafanaga.", "Hear diligently my speech, and let this be your consolations."]]},
  {num:3,words:[["Ina onosai ia ia te au,", "Suffer me that I may speak;"], ["a seia ou tautala atu; a mavae atu la'u upu,", "and after that I have spoken,"], ["i le tauemu mai pea ia.", "mock on."]]},
  {num:4,words:[["A o a'u nei,", "As for me,"], ["ou te tagi atu ea i tagata? A faapea ,", "is my complaint to man? and if it were so,"], ["se a le mea e le tiga ai lo'u loto?", "why should not my spirit be troubled?"]]},
  {num:5,words:[["Ia outou vaai mai ia te au,", "Mark me,"], ["ma ia outou fememeai,", "and be astonished,"], ["ma ia tuu ae o outou lima i o outou fofoga.", "and lay your hand upon your mouth."]]},
  {num:6,words:[["A ou manatu i ai, ona ou atuatuvale ai lea,", "Even when I remember I am afraid,"], ["ua maua ai foi lo'u tino e le tetemu.", "and trembling taketh hold on my flesh."]]},
  {num:7,words:[["Se a le mea ua ola mai ai o e amio leaga,", "Wherefore do the wicked live,"], ["ua oo ina toeaina,", "become old, yea,"], ["ma faateleina lava o latou oloa?", "are mighty in power?"]]},
  {num:8,words:[["Ua faatumauina a latou fanau i o latou luma e faatasi ma i latou,", "Their seed is established in their sight with them,"], ["ma e o tutupu ia te i latou ua faatumauina o latou o vaai i ai.", "and their offspring before their eyes."]]},
  {num:9,words:[["Ua saogalemu o latou fale e leai se mea e matatau ai,", "Their houses are safe from fear,"], ["ua le i ai foi i o latou luga le sasa a le Atua.", "neither is the rod of God upon them."]]},
  {num:10,words:[["Ua ofia a latou povi,", "Their bull gendereth,"], ["ma ua le papā,", "and faileth not;"], ["e fananau a latou povi,", "their cow calveth,"], ["a e le fanau le au.", "and casteth not her calf."]]},
  {num:11,words:[["E aauina atu e i latou o latou tama iti e pei o se lafu mamoe,", "They send forth their little ones like a flock,"], ["e taaalo foi a latou fanau.", "and their children dance."]]},
  {num:12,words:[["Ua latou avae le topa ma le kitara,", "They take the timbrel and harp,"], ["ma latou olioli i le leo o le faaili.", "and rejoice at the sound of the organ."]]},
  {num:13,words:[["E faauma o latou aso o manuia,", "They spend their days in wealth,"], ["e pei o le emo o le mata ona o ifo o i latou i le tuugamau.", "and in a moment go down to the grave."]]},
  {num:14,words:[["Ua latou fai atu foi i le Atua,", "Therefore they say unto God,"], ["Ina alu ese ia oe ia te i matou,", "Depart from us;"], ["auā matou te le fia iloa ou ala.", "for we desire not the knowledge of thy ways."]]},
  {num:15,words:[["O ai ea Le e ona le malosi uma lava,", "What is the Almighty, that we should serve him? and what profit should we have,"], ["matou te auauna ai ia te ia? Se a foi sona aoga ia te i matou pe a matou tatalo atu ia te ia?", "if we pray unto him?"]]},
  {num:16,words:[["Faauta,", "Lo,"], ["e le o i o latou lima lo latou manuia;", "their good is not in their hand:"], ["ia mamao ia te au le filifiliga a e amio leaga.", "the counsel of the wicked is far from me."]]},
  {num:17,words:[["E tineia faafia ea le lamepa a e amio leaga, ma oo atu ia te i latou lo latou malaia, ma na tufatufa i ai o puapuaga i lona toasa?", "How oft is the candle of the wicked put out! and how oft cometh their destruction upon them! God distributeth sorrows in his anger."]]},
  {num:18,words:[["E tutusa i latou ma 'au o saito e lelea i le matagi,", "They are as stubble before the wind,"], ["ua tutusa foi ma le aputi o saito ua lelea i le afā.", "and as chaff that the storm carrieth away."]]},
  {num:19,words:[["E teu e le Atua lana agasala mā lana fanau;", "God layeth up his iniquity for his children:"], ["na te tauia o ia,", "he rewardeth him,"], ["e iloa ai foi e ia.", "and he shall know it."]]},
  {num:20,words:[["E iloa e ona mata lona malaia,", "His eyes shall see his destruction,"], ["e inu foi e ia i le toasa o Le e ona le malosi uma lava.", "and he shall drink of the wrath of the Almighty."]]},
  {num:21,words:[["Auā se a ea sona fiafia i lona aiga pe a mavae atu o ia,", "For what pleasure hath he in his house after him,"], ["ma vaeluaina ona masina ua faitauina.", "when the number of his months is cut off in the midst?"]]},
  {num:22,words:[["E a'oa'o atu ea se tasi le poto i le Atua? O ia lava le faamasino i e maualuluga.", "Shall any teach God knowledge? seeing he judgeth those that are high."]]},
  {num:23,words:[["E oti le tasi a o atoatoa lona manuia,", "One dieth in his full strength,"], ["ua matuā saogalemu lava o ia ma le filemu.", "being wholly at ease and quiet."]]},
  {num:24,words:[["Ua tutumu ana faagagāmanu i le suāsusu,", "His breasts are full of milk,"], ["ua su foi le aano o ona ivi.", "and his bones are moistened with marrow."]]},
  {num:25,words:[["E oti foi le tasi a o faanoanoa lona loto,", "And another dieth in the bitterness of his soul,"], ["e lei 'ai foi o ia ma le fiafia.", "and never eateth with pleasure."]]},
  {num:26,words:[["La te taooto faatasi i le eleele,", "They shall lie down alike in the dust,"], ["e liloia foi i laua i ilo.", "and the worms shall cover them."]]},
  {num:27,words:[["Faauta,", "Behold,"], ["ua ou iloa o outou mafaufauga,", "I know your thoughts,"], ["ma manatunatuga tou te faasaua mai ai ia te au.", "and the devices which ye wrongfully imagine against me."]]},
  {num:28,words:[["Auā ua outou fai mai,", "For ye say,"], ["O ifea o iai le fale o le faasaua? O i fea foi faleie e mau ai e ua amio leaga?", "Where is the house of the prince? and where are the dwelling places of the wicked?"]]},
  {num:29,words:[["Ua outou le fesili ea ia te i latou o e ui ane i le ala? Pe tou te le iloa foi o latou faailoga?", "Have ye not asked them that go by the way? and do ye not know their tokens,"]]},
  {num:30,words:[["Ua tuu le tagata amio leaga mo le aso o le malaia; e ta'ita'iina atu i latou i le aso o le toasa tele.", "That the wicked is reserved to the day of destruction? they shall be brought forth to the day of wrath."]]},
  {num:31,words:[["O ai ea na te ta'u atu lona ala i ona luma? O ai foi na te taui atu ia te ia o mea na ia faia?", "Who shall declare his way to his face? and who shall repay him what he hath done?"]]},
  {num:32,words:[["E avea foi o ia i tuugamau,", "Yet shall he be brought to the grave,"], ["e leoleo foi se tasi i le loa.", "and shall remain in the tomb."]]},
  {num:33,words:[["E suamalie ia te ia le eleele o le vanu,", "The clods of the valley shall be sweet unto him,"], ["e mulimuli solo atu foi ia te ia o tagata uma,", "and every man shall draw after him,"], ["o e ua muamua foi ia te ia e le ma faitaulia.", "as there are innumerable before him."]]},
  {num:34,words:[["A faapefea ona outou faamatalaloto mai fua ia te au? Auā ua pepelo a outou tali.", "How then comfort ye me in vain, seeing in your answers there remaineth falsehood?"]]},
];
renderVerseSet(job_ch_21_Verses, 'job-ch21-verses');

var job_ch_22_Verses = [
  {num:1,words:[["Ona tali mai ai lea o Elifasa le Timanu, ua faapea mai,", "Then Eliphaz the Temanite answered and said,"]]},
  {num:2,words:[["E aoga ea le tagata i le Atua,", "Can a man be profitable unto God,"], ["e pei ona aoga o le ua poto ia te ia lava?", "as he that is wise may be profitable unto himself?"]]},
  {num:3,words:[["Se mea ea e fiafia ai Le e ona le malosi uma lava ina ua e amiotonu? Po ua aoga ia te ia ina ua sao o au amio?", "Is it any pleasure to the Almighty, that thou art righteous? or is it gain to him, that thou makest thy ways perfect?"]]},
  {num:4,words:[["E faia ea e ia se finauga ma oe ona o le mata'u ia te oe? Na te faia ea se faamasinoga faatasi ma oe?", "Will he reprove thee for fear of thee? will he enter with thee into judgment?"]]},
  {num:5,words:[["E le ua tele ea au amio leaga, e ai foi se gataaga o au agasala?", "Is not thy wickedness great? and thine iniquities infinite?"]]},
  {num:6,words:[["Auā ua e talia fua lava mai ou uso le mea tuu faafaatau;", "For thou hast taken a pledge from thy brother for nought,"], ["ua e to ese foi ofu o e matitiva.", "and stripped the naked of their clothing."]]},
  {num:7,words:[["Ua e le avatua le vai i le ua lailoa ia inu ai;", "Thou hast not given water to the weary to drink,"], ["ua e le avatua foi le mea e 'ai i le ua fia 'ai.", "and thou hast withholden bread from the hungry."]]},
  {num:8,words:[["A o le tagata malosi,", "But as for the mighty man,"], ["ua fai mona le laueleele;", "he had the earth;"], ["ua mau ai foi le alii mamalu.", "and the honourable man dwelt in it."]]},
  {num:9,words:[["Ua e aaufuaina atu fafine ua oti a latou tane;", "Thou hast sent widows away empty,"], ["ua gauia foi lima o e ua aumatuā.", "and the arms of the fatherless have been broken."]]},
  {num:10,words:[["O le mea lea ua siosiomia ai oe i mailei;", "Therefore snares are round about thee,"], ["ua faaatuatuvaleina ai foi oe i le mata'u faafuasei;", "and sudden fear troubleth thee;"]]},
  {num:11,words:[["po o le pouliuli e te le iloa ai se mea ,", "Or darkness, that thou canst not see;"], ["ma vai e tele ua lofia ai oe.", "and abundance of waters cover thee."]]},
  {num:12,words:[["E lē o i le lagi i luga ea le Atua? Ina vaai ia foi i le maualuga o fetu,", "Is not God in the height of heaven? and behold the height of the stars,"], ["ua maualuluga lava!", "how high they are!"]]},
  {num:13,words:[["Ua e fai mai foi,", "And thou sayest,"], ["Pe silafia mai faapefea le Atua? E mafai ea ona faamasino mai o ia i tua mai o le pogisa?", "How doth God know? can he judge through the dark cloud?"]]},
  {num:14,words:[["Ua fai ao uliuli ma puipui ia te ia,", "Thick clouds are a covering to him,"], ["ua ia le silafia mai ai;", "that he seeth not;"], ["ua feafioai foi o ia i le faataaliolio o le lagi.", "and he walketh in the circuit of heaven."]]},
  {num:15,words:[["Ua e mafaufau ea i le ala tuai na savavali ai tagata amio leaga?", "Hast thou marked the old way which wicked men have trodden?"]]},
  {num:16,words:[["O e na aveeseina faafuasei,", "Which were cut down out of time,"], ["na lofia o latou faavae i le lolo.", "whose foundation was overflown with a flood:"]]},
  {num:17,words:[["O e na fai atu i le Atua,", "Which said unto God,"], ["Ina alu ese ia oe ia te i matou; i le ma lea,", "Depart from us:"], ["Se a se mea e faia e Le e ona le malosi uma lava mo i latou?", "and what can the Almighty do for them?"]]},
  {num:18,words:[["A e peitai sa faatumuina e ia lava o latou fale i mea lelei. Ia mamao ia te au le filifiliga a e amio leaga!", "Yet he filled their houses with good things: but the counsel of the wicked is far from me."]]},
  {num:19,words:[["E iloa e tagata amiotonu,", "The righteous see it,"], ["ma latou olioli ai; o e ua sao foi a latou amio,", "and are glad:"], ["latou te tauemu ia te i latou.", "and the innocent laugh them to scorn."]]},
  {num:20,words:[["E, ua fano le na fai i tatou mona fili,", "Whereas our substance is not cut down,"], ["ua faaumatia i le afi la latou faulaigāmea!", "but the remnant of them the fire consumeth."]]},
  {num:21,words:[["Ia e faamasani ma ia,", "Acquaint now thyself with him,"], ["e te filemu ai;", "and be at peace:"], ["o le mea lea e oo mai ai le manuia ia te oe.", "thereby good shall come unto thee."]]},
  {num:22,words:[["Ia e talia le tulafono mai lona fofoga,", "Receive, I pray thee,"], ["ma ia e tuu ana afioga i lou loto.", "the law from his mouth, and lay up his words in thine heart."]]},
  {num:23,words:[["Afai e te foi atu i Le e ona le malosi uma lava,", "If thou return to the Almighty,"], ["e atiina ae ai oe;", "thou shalt be built up,"], ["ia e faateamamaoina le amioletonu i ou fale ie.", "thou shalt put away iniquity far from thy tabernacles."]]},
  {num:24,words:[["Ona e teu ai lea o auro e sili i le efuefu,", "Then shalt thou lay up gold as dust,"], ["o auro foi o Ofeira e pei o maa o alia.", "and the gold of Ophir as the stones of the brooks."]]},
  {num:25,words:[["E avea foi Le e ona le malosi uma lava ma au auro,", "Yea, the Almighty shall be thy defence,"], ["ma faulaigāario ma oe.", "and thou shalt have plenty of silver."]]},
  {num:26,words:[["Ona e fiafia ai lea i Le e ona le malosi uma lava,", "For then shalt thou have thy delight in the Almighty,"], ["ma faasaga ae ou mata i le Atua.", "and shalt lift up thy face unto God."]]},
  {num:27,words:[["E te talotalo ia te ia,", "Thou shalt make thy prayer unto him,"], ["na te faafofoga mai foi ia te oe;", "and he shall hear thee,"], ["e te faataunuuina foi mea na e tauto ai.", "and thou shalt pay thy vows."]]},
  {num:28,words:[["O le mea foi e te filifili e fai,", "Thou shalt also decree a thing,"], ["e faatumauina lea mo oe;", "and it shall be established unto thee:"], ["e pupula foi le malamalama i ou ala.", "and the light shall shine upon thy ways."]]},
  {num:29,words:[["Pe a faamaulaloina nisi ,", "When men are cast down,"], ["ona e fai atu lea,", "then thou shalt say, There is lifting up;"], ["E faaeaina. Na te faaolaina foi le ua faamaulalo.", "and he shall save the humble person."]]},
  {num:30,words:[["Na te laveaiina le ua sala;", "He shall deliver the island of the innocent:"], ["e laveaiina foi o ia e ou lima mamā.", "and it is delivered by the pureness of thine hands."]]},
];
renderVerseSet(job_ch_22_Verses, 'job-ch22-verses');

var job_ch_23_Verses = [
  {num:1,words:[["Ona tali atu ai lea o Iopu, ua faapea atu,", "Then Job answered and said,"]]},
  {num:2,words:[["O lenei lava aso ua tele ai lo'u tagi;", "Even to day is my complaint bitter:"], ["ua mamafa ifo le aao ua oo mai ia te au e sili i lo'u mapuitiga.", "my stroke is heavier than my groaning."]]},
  {num:3,words:[["E, ta fia iloa po o ifea le mea ou te maua ai o ia: ia ou oo atu lava i lona afioaga!", "Oh that I knew where I might find him! that I might come even to his seat!"]]},
  {num:4,words:[["Ou te sauni atu i ona luma la'u finauga,", "I would order my cause before him,"], ["ma faateleina a'u upu e faatonu atu ai.", "and fill my mouth with arguments."]]},
  {num:5,words:[["Ou te iloa ai ana afioga na te tali mai ai ia te au;", "I would know the words which he would answer me,"], ["ou te faalogo atu ai foi pe se a lana e fetalai mai ai ia te au.", "and understand what he would say unto me."]]},
  {num:6,words:[["E finau mai ea o ia ia te au i lona malosi tele? E leai;", "Will he plead against me with his great power? No;"], ["a e manatu mai lava o ia ia te au.", "but he would put strength in me."]]},
  {num:7,words:[["Ona fai ai lea e le ua amiotonu le faatonuga ma ia;", "There the righteous might dispute with him;"], ["ona ou sao ai lea e faavavau i le na te faamasino mai ia te au.", "so should I be delivered for ever from my judge."]]},
  {num:8,words:[["Faauta mai,", "Behold,"], ["ou te alu atu i luma,", "I go forward,"], ["a e le o i ai o ia,", "but he is not there;"], ["ma tua foi,", "and backward,"], ["a e ou te le iloa o ia.", "but I cannot perceive him:"]]},
  {num:9,words:[["Ou te alu i le itu tauagavale o loo galue ai o ia,", "On the left hand,"], ["a e ou te le maua o ia;", "where he doth work,"], ["ua ufitia o ia i le itu taumatau,", "but I cannot behold him: he hideth himself on the right hand,"], ["ou te le vaaia foi o ia .", "that I cannot see him:"]]},
  {num:10,words:[["A e peitai ua silafia e ia lo'u lava ala;", "But he knoweth the way that I take:"], ["a tofotofoina a'u,", "when he hath tried me,"], ["ou te sao atu ai e pei o le auro.", "I shall come forth as gold."]]},
  {num:11,words:[["Ua tumau o'u vae i ona tulagaaao;", "My foot hath held his steps,"], ["ua ou tausisi i lona ala,", "his way have I kept,"], ["ua ou le liliu ese ai lava.", "and not declined."]]},
  {num:12,words:[["Ua ou le alu ese foi i le poloaiga a ona laufofoga;", "Neither have I gone back from the commandment of his lips;"], ["ua sili lo'u tausi i afioga a lona fofoga i a'u sauniga.", "I have esteemed the words of his mouth more than my necessary food."]]},
  {num:13,words:[["A o ia e tasi lava lona finagalo ,", "But he is in one mind, and who can turn him? and what his soul desireth,"], ["Po o ai ea se faafoi atu ia te ia? Ua faia e ia le mea ua ia finagalo i ai.", "even that he doeth."]]},
  {num:14,words:[["Auā e faataunuuina e ia le mea ua saunia mo a'u. E tele foi mea faapena ua ia te ia.", "For he performeth the thing that is appointed for me: and many such things are with him."]]},
  {num:15,words:[["O le mea lea ua ou atuatuvale ai i ona luma;", "Therefore am I troubled at his presence:"], ["a ou manatunatu,", "when I consider,"], ["ona ou mata'u ai lea ia te ia.", "I am afraid of him."]]},
  {num:16,words:[["Auā ua faavaivaia e le Atua lo'u loto; ua faaatuatuvaleina foi a'u e Le e ona le malosi uma lava;", "For God maketh my heart soft,"], ["ina ua le faaumatia", "and the Almighty troubleth me:"]]},
  {num:17,words:[["a'u a o lei oo mai le pouliuli;", "Because I was not cut off before the darkness,"], ["mona ua le ufitia e ia le pogisa ai o'u luma.", "neither hath he covered the darkness from my face."]]},
];
renderVerseSet(job_ch_23_Verses, 'job-ch23-verses');

var job_ch_24_Verses = [
  {num:1,words:[["Ua le lilo tausaga i Le e ona le malosi uma lava,", "Why,"], ["o lenei,", "seeing times are not hidden from the Almighty,"], ["se a le mea ua le iloa ai ona aso e i latou ua masani ma ia?", "do they that know him not see his days?"]]},
  {num:2,words:[["Ua sii tuaoi e nisi;", "Some remove the landmarks;"], ["ua latou faoa le lafu mamoe ,", "they violently take away flocks,"], ["ma latou fafaga ai.", "and feed thereof."]]},
  {num:3,words:[["Ua latou avea le asini a e ua aumatuā,", "They drive away the ass of the fatherless,"], ["ua latou ave le povi a le fafine ua oti lana tane e fai ma mea tuu faafaatau.", "they take the widow's ox for a pledge."]]},
  {num:4,words:[["Ua latou tuleia e ua matitiva nai le ala;", "They turn the needy out of the way:"], ["ua lalafi faatasi ai o e ua puapuagatia i le nuu.", "the poor of the earth hide themselves together."]]},
  {num:5,words:[["Faauta,", "Behold,"], ["e pei o asini o le vao i le vao,", "as wild asses in the desert,"], ["latou te o atu ai i a latou galuega,", "go they forth to their work;"], ["e ala saili i se mea e fao;", "rising betimes for a prey:"], ["o le vao latou te maua mai ai mea e 'ai ma a latou fanau.", "the wilderness yieldeth food for them and for their children."]]},
  {num:6,words:[["Ua latou selesele mea e faga a'i a latou manu i le fanua ese;", "They reap every one his corn in the field:"], ["ua latou tau le fua o le tovine ua maua i le amio leaga.", "and they gather the vintage of the wicked."]]},
  {num:7,words:[["Ua aoina o latou o faasautia o e matitiva,", "They cause the naked to lodge without clothing,"], ["e leai foi so latou ie afu i le maalili.", "that they have no covering in the cold."]]},
  {num:8,words:[["Ua sūsū i latou i le timuga i mauga,", "They are wet with the showers of the mountains,"], ["ua pipii foi i le papa ina ua leai se mea e malu ai.", "and embrace the rock for want of a shelter."]]},
  {num:9,words:[["Ua latou faoa i le susu o lona tinā le tama ua oti lona tamā;", "They pluck the fatherless from the breast,"], ["ua latou talia foi le mea tuu faafaatau i le ua mativa.", "and take a pledge of the poor."]]},
  {num:10,words:[["O i latou ua fealuai ai le ua mativa ma le le lavalavā;", "They cause him to go naked without clothing,"], ["ua fia aai foi i latou o e tautuu a latou fusi saito.", "and they take away the sheaf from the hungry;"]]},
  {num:11,words:[["Ua latou tatau le suāuu i o latou fale,", "Which make oil within their walls,"], ["ua latou solisoli i o latou soligāvine,", "and tread their winepresses,"], ["a ua latou fia inu.", "and suffer thirst."]]},
  {num:12,words:[["O loo feoi tagata i le aai,", "Men groan from out of the city,"], ["o loo alalaga foi e ua manunua;", "and the soul of the wounded crieth out:"], ["a e lei ta'usalaina i latou e le Atua.", "yet God layeth not folly to them."]]},
  {num:13,words:[["E i ai latou nei faatasi ma i latou e foua le malamalama;", "They are of those that rebel against the light;"], ["latou te le iloa ona ala,", "they know not the ways thereof,"], ["latou te le tumau foi i ona magāala.", "nor abide in the paths thereof."]]},
  {num:14,words:[["Ua tulai i le vave ao le fasi tagata, ua ia fasioti i le ua puapuagatia ma le ua mativa;", "The murderer rising with the light killeth the poor and needy,"], ["ua pei o se gaoi foi o ia i le po.", "and in the night is as a thief."]]},
  {num:15,words:[["Ua faatalitali foi le tagata mulilua i le segisegi,", "The eye also of the adulterer waiteth for the twilight,"], ["o loo faapea ifo,", "saying,"], ["E le iloa a'u e se tasi;", "No eye shall see me:"], ["ua ia ufiufi foi ona mata.", "and disguiseth his face."]]},
  {num:16,words:[["Latou te elia pa o fale i le po,", "In the dark they dig through houses,"], ["ua puipuia i latou e i latou i le ao;", "which they had marked for themselves in the daytime:"], ["ua latou le iloa le malamalama.", "they know not the light."]]},
  {num:17,words:[["Auā ua tusa ia te i latou le taeao ma le ata o le oti,", "For the morning is to them even as the shadow of death: if one know them,"], ["ina ua latou iloa mea matautia o le ata o le oti.", "they are in the terrors of the shadow of death."]]},
  {num:18,words:[["E tusa ia ma se mea māmā i luga o le vai;", "He is swift as the waters;"], ["ua faafanoina o latou tofi i le lalolagi;", "their portion is cursed in the earth:"], ["ua le faasaga o ia i le ala i tovine.", "he beholdeth not the way of the vineyards."]]},
  {num:19,words:[["Ua faaumatia vai kiona i le la ma le vevela,", "Drought and heat consume the snow waters:"], ["e faaumatia foi o e agasala i le tuugamau.", "so doth the grave those which have sinned."]]},
  {num:20,words:[["E faagalogaloina o ia e le manava o lona tinā;", "The womb shall forget him;"], ["e suamalie o ia i ilo,", "the worm shall feed sweetly on him;"], ["e le toe manatua o ia;", "he shall be no more remembered;"], ["e gauia foi le ua amioletonu e pei o le laau.", "and wickedness shall be broken as a tree."]]},
  {num:21,words:[["E agaleaga o ia i le fafine pa ua le fanau;", "He evil entreateth the barren that beareth not:"], ["ua ia le agalelei foi i le fafine ua oti lana tane.", "and doeth not good to the widow."]]},
  {num:22,words:[["E tosina foi e ia e ua malolosi i lona malosi;", "He draweth also the mighty with his power:"], ["a tulai o ia,", "he riseth up,"], ["ona le faatuatua ai lea se tasi i lona ola.", "and no man is sure of life."]]},
  {num:23,words:[["E tuuina e le Atua ia te ia ia saogalemu,", "Though it be given him to be in safety,"], ["ua ia faalagolago foi i ai;", "whereon he resteth;"], ["e silasila foi o ia i o latou ala.", "yet his eyes are upon their ways."]]},
  {num:24,words:[["E faamaualulugaina i latou i nai aso,", "They are exalted for a little while,"], ["ona leai lea o i latou;", "but are gone and brought low;"], ["ua faaumatia foi i latou, ua faapotopotoina e pei o tagata uma;", "they are taken out of the way as all other,"], ["e salaina foi i latou e pei o le tumutumu o le 'au saito.", "and cut off as the tops of the ears of corn."]]},
  {num:25,words:[["Afai e le faapea,", "And if it be not so now,"], ["o ai se na te faailoa mai lo'u pepelo,", "who will make me a liar,"], ["ma faaleaogaina la'u upu?", "and make my speech nothing worth?"]]},
];
renderVerseSet(job_ch_24_Verses, 'job-ch24-verses');

var job_ch_25_Verses = [
  {num:1,words:[["Ona tali mai ai lea o Pilitati le Sua, Ua faapea mai,", "Then answered Bildad the Shuhite,"], ["ua ia te ia le pule ma le matautia;", "and said,"]]},
  {num:2,words:[["na te faatupuina le filemu i ana mea maualuluga.", "Dominion and fear are with him, he maketh peace in his high places."]]},
  {num:3,words:[["E mafai ea ona faitaulia ana 'au? Oo ai foi se tasi ua le pupula i ai lona malamalama?", "Is there any number of his armies? and upon whom doth not his light arise?"]]},
  {num:4,words:[["O lenei, pe faapefea ona ta'uamiotonuina le tagata i luma o le Atua? Pe faapefea foi ona mamā o ia ua fanau mai i le fafine?", "How then can man be justified with God? or how can he be clean that is born of a woman?"]]},
  {num:5,words:[["Faauta,", "Behold even to the moon,"], ["o le masina ua le pupula lea;", "and it shineth not; yea,"], ["o fetu foi ua le mamā ia i lana silafaga.", "the stars are not pure in his sight."]]},
  {num:6,words:[["E atili ai ona faapea le tagata ua se tuga ia,", "How much less man, that is a worm? and the son of man,"], ["ma le fanauga a tagata ua se ilo ia.", "which is a worm?"]]},
];
renderVerseSet(job_ch_25_Verses, 'job-ch25-verses');

var job_ch_26_Verses = [
  {num:1,words:[["Ona tali atu ai lea o Iopu, ua faapea atu,", "But Job answered and said,"]]},
  {num:2,words:[["Ua faapefea ea ona e fesoasoani i le ua leai sona malosi, ma faamalosia le lima vaivai?", "How hast thou helped him that is without power? how savest thou the arm that hath no strength?"]]},
  {num:3,words:[["Ua faapefea ea ona e faatonu i le ua leai sona poto, ma faailoa tele mai le tonu?", "How hast thou counselled him that hath no wisdom? and how hast thou plentifully declared the thing as it is?"]]},
  {num:4,words:[["Ua e ta'u mai ea ia upu ia te ai? Se atamai ea o ai ua oo mai mai ia te oe?", "To whom hast thou uttered words? and whose spirit came from thee?"]]},
  {num:5,words:[["E gatete agaga o e ua oti ua i lalo,", "Dead things are formed from under the waters,"], ["o le moana foi atoa ma mea o i ai.", "and the inhabitants thereof."]]},
  {num:6,words:[["Ua taatia fua seoli i ona luma,", "Hell is naked before him,"], ["e leai foi se ufiufi o le mea o i ai le malaia.", "and destruction hath no covering."]]},
  {num:7,words:[["Ua ia folasia le itu i matu i luga o le va nimonimo, ua ia tautauina le lalolagi,", "He stretcheth out the north over the empty place,"], ["a e leai se tautaulaga .", "and hangeth the earth upon nothing."]]},
  {num:8,words:[["Ua ia 'ofu'ofuina vai i ona ao uliuli,", "He bindeth up the waters in his thick clouds;"], ["a e le masae le ao i ona lalo.", "and the cloud is not rent under them."]]},
  {num:9,words:[["Ua ia puipuia luma o lona nofoālii,", "He holdeth back the face of his throne,"], ["ua ia fofola ifo lona ao i ona luga.", "and spreadeth his cloud upon it."]]},
  {num:10,words:[["Ua tusi faataaliolio e ia tuluiga o le fogātai,", "He hath compassed the waters with bounds,"], ["e oo i le gataaga o le malamalama atoa ma le pouliuli.", "until the day and night come to an end."]]},
  {num:11,words:[["Ua luluina pou tu o le lagi, ua fememeai foi i ana aoaiga.", "The pillars of heaven tremble and are astonished at his reproof."]]},
  {num:12,words:[["O lona mana na te faamalūina ai le sami,", "He divideth the sea with his power,"], ["o lona poto foi na te taia ai lona faamaualuga.", "and by his understanding he smiteth through the proud."]]},
  {num:13,words:[["O lona agaga ua ia faamatagofie ai le lagi;", "By his spirit he hath garnished the heavens;"], ["ua manua foi i lona aao le gata televave.", "his hand hath formed the crooked serpent."]]},
  {num:14,words:[["Faauta, o mea aupito mai ia a ona ala,", "Lo,"], ["a e matuā itiiti se mea ua tatou lagona ia te ia;", "these are parts of his ways:"], ["a o le faititili o lona malosi, o ai se lagona lea?", "but how little a portion is heard of him? but the thunder of his power who can understand?"]]},
  {num:15,words:[["E tanumia", "by tanumia"], ["e le oti", "by the die"], ["e o totoe ia te ia;", "by phiral of foe unto to"], ["e le fetagisi foi", "by the fetagisi also"], ["ona fafine", "and woman"], ["ua oti", "die"], ["a latou tane.", "but them man"]]},
  {num:16,words:[["E ui", "to although"], ["ina faafaupue", "let faafaupue"], ["e ia o ario", "by him silver"], ["e pei o le efuefu,", "to to be broken the efuefu"], ["ma sauni ofu", "and he who beg^ins the game garment"], ["e pei o le omea;", "to to be broken the omea"], ["17 e saunia", "17 to prepared"], ["e ia,", "by him"], ["a e ofu ai le ua amiotonu,", "but to garment the righteous"], ["e tufatufa foi ario", "by tufatufa also silver"], ["e le ua sao lana amio.", "by the the appointed portion of his conduct"]]},
];
renderVerseSet(job_ch_26_Verses, 'job-ch26-verses');

var job_ch_27_Verses = [
  {num:1,words:[["Ua sauni atu pea foi e Iopu lana lauga,", "Moreover Job continued his parable,"], ["ua faapea atu,", "and said,"]]},
  {num:2,words:[["O loo soifua le Atua,", "As God liveth,"], ["o le ua aveesea lo'u faamasinoga;", "who hath taken away my judgment; and the Almighty,"], ["o Le e ona le malosi uma lava o le ua faatiga mai ia te au.", "who hath vexed my soul;"]]},
  {num:3,words:[["O aso uma ua i ai ia te au lo'u ola,", "All the while my breath is in me,"], ["ua i ai foi i o'u pogaiisu le mānava mai le Atua,", "and the spirit of God is in my nostrils;"]]},
  {num:4,words:[["e le tautala ai lava o'u laugutu i se mea le tonu,", "My lips shall not speak wickedness,"], ["e le tautala foi lo'u laulaufaiva i se mea pepelo.", "nor my tongue utter deceit."]]},
  {num:5,words:[["Ia mamao lava ia te au ona ou ta'ua outou ua tonu;", "God forbid that I should justify you:"], ["seia oo lava i lo'u oti ou te le faateaina lava la'u amio sao.", "till I die I will not remove mine integrity from me."]]},
  {num:6,words:[["Ou te taofimauina la'u amiotonu,", "My righteousness I hold fast,"], ["ou te le tuua lava;", "and will not let it go:"], ["e le faaleagaina a'u i lo'u loto i o'u aso uma .", "my heart shall not reproach me so long as I live."]]},
  {num:7,words:[["O lē ua fai a'u mona fili, ia avea o ia e pei o se tagata amio leaga;", "Let mine enemy be as the wicked,"], ["o lē ua tulai mai foi ia te au, ia pei o le ua amioletonu.", "and he that riseth up against me as the unrighteous."]]},
  {num:8,words:[["Auā e ui lava ina ua mau mea le tagata faalematau,", "For what is the hope of the hypocrite, though he hath gained,"], ["se a lona faamoemoe pe a avea e le Atua lona agaga?", "when God taketh away his soul?"]]},
  {num:9,words:[["E faafofogaina ea e le Atua lana alaga, pe a oo ia te ia le puapuaga?", "Will God hear his cry when trouble cometh upon him?"]]},
  {num:10,words:[["E fiafia ea o ia i Le e ona le malosi uma lava? E valaau ea o ia i le Atua i aso uma?", "Will he delight himself in the Almighty? will he always call upon God?"]]},
  {num:11,words:[["Ou te a'oa'o atu ia te outou i le aao o le Atua;", "I will teach you by the hand of God:"], ["ou te le natia mea ua i ai i Le e ona le malosi uma lava.", "that which is with the Almighty will I not conceal."]]},
  {num:12,words:[["Faauta,", "Behold,"], ["ua outou iloa e outou uma lava; o lenei,", "all ye yourselves have seen it;"], ["se a le mea ua outou fai mai ai upu matuā faatauvaa?", "why then are ye thus altogether vain?"]]},
  {num:13,words:[["O lenei le tofi o le tagata amio leaga mai le Atua,", "This is the portion of a wicked man with God, and the heritage of oppressors,"], ["o le tofi foi o e faasaua latou te maua mai i Le e ona le malosi uma lava.", "which they shall receive of the Almighty."]]},
  {num:14,words:[["Afai e faatoateleina ona atalii e fai i latou mo le pelu;", "If his children be multiplied, it is for the sword:"], ["e le maoona foi ana fanau i mea e 'ai.", "and his offspring shall not be satisfied with bread."]]},
  {num:15,words:[["E tanumia e le oti e o totoe ia te ia;", "Those that remain of him shall be buried in death:"], ["e le fetagisi foi ona fafine ua oti a latou tane.", "and his widows shall not weep."]]},
  {num:16,words:[["E ui ina faafaupue e ia o ario e pei o le efuefu,", "Though he heap up silver as the dust,"], ["ma sauni ofu e pei o le omea;", "and prepare raiment as the clay;"]]},
  {num:17,words:[["e saunia e ia,", "He may prepare it,"], ["a e ofu ai le ua amiotonu,", "but the just shall put it on,"], ["e tufatufa foi ario e le ua sao lana amio.", "and the innocent shall divide the silver."]]},
  {num:18,words:[["Ua ia faia lona fale e pei o se pepe,", "He buildeth his house as a moth,"], ["e pei o se fale apitaga foi ua faia e le leoleo.", "and as a booth that the keeper maketh."]]},
  {num:19,words:[["E taoto le mauoa,", "The rich man shall lie down,"], ["a e le faaopoopoina atu i ona tamā;", "but he shall not be gathered:"], ["e pupula ona mata,", "he openeth his eyes,"], ["ona leai ai lea o ia.", "and he is not."]]},
  {num:20,words:[["E oo atu ia te ia mea matautia e pei o vai,", "Terrors take hold on him as waters,"], ["e avea o ia e le asiosio i le po.", "a tempest stealeth him away in the night."]]},
  {num:21,words:[["E lelea o ia e le matagi mai sasae,", "The east wind carrieth him away,"], ["ona alu ai lea;", "and he departeth:"], ["e matuā lelea ese ai o ia i le mea sa nofo ai.", "and as a storm hurleth him out of his place."]]},
  {num:22,words:[["E faaoo e le Atua ia mea ia te ia,", "For God shall cast upon him,"], ["a e le faasaoina;", "and not spare:"], ["e matuā fia sola ese ia i lona aao.", "he would fain flee out of his hand."]]},
  {num:23,words:[["E pāti lima tagata ia te ia,", "Men shall clap their hands at him,"], ["ma tuliuisa ia te ia ai le mea e nofo ai o ia.", "and shall hiss him out of his place."]]},
];
renderVerseSet(job_ch_27_Verses, 'job-ch27-verses');

var job_ch_28_Verses = [
  {num:1,words:[["O i ai lava le mea e maua ai le ario,", "Surely there is a vein for the silver,"], ["ma le mea mo le auro latou te faamamāina ai.", "and a place for gold where they fine it."]]},
  {num:2,words:[["E maua le uamea i le eleele,", "Iron is taken out of the earth,"], ["e tunu ia liu suāvai le maa e maua ai 'apa memea.", "and brass is molten out of the stone."]]},
  {num:3,words:[["E faagataina e le tagata le pouliuli,", "He setteth an end to darkness,"], ["e matuā suesueina foi e ia mea uma;", "and searcheth out all perfection: the stones of darkness,"], ["o maa o i ai i le pouliuli ma le ata o le oti.", "and the shadow of death."]]},
  {num:4,words:[["E elia e ia le lua maulalo e mamao ma le mea e nonofo ai tagata ,", "The flood breaketh out from the inhabitant;"], ["e faagalogaloina e le vae;", "even the waters forgotten of the foot: they are dried up,"], ["ua latou tautau ma tāupe e mamao ae ma tagata.", "they are gone away from men."]]},
  {num:5,words:[["E tupu mai mea e 'ai i le laueleele;", "As for the earth, out of it cometh bread:"], ["o ona lalo foi pe a suatia e i ai e peiseai o le afi.", "and under it is turned up as it were fire."]]},
  {num:6,words:[["O ona maa o le mea lea e i ai safaira,", "The stones of it are the place of sapphires:"], ["e i ai foi efuefu auro.", "and it hath dust of gold."]]},
  {num:7,words:[["O le ala i ai e le iloa e le manu lele e feai,", "There is a path which no fowl knoweth,"], ["e le vaai i ai foi mata o le aia.", "and which the vulture's eye hath not seen:"]]},
  {num:8,words:[["E le savavali i ai manu feai,", "The lion's whelps have not trodden it,"], ["e le ui ai le leona.", "nor the fierce lion passed by it."]]},
  {num:9,words:[["E tago atu le lima o le tagata i le papa alā,", "He putteth forth his hand upon the rock;"], ["na te fulisia mauga ai o latou vae mauga .", "he overturneth the mountains by the roots."]]},
  {num:10,words:[["E foa e ia alāvai i papa;", "He cutteth out rivers among the rocks;"], ["e vaai atu foi ona mata i mea tāua uma.", "and his eye seeth every precious thing."]]},
  {num:11,words:[["E punitia e ia vaitafe ia le tulutulu ifo;", "He bindeth the floods from overflowing;"], ["na te au mai foi i le malamalama le mea sa lilo.", "and the thing that is hid bringeth he forth to light."]]},
  {num:12,words:[["Ao le poto e maua lea i fea? Po o i fea foi le mea o iai le mafaufau?", "But where shall wisdom be found? and where is the place of understanding?"]]},
  {num:13,words:[["E le iloa sona tau e le tagata;", "Man knoweth not the price thereof;"], ["e le maua foi i le nuu o tagata ola.", "neither is it found in the land of the living."]]},
  {num:14,words:[["Ua fai mai le moana,", "The depth saith,"], ["E le o i ai lea ia te au;", "It is not in me:"], ["ua fai mai foi le sami,", "and the sea saith,"], ["E le o ia te au.", "It is not with me."]]},
  {num:15,words:[["E le taulia i auro lelei,", "It cannot be gotten for gold,"], ["e le fuatia atu foi ario e faatau a'i.", "neither shall silver be weighed for the price thereof."]]},
  {num:16,words:[["E le faatatauina i auro mai Ofeira,", "It cannot be valued with the gold of Ophir,"], ["po o le soama tāua,", "with the precious onyx,"], ["po o le safaira.", "or the sapphire."]]},
  {num:17,words:[["E le faatusatusa i ai auro ma maa tioata;", "The gold and the crystal cannot equal it:"], ["e le fesuiaiina foi i teugāauro lelei.", "and the exchange of it shall not be for jewels of fine gold."]]},
  {num:18,words:[["E le ta'ua ramuta ma le kapesa,", "No mention shall be made of coral, or of pearls:"], ["auā a maua le poto e sili lea i penina.", "for the price of wisdom is above rubies."]]},
  {num:19,words:[["E le faatusatusa i ai le topasi mai Kusa,", "The topaz of Ethiopia shall not equal it,"], ["e le faatatauina i auro lelei.", "neither shall it be valued with pure gold."]]},
  {num:20,words:[["O lenei, pe sau mai fea le poto? Po o i fea foi le mea o iai le mafaufau?", "Whence then cometh wisdom? and where is the place of understanding?"]]},
  {num:21,words:[["Auā ua natia i mata o e ola uma lava,", "Seeing it is hid from the eyes of all living,"], ["ua lilo foi i manu felelei.", "and kept close from the fowls of the air."]]},
  {num:22,words:[["Ua fai mai le malaia ma le oti,", "Destruction and death say,"], ["Ua lagona e o ma taliga lona logo.", "We have heard the fame thereof with our ears."]]},
  {num:23,words:[["Ua silasila le Atua i lona ala,", "God understandeth the way thereof,"], ["o ia lava ua silafia le mea o i ai.", "and he knoweth the place thereof."]]},
  {num:24,words:[["Auā o loo silasila o ia i tuluiga o le lalolagi;", "For he looketh to the ends of the earth,"], ["o loo silafia e ia i lalo o le lagi uma;", "and seeth under the whole heaven;"]]},
  {num:25,words:[["ina ia faatatau ai le mamafa o le matagi,", "To make the weight for the winds;"], ["ma ia fuatia ai vai i le fua.", "and he weigheth the waters by measure."]]},
  {num:26,words:[["O ona po na ia faia le tulafono mo le ua,", "When he made a decree for the rain,"], ["ma le ala mo le uila o le faititili;", "and a way for the lightning of the thunder:"]]},
  {num:27,words:[["Na silafia ai e ia,", "Then did he see it,"], ["ma na faaalia mai ai;", "and declare it;"], ["na ia saunia,", "he prepared it, yea,"], ["ma na suesueina lava.", "and searched it out."]]},
  {num:28,words:[["Na fetalai mai foi o ia i le tagata,", "And unto man he said,"], ["Faauta,", "Behold,"], ["o le mata'u i le Alii, o le poto lava lea;", "the fear of the Lord,"], ["o le 'alo ese i le amio leaga,", "that is wisdom;"], ["o le mafaufau lea.", "and to depart from evil is understanding."]]},
];
renderVerseSet(job_ch_28_Verses, 'job-ch28-verses');

var job_ch_29_Verses = [
  {num:1,words:[["Ua sauni atu pea foi e Iopu lana lauga,", "Moreover Job continued his parable,"], ["ua faapea atu,", "and said,"]]},
  {num:2,words:[["E! Ta fia faapei o masina ua mavae;", "Oh that I were as in months past,"], ["e pei o aso na tausi mai ai le Atua ia te au;", "as in the days when God preserved me;"]]},
  {num:3,words:[["ina o pupula mai lona lamepa i luga ae o lo'u ulu,", "When his candle shined upon my head,"], ["ma ua ou mafaia ona savali i le pouliuli ona o lona malamalama;", "and when by his light I walked through darkness;"]]},
  {num:4,words:[["e pei ona i ai o a'u i ona po o lo'u malosi,", "As I was in the days of my youth,"], ["ina o ma faauo ma le Atua i lo'u fale ie;", "when the secret of God was upon my tabernacle;"]]},
  {num:5,words:[["ina o faatasi ma a'u Le e ona le malosi uma lava,", "When the Almighty was yet with me,"], ["ma ua vagaia a'u e la'u fanau;", "when my children were about me;"]]},
  {num:6,words:[["ina o mulumuluina o'u vae i le suāsusu;", "When I washed my steps with butter,"], ["na faapunaia mai foi e le papa tafe suāuu mo a'u;", "and the rock poured me out rivers of oil;"]]},
  {num:7,words:[["ina ou ui ane i le aai i lo'u alu atu i le faitotoa,", "When I went out to the gate through the city,"], ["ma ou sauni lo'u nofoa i le malae.", "when I prepared my seat in the street!"]]},
  {num:8,words:[["Na iloa mai a'u e taulelea,", "The young men saw me,"], ["ma latou 'alo'alo ese ai;", "and hid themselves:"], ["na tulai foi toeaina,", "and the aged arose,"], ["ua latou laulaututū.", "and stood up."]]},
  {num:9,words:[["Na faalologo alii sili,", "The princes refrained talking,"], ["ma tuu o latou lima i o latou fofoga.", "and laid their hand on their mouth."]]},
  {num:10,words:[["Na faalologo ai siufofoga o alii;", "The nobles held their peace,"], ["na pipii ae foi o latou laulaufaiva i o latou gutu.", "and their tongue cleaved to the roof of their mouth."]]},
  {num:11,words:[["Na faalogo mai taliga,", "When the ear heard me,"], ["ona faaamuia mai ai lea ia te au;", "then it blessed me;"], ["na iloa mai e mata,", "and when the eye saw me,"], ["ona vivii mai ai lea ia te au.", "it gave witness to me:"]]},
  {num:12,words:[["Auā na ou laveaiina le ua puapuagaina,", "Because I delivered the poor that cried,"], ["ina ua valaau mai o ia, ma le ua aumatuā,", "and the fatherless,"], ["atoa ma le ua leai sona fesoasoani.", "and him that had none to help him."]]},
  {num:13,words:[["Na oo mai ia te au le faamanū o le na fai a fano;", "The blessing of him that was ready to perish came upon me:"], ["o a'u foi na pese fiafia ai le loto o le fafine ua oti lana tane.", "and I caused the widow's heart to sing for joy."]]},
  {num:14,words:[["Na fai le amiotonu mo'u ofu,", "I put on righteousness,"], ["ma ou ofu ai;", "and it clothed me:"], ["na fai la'u faamasinoga e peiseai o se ofu talaloa ma se pulou.", "my judgment was as a robe and a diadem."]]},
  {num:15,words:[["Na fai a'u ma mata o le tauaso, o vae o le pipili,", "I was eyes to the blind,"], ["o a'u lea.", "and feet was I to the lame."]]},
  {num:16,words:[["Na fai a'u ma tamā o e ua matitiva;", "I was a father to the poor:"], ["na ou suesueina foi le finauga sa ou le iloa.", "and the cause which I knew not I searched out."]]},
  {num:17,words:[["Na ou gagauina gao o le amio leaga,", "And I brake the jaws of the wicked,"], ["ma ou seia i ona nifo le mea ua faoa.", "and plucked the spoil out of his teeth."]]},
  {num:18,words:[["Na ou faapea foi,", "Then I said,"], ["Ou te oti i lo'u ofaga,", "I shall die in my nest,"], ["e faateleina foi o'u aso e pei o le oneone.", "and I shall multiply my days as the sand."]]},
  {num:19,words:[["Na sosolo atu o'u aa i le vai,", "My root was spread out by the waters,"], ["na sautia foi o'u la i le po atoa.", "and the dew lay all night upon my branch."]]},
  {num:20,words:[["Sa fou lo'u mamalu ia te au,", "My glory was fresh in me,"], ["ma la'u aufana sa faafouina pea i lo'u lima.", "and my bow was renewed in my hand."]]},
  {num:21,words:[["Sa faalogologo mai tagata ia te au,", "Unto me men gave ear,"], ["ma faatalitali mai,", "and waited,"], ["sa latou le tautala ina ua fai la'u pule.", "and kept silence at my counsel."]]},
  {num:22,words:[["E lei toe fai mai i latou ina ua mavae atu la'u upu;", "After my words they spake not again;"], ["sa mālie lava la'u lauga ia te i latou.", "and my speech dropped upon them."]]},
  {num:23,words:[["Sa latou faatalitali mai ia te au e pei ona faatalitali i le ua;", "And they waited for me as for the rain;"], ["sa latou faamaga o latou gutu e pei ona faamaga i le uaga mulimuli.", "and they opened their mouth wide as for the latter rain."]]},
  {num:24,words:[["A ou 'ata'ata ia te i latou,", "If I laughed on them,"], ["latou te lei taofi i ai;", "they believed it not;"], ["latou te lei faateaina foi o'u mata fiafia.", "and the light of my countenance they cast not down."]]},
  {num:25,words:[["Sa ou filifilia lo latou ala;", "I chose out their way,"], ["sa ou nofo atu foi o le sili ia te i latou ;", "and sat chief,"], ["ma ou nofo e pei o se tupu i ana 'au,", "and dwelt as a king in the army,"], ["e faapei o le na te faamatalaloto i e o faanoanoa.", "as one that comforteth the mourners."]]},
];
renderVerseSet(job_ch_29_Verses, 'job-ch29-verses');

var job_ch_30_Verses = [
  {num:1,words:[["A o ona po nei ua tapisa mai ai ia te au i latou e itiiti o latou aso i o'u;", "But now they that are younger than I have me in derision,"], ["ta 'ino'ino e tuu faatasi o latou tamā ma ulī o lo'u lafu mamoe.", "whose fathers I would have disdained to have set with the dogs of my flock."]]},
  {num:2,words:[["A o le malosi o latou lima se a ea lona aoga ia te au,", "Yea, whereto might the strength of their hands profit me,"], ["o e ua mavae lo latou malosi?", "in whom old age was perished?"]]},
  {num:3,words:[["O le mativa ma le oge na tino vavale ai i latou; na sosola atu i le nuu naumati,", "For want and famine they were solitary;"], ["o le pouliuli, o le taaligoligoa, ma le gaogao.", "fleeing into the wilderness in former time desolate and waste."]]},
  {num:4,words:[["O e na fafati i maluka i tafatafa o vao iti,", "Who cut up mallows by the bushes,"], ["ma aa o ratami e fai mā latou mea e 'ai.", "and juniper roots for their meat."]]},
  {num:5,words:[["Na tuliesea i latou i le mea o i ai tagata ,", "They were driven forth from among men, (they cried after them as after a thief;"], ["na latou tulialaga ia i latou e pei o se gaoi;", ")"]]},
  {num:6,words:[["ia nonofo i vanu matuā fitā,", "To dwell in the clifts of the valleys,"], ["o ana foi o le laueleele,", "in caves of the earth,"], ["ma papa.", "and in the rocks."]]},
  {num:7,words:[["Na latou fetagisi i totonu o vao iti, e pei o asini o le vao;", "Among the bushes they brayed;"], ["na faapotopotoina i latou i lalo o le vao ogoogo.", "under the nettles they were gathered together."]]},
  {num:8,words:[["O le fanau i latou a tagata vālea;", "They were children of fools,"], ["o le fanau foi a e ua le igoā;", "yea, children of base men:"], ["na tulieseina i latou i le nuu.", "they were viler than the earth."]]},
  {num:9,words:[["A o ona po nei ua avea ai a'u ma a latou pese,", "And now am I their song, yea,"], ["ua fai foi a'u ma faatauemuga ia te i latou.", "I am their byword."]]},
  {num:10,words:[["Ua latou 'ino'ino mai ia te au,", "They abhor me,"], ["ma 'alo'alo mamao ia te au;", "they flee far from me,"], ["ua latou le taofia o latou feanuga i o'u luma.", "and spare not to spit in my face."]]},
  {num:11,words:[["Auā ua tālaina e ia la'u maea,", "Because he hath loosed my cord,"], ["ma na faatigaina a'u,", "and afflicted me,"], ["ua latou tuulafoai ai le faagutu i o'u luma.", "they have also let loose the bridle before me."]]},
  {num:12,words:[["Ua tulai mai tama leaga i lo'u itu taumatau,", "Upon my right hand rise the youth;"], ["ua latou tavae mai i o'u vae,", "they push away my feet,"], ["ua latou tanu foi o latou ala ia malaia ai a'u.", "and they raise up against me the ways of their destruction."]]},
  {num:13,words:[["Ua latou lepeti lo'u ala,", "They mar my path,"], ["ua latou faateleina lo'u malaia,", "they set forward my calamity,"], ["e leai se fesoasoani ia te i latou.", "they have no helper."]]},
  {num:14,words:[["Ua latou feosofi mai i le mea ua sofaia ua lautele;", "They came upon me as a wide breaking in of waters:"], ["ua latou fetuleni mai i le mea ua lepetia.", "in the desolation they rolled themselves upon me."]]},
  {num:15,words:[["Ua faasagasaga mai ia te au mea matautia;", "Terrors are turned upon me:"], ["ua latou tuliloa mai i lo'u mamalu e pei o le matagi;", "they pursue my soul as the wind:"], ["ua mavae atu foi lo'u manuia e pei o le ao.", "and my welfare passeth away as a cloud."]]},
  {num:16,words:[["O lenei, ua faavaivaia lo'u loto i totonu ia te au;", "And now my soul is poured out upon me;"], ["ua maua a'u i aso o le puapuaga.", "the days of affliction have taken hold upon me."]]},
  {num:17,words:[["Ua tiga tele lava o'u ivi i le po,", "My bones are pierced in me in the night season:"], ["e le mapu i le gāoi o lo'u tino .", "and my sinews take no rest."]]},
  {num:18,words:[["O lo'u ma'i ina ua matuā tele ua fai mo'u ofu;", "By the great force of my disease is my garment changed:"], ["ua fusi ia te au e pei o le ua o lo'u ofu tino.", "it bindeth me about as the collar of my coat."]]},
  {num:19,words:[["Ua ia lafotuina a'u i le palapala;", "He hath cast me into the mire,"], ["ua avea foi a'u e pei o le efuefu ma le lefulefu.", "and I am become like dust and ashes."]]},
  {num:20,words:[["Ua ou alaga atu ia te oe,", "I cry unto thee,"], ["a e te le tali mai ia te au;", "and thou dost not hear me:"], ["ua ou tu atu,", "I stand up,"], ["a e te lei silasila mai ia te au.", "and thou regardest me not."]]},
  {num:21,words:[["Ua liua oe ua e faatiga ia te au;", "Thou art become cruel to me:"], ["ua e tuliloa mai ia te au i lou aao malosi.", "with thy strong hand thou opposest thyself against me."]]},
  {num:22,words:[["Ua e siitia a'u,", "Thou liftest me up to the wind;"], ["ua e faatietie ia te au i le matagi;", "thou causest me to ride upon it,"], ["ua e faavaivaia ma faamatautia a'u.", "and dissolvest my substance."]]},
  {num:23,words:[["Auā ua ou iloa e te avea a'u i le oti,", "For I know that thou wilt bring me to death,"], ["ma le fale ua tofia mo tagata ola uma lava.", "and to the house appointed for all living."]]},
  {num:24,words:[["A e peitai, na te le faaoo atu lona aao i le tuugamau,", "Howbeit he will not stretch out his hand to the grave,"], ["pe afai e i ai ia te i latou le tatalo i lona faaooina o le malaia.", "though they cry in his destruction."]]},
  {num:25,words:[["Ou te lei tagi ea ona o le na puapuagatia? E lei faanoanoa ea lo'u loto ona o le ua mativa?", "Did not I weep for him that was in trouble? was not my soul grieved for the poor?"]]},
  {num:26,words:[["Na ou faatalitali i le lelei,", "When I looked for good,"], ["ona oo mai ai lea o le leaga;", "then evil came unto me:"], ["na ou faamoemoe foi i le malamalama,", "and when I waited for light,"], ["ona oo mai ai lea o le pogisa.", "there came darkness."]]},
  {num:27,words:[["Ua sapotuvale lo'u manava,", "My bowels boiled,"], ["ma ua le to'a filemu;", "and rested not:"], ["ua oo mai ia te au aso o le puapuaga.", "the days of affliction prevented me."]]},
  {num:28,words:[["Ua ou fealuai ua uliuli a e le o le la;", "I went mourning without the sun:"], ["ua ou tulai i le faapotopotoga,", "I stood up,"], ["ma ou alaga.", "and I cried in the congregation."]]},
  {num:29,words:[["Ua avea a'u ma uso o tanimo,", "I am a brother to dragons,"], ["ma uo o iaena.", "and a companion to owls."]]},
  {num:30,words:[["Ua uliuli lo'u lava pa'u,", "My skin is black upon me,"], ["ua mu foi o'u ivi i le vevela.", "and my bones are burned with heat."]]},
  {num:31,words:[["Ua liua foi la'u kitara ma faanoanoaga,", "My harp also is turned to mourning,"], ["o la'u faaili foi ua liua ma leo o e fetagisi.", "and my organ into the voice of them that weep."]]},
];
renderVerseSet(job_ch_30_Verses, 'job-ch30-verses');

var job_ch_31_Verses = [
  {num:1,words:[["Ua ou osia le feagaiga ma o'u mata,", "I made a covenant with mine eyes;"], ["se a foi le mea ou te manatu ai i se taupou?", "why then should I think upon a maid?"]]},
  {num:2,words:[["Se a foi le tofi mai le Atua o i lugā? Ma le tofi mai Le e ona le malosi uma lava o i mea maualuluga?", "For what portion of God is there from above? and what inheritance of the Almighty from on high?"]]},
  {num:3,words:[["E le ua tuu ea le malaia mo le ua amio leaga, ma le puapuaga mo e ua fai mea leaga?", "Is not destruction to the wicked? and a strange punishment to the workers of iniquity?"]]},
  {num:4,words:[["Ua le silasila ea o ia i o'u ala,", "Doth not he see my ways,"], ["ma faitaulia o'u laasaga uma?", "and count all my steps?"]]},
  {num:5,words:[["Afai ua ou savali ma le pepelo,", "If I have walked with vanity,"], ["po ua tele vavave o'u vae i le faa'ole'ole,", "or if my foot hath hasted to deceit;"]]},
  {num:6,words:[["ia fuatia a'u e ia i le fua faatautau tusa,", "Let me be weighed in an even balance,"], ["ia silafia ai e le Atua ua sao la'u amio.", "that God may know mine integrity."]]},
  {num:7,words:[["Afai ua o ese o'u vae i le ala,", "If my step hath turned out of the way,"], ["ma mulimuli atu lo'u loto i o'u mata,", "and mine heart walked after mine eyes,"], ["ma pipii mai se mea leaga i o'u lima;", "and if any blot hath cleaved to mine hands;"]]},
  {num:8,words:[["ia ou luluina atu saito,", "Then let me sow,"], ["a ia 'aina e se tasi;", "and let another eat; yea,"], ["ia liaiina foi a'u mea e tutupu.", "let my offspring be rooted out."]]},
  {num:9,words:[["Afai ua olegia lo'u loto i se fafine,", "If mine heart have been deceived by a woman,"], ["po ua ou lamalama i le faitotoa o lē ma te tuaoi;", "or if I have laid wait at my neighbour's door;"]]},
  {num:10,words:[["ia olo ai saito e la'u avā mā se tasi,", "Then let my wife grind unto another,"], ["ia taooto foi ma ia isi tane.", "and let others bow down upon her."]]},
  {num:11,words:[["Auā o le agasala tele lea,", "For this is an heinous crime; yea,"], ["o le pagota foi lea e faasalaina e faamasino.", "it is an iniquity to be punished by the judges."]]},
  {num:12,words:[["Auā o le afi lava lea e susunuina ai seia oo ina faaumatia;", "For it is a fire that consumeth to destruction,"], ["e liaiina ai foi a'u mea uma ua tutupu.", "and would root out all mine increase."]]},
  {num:13,words:[["Afai ana ou le mafai ona faamasinoina mea a la'u auauna tane ma la'u auauna fafine,", "If I did despise the cause of my manservant or of my maidservant,"], ["ina ua la finau mai ia te au;", "when they contended with me;"]]},
  {num:14,words:[["se a foi se mea ou te faia pe a tulai mai le Atua? Se a foi sa'u e tali atu ai ia te ia pe a faamasino mai o ia?", "What then shall I do when God riseth up? and when he visiteth, what shall I answer him?"]]},
  {num:15,words:[["O lē na faia a'u i le manava, e le o ia foi lea na faia o ia? E le o le toatasi ea foi na ia faia i maua i le manava?", "Did not he that made me in the womb make him? and did not one fashion us in the womb?"]]},
  {num:16,words:[["Afai ua ou taofi se mea na mananao i ai o e matitiva,", "If I have withheld the poor from their desire,"], ["po ua fole talu a'u mata o le fafine ua oti lana tane;", "or have caused the eyes of the widow to fail;"]]},
  {num:17,words:[["po ua ou 'ai toatasi na o a'u i la'u mea e 'ai,", "Or have eaten my morsel myself alone,"], ["a e lei 'ai ai foi le ua aumatuā.", "and the fatherless hath not eaten thereof;"]]},
  {num:18,words:[["Auā na ma tutupu talu ina ou itiiti e peiseai o lona tamā a'u;", "(For from my youth he was brought up with me,"], ["talu foi ina fanaua mai a'u e lo'u tinā,", "as with a father, and I have guided her from my mother's womb;"], ["ua ou tausi i le fafine ua oti lana tane .", ")"]]},
  {num:19,words:[["Afai ua ou iloa se tasi a fano ina ua leai sona ofu,", "If I have seen any perish for want of clothing,"], ["ma se ua mativa ua leai sona lavalava;", "or any poor without covering;"]]},
  {num:20,words:[["afai ua le faamanu mai ia te au lona sulugatiti,", "If his loins have not blessed me,"], ["afai foi ua le mafanafana o ia i fulufulu o a'u mamoe;", "and if he were not warmed with the fleece of my sheep;"]]},
  {num:21,words:[["afai ua ou sii atu lo'u lima i le ua aumatuā,", "If I have lifted up my hand against the fatherless,"], ["ina ua ou iloa i le faitotoa e fesoasoani ia te au;", "when I saw my help in the gate:"]]},
  {num:22,words:[["ia paū ese ai lo'u tau'au i le ivisa,", "Then let mine arm fall from my shoulder blade,"], ["ia fa'ia foi lo'u lima ai le tulilima.", "and mine arm be broken from the bone."]]},
  {num:23,words:[["Auā ua ia te au le mata'u i le malaia mai le Atua;", "For destruction from God was a terror to me,"], ["ua ou le mafaia foi ona o lona silisili.", "and by reason of his highness I could not endure."]]},
  {num:24,words:[["Afai ua ou fai auro ma mea ou te faalagolago i ai,", "If I have made gold my hope,"], ["po ua ou fai atu i auro,", "or have said to the fine gold,"], ["O lo'u faatuatuaga oe;", "Thou art my confidence;"]]},
  {num:25,words:[["afai ua ou olioli ina ua tele lo'u oloa,", "If I rejoiced because my wealth was great,"], ["ina ua maua foi e o'u lima mea e tele,", "and because mine hand had gotten much;"]]},
  {num:26,words:[["afai ua ou vaai i le la ina ua pupula mai; ma le masina ina ua alualu ae,", "If I beheld the sun when it shined,"], ["ma susulu mai;", "or the moon walking in brightness;"]]},
  {num:27,words:[["ma ua olegia faalilolilo lo'u loto,", "And my heart hath been secretly enticed,"], ["ma ua miti ai lo'u gutu i lo'u lima;", "or my mouth hath kissed my hand:"]]},
  {num:28,words:[["o le agasala lava lea e faasalaina e faamasino;", "This also were an iniquity to be punished by the judge:"], ["auā o le tuua lea e a'u o le Atua o i lugā.", "for I should have denied the God that is above."]]},
  {num:29,words:[["Afai ua ou olioli i le malaia o le ua 'ino'ino mai ia te au,", "If I rejoiced at the destruction of him that hated me,"], ["ma ou faatuumana ina ua maua o ia i le leaga;", "or lifted up myself when evil found him:"]]},
  {num:30,words:[["ua ou le mafaia foi ona agasala lo'u gutu i le ole atu ia faafanoina o ia.", "Neither have I suffered my mouth to sin by wishing a curse to his soul."]]},
  {num:31,words:[["Ua le fai ane ea o lo'u au aiga,", "If the men of my tabernacle said not,"], ["O ai ea ua le ma'ona i ana manu?", "Oh that we had of his flesh! we cannot be satisfied."]]},
  {num:32,words:[["E lei moe i fafo le tagata ese;", "The stranger did not lodge in the street:"], ["ua ou faaavanoa lo'u faitotoa ma malaga.", "but I opened my doors to the traveller."]]},
  {num:33,words:[["Afai ua ou ufiufi lo'u solitulafono e pei o Atamu,", "If I covered my transgressions as Adam,"], ["i lo'u natia o la'u agasala i lo'u loto,", "by hiding mine iniquity in my bosom:"]]},
  {num:34,words:[["ia ou fefe lava i le vao tagata e toatele;", "Did I fear a great multitude,"], ["ia faaatuatuvaleina a'u i le 'ino'ino mai o aiga;", "or did the contempt of families terrify me,"], ["ia ou faalologo foi,", "that I kept silence,"], ["ia ou le toe ulufafo i le faitotoa", "and went not out of the door?"]]},
  {num:35,words:[["E! Fia faafofogaina mai a'u e ia. Faauta,", "Oh that one would hear me! behold,"], ["o lo'u faailoga;", "my desire is,"], ["ia tali mai Le e ona le malosi uma lava ia te au,", "that the Almighty would answer me,"], ["ma ia tusia se tusi e le tagata ua finau mai ia te au.", "and that mine adversary had written a book."]]},
  {num:36,words:[["Ou te faafuataina lava;", "Surely I would take it upon my shoulder,"], ["ou te nonoaina lava e fai mo'u pale.", "and bind it as a crown to me."]]},
  {num:37,words:[["Ou te faaali atu ia te ia le faitau o o'u laasaga;", "I would declare unto him the number of my steps;"], ["ou te faalatalata atu ia te ia e pei o se alii sili.", "as a prince would I go near unto him."]]},
  {num:38,words:[["Afai e alaga atu lo'u fanua ona o a'u,", "If my land cry against me,"], ["ma fetagisi faatasi ona atu pue;", "or that the furrows likewise thereof complain;"]]},
  {num:39,words:[["afai ua ou 'aina ona fua ma le le tauia,", "If I have eaten the fruits thereof without money,"], ["ma ou faasaunoa i e pule i ai,", "or have caused the owners thereof to lose their life:"]]},
  {num:40,words:[["ia tupu mai ai le laau talatala e sui a'i le saito,", "Let thistles grow instead of wheat,"], ["ma le vao leaga e sui a'i le karite! Ona gata lea o upu a Iopu.", "and cockle instead of barley. The words of Job are ended."]]},
];
renderVerseSet(job_ch_31_Verses, 'job-ch31-verses');

var job_ch_32_Verses = [
  {num:1,words:[["Ona le toe tali mai ai lea o ia tagata e toatolu ia Iopu,", "So these three men ceased to answer Job,"], ["auā ua amiotonu o ia i lona lava manatu.", "because he was righteous in his own eyes."]]},
  {num:2,words:[["Ona tupu ai lea o le ita o Eliu le atalii o Parakelu,", "Then was kindled the wrath of Elihu the son of Barachel the Buzite,"], ["o lo sa Pusāo so le aiga o Rama,", "of the kindred of Ram:"], ["na tupu lona ita ia Iopu, ina ua ta'uamiotonuina e ia o ia,", "against Job was his wrath kindled,"], ["a e le o le Atua.", "because he justified himself rather than God."]]},
  {num:3,words:[["Ua tupu foi lona ita i ana uo e toatolu,", "Also against his three friends was his wrath kindled,"], ["ina ua latou le mautali,", "because they had found no answer,"], ["a ua latou faasala pea ia Iopu.", "and yet had condemned Job."]]},
  {num:4,words:[["Ua faatalitali Eliu ia Iopu, seia uma atu upu,", "Now Elihu had waited till Job had spoken,"], ["auā ua toeaina i latou, a e itiiti o ia.", "because they were elder than he."]]},
  {num:5,words:[["Ua vaai atu Eliu, ua leai se tali i fofoga o ia tagata e toatolu,", "When Elihu saw that there was no answer in the mouth of these three men,"], ["ona tupu ai lea o lona ita.", "then his wrath was kindled."]]},
  {num:6,words:[["Ona tali mai ai lea o Eliu le atalii o Parakelu,", "And Elihu the son of Barachel the Buzite answered and said,"], ["o lo sa Pusā, ua faapea mai,", "I am young,"], ["Ou te itiiti a'u,", "and ye are very old;"], ["a e toeaina lava outou, o le mea lea sa ou mata'u ai,", "wherefore I was afraid,"], ["ma ou fefe e faailoa atu ia te outou la'u taofi.", "and durst not shew you mine opinion."]]},
  {num:7,words:[["Sa ou faapea,", "I said,"], ["Ia tautala mai aso,", "Days should speak,"], ["ia faailoa mai le poto e le tele o tausaga.", "and multitude of years should teach wisdom."]]},
  {num:8,words:[["A e peitai o i ai lava le agaga i totonu o le tagata;", "But there is a spirit in man:"], ["o le mānava foi a Le e ona le malosi uma lava e faapopotoina ai i latou.", "and the inspiration of the Almighty giveth them understanding."]]},
  {num:9,words:[["E le laupopoto e ua sili;", "Great men are not always wise:"], ["e le lausilafia foi le tonu e toeaina.", "neither do the aged understand judgment."]]},
  {num:10,words:[["O le mea lea ou te fai atu ai,", "Therefore I said,"], ["Faafofoga mai ia ia te au,", "Hearken to me;"], ["ou te faaali atu foi e a'u la'u taofi.", "I also will shew mine opinion."]]},
  {num:11,words:[["Faauta,", "Behold,"], ["ua ou faatalitali i a outou fetalaiga;", "I waited for your words;"], ["ua ou faalogologo atu i a outou mafaufauga,", "I gave ear to your reasons,"], ["seia filifili ni a outou fetalaiga.", "whilst ye searched out what to say."]]},
  {num:12,words:[["Ua ou mafaufau foi i a outou upu;", "Yea, I attended unto you,"], ["faauta foi,", "and,"], ["e leai so outou ua na aoai tonu ia Iopu,", "behold,"], ["po ua tali atu i ana upu.", "there was none of you that convinced Job, or that answered his words:"]]},
  {num:13,words:[["Ne'i outou fai ane,", "Lest ye should say,"], ["Ua maua e i matou le poto;", "We have found out wisdom:"], ["ua faiaina o ia i le Atua lava,", "God thrusteth him down,"], ["a e le o tagata.", "not man."]]},
  {num:14,words:[["Ua ia le sauni ana upu ia te au,", "Now he hath not directed his words against me:"], ["ou te le tali atu foi ia te ia i a outou upu.", "neither will I answer him with your speeches."]]},
  {num:15,words:[["Ua fememeai i latou;", "They were amazed,"], ["ua le toe tali mai;", "they answered no more:"], ["ua latou tuu a latou fetalaiga.", "they left off speaking."]]},
  {num:16,words:[["Ua ou faatalitali foi ina ua latou le tautala;", "When I had waited, (for they spake not,"], ["a ua faalologo i latou,", "but stood still,"], ["ua latou le toe tali mai.", "and answered no more; )"]]},
  {num:17,words:[["O a'u foi ou te tali atu lava a'u,", "I said,"], ["o a'u lava;", "I will answer also my part,"], ["ou te faaali atu la'u taofi.", "I also will shew mine opinion."]]},
  {num:18,words:[["Auā ua tumu a'u i upu,", "For I am full of matter,"], ["ua uunai mai ia te au le agaga o i totonu ia te au.", "the spirit within me constraineth me."]]},
  {num:19,words:[["Faauta,", "Behold,"], ["o lo'u loto ua pei o le uaina e lei tālaina,", "my belly is as wine which hath no vent;"], ["ua tāli pa e pei o fagu pa'u fou.", "it is ready to burst like new bottles."]]},
  {num:20,words:[["Ou te tautala atu,", "I will speak,"], ["ia ou mānava ai, ou te faamaga o'u laugutu,", "that I may be refreshed:"], ["ma ou tali atu ai.", "I will open my lips and answer."]]},
  {num:21,words:[["Aua lava ne'i ou faailogaina se tagata;", "Let me not, I pray you,"], ["aua foi ne'i ou faaneenee i se tagata.", "accept any man's person, neither let me give flattering titles unto man."]]},
  {num:22,words:[["Auā ou te le mafai ona faaneenee atu,", "For I know not to give flattering titles;"], ["ne'i avea faafuasei a'u e Le na faia a'u.", "in so doing my maker would soon take me away."]]},
  {num:23,words:[["Afai", "if"], ["ua ia te ia", "unto to"], ["le Agelu,", "the angel"], ["o le Puluvaga,", "the puluvaga"], ["Le ua sili", "the most"], ["i le toaafe,", "in the toaafe"], ["e faaali atu i le tagata lana amiotonu.", "to reveal in the man his righteous"]]},
  {num:24,words:[["Ona alofa lea o ia ia te ia,", "and love he unto to"], ["ma fetalai ane,", "and said"], ["Laveai mai ia ia te ia,", "deliver from to unto to"], ["пe“ alu ifo", "пe go"], ["i le lua;", "in the two"], ["ua ou maua", "I received"], ["le togiola.", "the atonement"]]},
  {num:25,words:[["E toe ola lelei ai lona tino", "to again life good his body"], ["e sili", "to most"], ["i le tama itiiti,", "in the child small"], ["e toe foi o ia i ona po o lona taulealea.", "to again also he in then night his taulealea"]]},
  {num:26,words:[["E tatalo o ia i le Atua,", "to pray he in the God"], ["ona finagalo malie mai ai lea o ia", "and a chiefs will or desire fight from he"], ["ia te ia;", "unto him"], ["e iloa foi e ia", "to known also by him"], ["ona fofoga", "and face"], ["ma le olioli;", "and the rejoice"], ["na te faafoi mai foi i le tagata lana amiotonu.", "faafoi from also in the man his righteous"]]},
  {num:27,words:[["E faasagasaga o ia i tagata,", "by faasagasaga he in man"], ["ma fai atu,", "and make"], ["Ua ou agasala,", "I sin"], ["ua ou faia le amio faapiopio,", "I made the conduct faapiopio"], ["a", "but"], ["ua le taula mai ia te au.", "the taula from unto I"]]},
  {num:28,words:[["Na te laveaiina o ia,", "delivered he"], ["ina ia", "so that"], ["le oo", "the oo"], ["i le lua;", "in the two"], ["e iloa foi e ia", "to known also by him"], ["le malamalama.", "the light"]]},
  {num:29,words:[["Faauta,", "behold"], ["ua faia ia mea uma faalua", "made to thing all faalua"], ["ma faatolu", "and faatolu"], ["e le Atua i le tagata,", "by God in the man"], ["30", "30"], ["ina ia faafoisia o ia ai le lua,", "so that faafoisia he the two"], ["ina ia faamalamalamaina", "so that faamalamalamaina"], ["i le malamalama o tagata ola.", "in the light man life"], ["31 lopu", "31 lopu"], ["e,", "by"], ["liliu mai ia ou fofoga,", "turned from to I face"], ["ina faafofoga mai ia ia te au;", "let listen from to unto I"], ["alaala mai ia,", "alaala from to"], ["ou te tautala atu ai a'u.", "I to talk I"]]},
];
