var job_ch_33_Verses = [
  {num:1,words:[["O lenei,", "Wherefore,"], ["Iopu e,", "Job,"], ["faafogafoga mai ia i la'u tautalaga,", "I pray thee, hear my speeches,"], ["ma liliu mai ou fofoga i a'u upu uma.", "and hearken to all my words."]]},
  {num:2,words:[["Faauta,", "Behold,"], ["ua ou faamaga atu lo'u gutu,", "now I have opened my mouth,"], ["ua tautala lo'u laulaufaiva i lo'u gutu;", "my tongue hath spoken in my mouth."]]},
  {num:3,words:[["o le faamaoni o lo'u loto e fai atu ai a'u upu;", "My words shall be of the uprightness of my heart:"], ["e tautala atu o'u laugutu i le poto e sao ona lelei.", "and my lips shall utter knowledge clearly."]]},
  {num:4,words:[["Na faia a'u e le Agaga o le Atua;", "The Spirit of God hath made me,"], ["o le mānava foi a Le e ona le malosi uma lava ua ola ai a'u.", "and the breath of the Almighty hath given me life."]]},
  {num:5,words:[["Afai ua e mafaia,", "If thou canst answer me,"], ["ina tali mai ia ia te au, ina sauni mai ia ia te au;", "set thy words in order before me,"], ["ina tulai mai ia.", "stand up."]]},
  {num:6,words:[["Faauta,", "Behold,"], ["o a'u nei o le sui o le Atua, e pei ona e fetalai mai ai. O a'u foi,", "I am according to thy wish in God's stead:"], ["ua faia a'u i le eleele.", "I also am formed out of the clay."]]},
  {num:7,words:[["Faauta mai,", "Behold,"], ["e le faamatautia oe i so'u matautia;", "my terror shall not make thee afraid,"], ["e le mamafa foi la'u avega i luga ia te oe.", "neither shall my hand be heavy upon thee."]]},
  {num:8,words:[["Ua e fetalai mai lava o loo ou faalogo atu,", "Surely thou hast spoken in mine hearing,"], ["ua ou lagona atu foi upu o lau fetalaiga,", "and I have heard the voice of thy words,"], ["ua faapea mai ,", "saying,"]]},
  {num:9,words:[["Ua mamā a'u;", "I am clean without transgression,"], ["ua aunoa ma le solitulafono; ua sao a'u;", "I am innocent;"], ["e leai foi sa'u agasala.", "neither is there iniquity in me."]]},
  {num:10,words:[["Faauta,", "Behold,"], ["ua ia saili mea e toasa mai ai ia te au, o lona manatu ia te au,", "he findeth occasions against me,"], ["o a'u le ita ia te ia.", "he counteth me for his enemy,"]]},
  {num:11,words:[["Ua ia tuu o'u vae i laau faamau,", "He putteth my feet in the stocks,"], ["ua ia lamalama i o'u ala uma.", "he marketh all my paths."]]},
  {num:12,words:[["Faauta,", "Behold,"], ["ua e le amiotonu i lenei mea;", "in this thou art not just:"], ["ou te tali atu ia te oe,", "I will answer thee,"], ["auā ua sili le Atua i tagata.", "that God is greater than man."]]},
  {num:13,words:[["Se a le mea ua e finau atu ai ia te ia? Auā ua ia le faamatala mai se tasi o ana mea.", "Why dost thou strive against him? for he giveth not account of any of his matters."]]},
  {num:14,words:[["Auā ua fetalai mai le Atua faatasi ma faalua,", "For God speaketh once, yea twice,"], ["a ua le manatu i ai tagata .", "yet man perceiveth it not."]]},
  {num:15,words:[["O le miti,", "In a dream,"], ["o le mea e vaaia i le po,", "in a vision of the night,"], ["ina o moe gagase tagata,", "when deep sleep falleth upon men,"], ["ina o momoe i latou i luga o moega;", "in slumberings upon the bed;"]]},
  {num:16,words:[["ona faafaalogo ai lea e ia o taliga o tagata,", "Then he openeth the ears of men,"], ["ma faamauina atu ai le mea ua a'oa'oina ai i latou e ia.", "and sealeth their instruction,"]]},
  {num:17,words:[["Ina ia liliueseina le tagata ai lana mea e fai;", "That he may withdraw man from his purpose,"], ["ia faalilo foi i le tagata le faamaualuga.", "and hide pride from man."]]},
  {num:18,words:[["Ua ia taofi ia te ia ia le oo i le lua,", "He keepeth back his soul from the pit,"], ["atoa ma lona ola ia le faaumatia i le tao.", "and his life from perishing by the sword."]]},
  {num:19,words:[["Ua aoaiina o ia i luga o lona moega i le tiga,", "He is chastened also with pain upon his bed,"], ["ma le tiga tele o ona ivi e le aunoa.", "and the multitude of his bones with strong pain:"]]},
  {num:20,words:[["Ua 'ino'ino foi o ia i mea e 'ai,", "So that his life abhorreth bread,"], ["ua le manao foi i mea suamalie.", "and his soul dainty meat."]]},
  {num:21,words:[["Ua faaumatia lona aano,", "His flesh is consumed away,"], ["ua le iloa;", "that it cannot be seen;"], ["ua aliali mai ona ivi sa le iloa.", "and his bones that were not seen stick out."]]},
  {num:22,words:[["Ua faalatalata foi o ia i le tuugamau,", "Yea, his soul draweth near unto the grave,"], ["ma lona ola i e fasioti.", "and his life to the destroyers."]]},
  {num:23,words:[["Afai ua ia te ia le Agelu,", "If there be a messenger with him,"], ["o le Puluvaga,", "an interpreter,"], ["Le ua sili i le toaafe,", "one among a thousand,"], ["e faaali atu i le tagata lana amiotonu.", "to shew unto man his uprightness:"]]},
  {num:24,words:[["Ona alofa lea o ia ia te ia,", "Then he is gracious unto him,"], ["ma fetalai ane,", "and saith,"], ["Laveai mai ia ia te ia, ne'i alu ifo i le lua;", "Deliver him from going down to the pit:"], ["ua ou maua le togiola.", "I have found a ransom."]]},
  {num:25,words:[["E toe ola lelei ai lona tino e sili i le tama itiiti,", "His flesh shall be fresher than a child's:"], ["e toe foi o ia i ona po o lona taulealea.", "he shall return to the days of his youth:"]]},
  {num:26,words:[["E tatalo o ia i le Atua,", "He shall pray unto God,"], ["ona finagalo mălie mai ai lea o ia ia te ia;", "and he will be favourable unto him:"], ["e iloa foi e ia ona fofoga ma le olioli;", "and he shall see his face with joy:"], ["na te faafoi mai foi i le tagata lana amiotonu.", "for he will render unto man his righteousness."]]},
  {num:27,words:[["E faasagasaga o ia i tagata,", "He looketh upon men,"], ["ma fai atu,", "and if any say,"], ["Ua ou agasala,", "I have sinned,"], ["ua ou faia le amio faapiopio,", "and perverted that which was right,"], ["a ua le tauia mai ia te au.", "and it profited me not;"]]},
  {num:28,words:[["Na te laveaiina o ia, ina ia le oo i le lua;", "He will deliver his soul from going into the pit,"], ["e iloa foi e ia le malamalama.", "and his life shall see the light."]]},
  {num:29,words:[["Faauta,", "Lo,"], ["ua faia ia mea uma faalua ma faatolu e le Atua i le tagata,", "all these things worketh God oftentimes with man,"]]},
  {num:30,words:[["ina ia faafoisia o ia ai le lua,", "To bring back his soul from the pit,"], ["ina ia faamalamalamaina i le malamalama o tagata ola.", "to be enlightened with the light of the living."]]},
  {num:31,words:[["Iopu e,", "Mark well,"], ["liliu mai ia ou fofoga ,", "O Job,"], ["ina faafofoga mai ia ia te au;", "hearken unto me:"], ["alaala mai ia,", "hold thy peace,"], ["ou te tautala atu ai a'u.", "and I will speak."]]},
  {num:32,words:[["Afai e ai sau upu,", "If thou hast any thing to say,"], ["tali mai ia ia te au;", "answer me:"], ["ia e tautala mai;", "speak,"], ["auā ou te loto ina ia ta'uamiotonuina oe.", "for I desire to justify thee."]]},
  {num:33,words:[["Afai e leai,", "If not,"], ["ia e faafofoga mai ia te au;", "hearken unto me:"], ["alaala mai ia,", "hold thy peace,"], ["ou te a'oa'o atu ai ia te oe i le poto.", "and I shall teach thee wisdom."]]},
];
renderVerseSet(job_ch_33_Verses, 'job-ch33-verses');

var job_ch_34_Verses = [
  {num:1,words:[["Ua tali mai pea Eliu, ua faapea mai,", "Furthermore Elihu answered and said,"]]},
  {num:2,words:[["Faafogafoga mai i a'u upu o outou o e popoto;", "Hear my words,"], ["o outou o e silafia mea ,", "O ye wise men; and give ear unto me,"], ["ina liliu mai ia o outou fofoga ia te au.", "ye that have knowledge."]]},
  {num:3,words:[["Auā e faamasino e le taliga i upu,", "For the ear trieth words,"], ["e pei ona tofotofo e le gutu i mea e 'ai.", "as the mouth tasteth meat."]]},
  {num:4,words:[["Ina tatou filifili ia le tonu mo i tatou; ia tatou iloa e i tatou lava,", "Let us choose to us judgment:"], ["po o le a le lelei.", "let us know among ourselves what is good."]]},
  {num:5,words:[["Auā ua faapea mai Iopu,", "For Job hath said,"], ["Ua ou amiotonu;", "I am righteous:"], ["ua aveesea foi e le Atua lo'u faamasinoga.", "and God hath taken away my judgment."]]},
  {num:6,words:[["Ua avea a'u ma pepelo i lo'u faamasinoga, ua manua leaga lava a'u, a e leai so'u solitulafono.", "Should I lie against my right? my wound is incurable without transgression."]]},
  {num:7,words:[["O ai ea se tagata e tusa ma Iopu,", "What man is like Job,"], ["o le ua inu i le faifaiga e pei ona inu i le vai?", "who drinketh up scorning like water?"]]},
  {num:8,words:[["O le ua fefaauoai foi ma i latou ua fai amioletonu,", "Which goeth in company with the workers of iniquity,"], ["ma feoai ma tagata amio leaga.", "and walketh with wicked men."]]},
  {num:9,words:[["Auā ua ia fai mai,", "For he hath said,"], ["e le aoga i le tagata ona ia fiafia o ia i le Atua.", "It profiteth a man nothing that he should delight himself with God."]]},
  {num:10,words:[["O lenei,", "Therefore hearken unto me,"], ["tagata atamamai e,", "ye men of understanding:"], ["faafogafoga mai ia ia te au;", "far be it from God, that he should do wickedness;"], ["e mamao ma le Atua ona ia amio leaga,", "and from the Almighty,"], ["ma Le e ona le malosi uma lava ona ia amioletonu.", "that he should commit iniquity."]]},
  {num:11,words:[["Auā e taui atu e ia i le tagata lana lava galuega;", "For the work of a man shall he render unto him,"], ["na te faatatau foi i tagata taitoatasi e tusa ma lona ala.", "and cause every man to find according to his ways."]]},
  {num:12,words:[["E moni lava e le amioleaga le Atua,", "Yea, surely God will not do wickedly,"], ["e le faapiopioina foi e Le e ona le malosi uma lava le faamasinoga.", "neither will the Almighty pervert judgment."]]},
  {num:13,words:[["O ai ea ua tofia o ia e pule i le lalolagi? Po o ai foi ua saunia le atu laulau uma lava?", "Who hath given him a charge over the earth? or who hath disposed the whole world?"]]},
  {num:14,words:[["Afai e faapea ona finagalo o ia ia te ia,", "If he set his heart upon man,"], ["na te faafoisia ia te ia lona agaga ma lana mānava;", "if he gather unto himself his spirit and his breath;"]]},
  {num:15,words:[["ona oti ai lea o tagata uma lava faatasi,", "All flesh shall perish together,"], ["ma toe foi atu tagata i le eleele.", "and man shall turn again unto dust."]]},
  {num:16,words:[["Afai ua ia te oe le mafaufau,", "If now thou hast understanding,"], ["ina e faafofoga mai ia i lenei mea;", "hear this:"], ["liliu mai ia ou fofoga i a'u lava upu.", "hearken to the voice of my words."]]},
  {num:17,words:[["E pule ea lē ua 'ino'ino i le tonu? E te faasalaina ea foi lē ua matuā amiotonu lava?", "Shall even he that hateth right govern? and wilt thou condemn him that is most just?"]]},
  {num:18,words:[["E fai atu ea i le tupu,", "Is it fit to say to a king,"], ["Ua e ulavale? Ma alii,", "Thou art wicked? and to princes,"], ["Ua amio leaga outou?", "Ye are ungodly?"]]},
  {num:19,words:[["Pe fai atu ea i le na te le faailogaina alii sili,", "How much less to him that accepteth not the persons of princes,"], ["ma ua le sili lona silasila i lē mauoa i lona silasila i lē mativa? Auā o le galuega a ona aao i latou uma.", "nor regardeth the rich more than the poor? for they all are the work of his hands."]]},
  {num:20,words:[["E oti faafuasei i latou,", "In a moment shall they die,"], ["o le tulua o po ma ao e faagateteina ai le nuu,", "and the people shall be troubled at midnight,"], ["ma mavae atu ai; e avea foi ē malolosi,", "and pass away:"], ["a e le se lima e avea ai .", "and the mighty shall be taken away without hand."]]},
  {num:21,words:[["Auā ua silasila o ia i ala o tagata taitoatasi,", "For his eyes are upon the ways of man,"], ["ua ia silafia foi ona savaliga uma.", "and he seeth all his goings."]]},
  {num:22,words:[["E leai se pouliuli,", "There is no darkness, nor shadow of death,"], ["e leai foi se ata o le oti e lalafi ai o e fai amio leaga.", "where the workers of iniquity may hide themselves."]]},
  {num:23,words:[["Auā e le tatau i le tagata ona manao pea ia alu atu i le Atua e fai se faamasinoga.", "For he will not lay upon man more than right; that he should enter into judgment with God."]]},
  {num:24,words:[["E tu'imomomoina e ia o e malolosi e le mafaitaulia,", "He shall break in pieces mighty men without number,"], ["ma faatuina e ia nisi e sui a'i i latou.", "and set others in their stead."]]},
  {num:25,words:[["Ua ia silafia a latou galuega,", "Therefore he knoweth their works,"], ["o le mea lea ua ia lafoia ai i latou i le po,", "and he overturneth them in the night,"], ["ona tu'imomomoina ai lea o i latou.", "so that they are destroyed."]]},
  {num:26,words:[["Ua amio leaga i latou, o le mea lea ua ia sasa ai ia te i latou i le mea e vaavaai ai tagata;", "He striketh them as wicked men in the open sight of others;"]]},
  {num:27,words:[["ina ua latou o ese ua le mulimuli ia te ia,", "Because they turned back from him,"], ["ma ua le manatu i latou i se tasi o ona ala.", "and would not consider any of his ways:"]]},
  {num:28,words:[["Ua oo atu ai ia te ia le alaga o le ua mativa,", "So that they cause the cry of the poor to come unto him,"], ["ua ia faafofoga foi i le alaga o e ua puapuagatia.", "and he heareth the cry of the afflicted."]]},
  {num:29,words:[["A tuuina mai e ia le filemu,", "When he giveth quietness,"], ["po o ai ea na te faaatuatuvaleina? A 'alo foi ona fofoga,", "who then can make trouble? and when he hideth his face,"], ["po o ai se na te iloa o ia? Pe faia i se nuu,", "who then can behold him? whether it be done against a nation,"], ["po o se tagata e toatasi;", "or against a man only:"]]},
  {num:30,words:[["ina ne'i fai ma tupu le tagata amio faalematau,", "That the hypocrite reign not,"], ["ne'i maileia ai le nuu.", "lest the people be ensnared."]]},
  {num:31,words:[["E tatau lava ina fai atu i le Atua,", "Surely it is meet to be said unto God,"], ["Ua aoaiina a'u,", "I have borne chastisement,"], ["ou te le toe agaleaga.", "I will not offend any more:"]]},
  {num:32,words:[["O se mea ua ou le iloa ia e a'oa'o mai ai e oe ia te au;", "That which I see not teach thou me:"], ["afai ua ou faia se amio leaga,", "if I have done iniquity,"], ["ou te le toe faia.", "I will do no more."]]},
  {num:33,words:[["Pe faatatau ea i lou manatu ona taui atu ai e ia i amio ,", "Should it be according to thy mind? he will recompense it,"], ["auā ua e teteeina atu,", "whether thou refuse,"], ["po ua e loto i ai lava oe,", "or whether thou choose;"], ["a e le o a'u? O lenei,", "and not I:"], ["ta'u mai ia se mea ua e iloa.", "therefore speak what thou knowest."]]},
  {num:34,words:[["E fai mai ia te au tagata atamamai,", "Let men of understanding tell me,"], ["ma le tagata poto o lē faalogo mai ia te au,", "and let a wise man hearken unto me."]]},
  {num:35,words:[["Ua tautala Iopu ma le le iloa,", "Job hath spoken without knowledge,"], ["ua fai ana upu ma le le mafaufau.", "and his words were without wisdom."]]},
  {num:36,words:[["O lo'u loto lenei , ia matuā suesueina lava Iopu, ona o ana tali e pei o tagata amio leaga.", "My desire is that Job may be tried unto the end because of his answers for wicked men."]]},
  {num:37,words:[["Auā ua ia faaopoopoina le fouvale i lana agasala,", "For he addeth rebellion unto his sin,"], ["ua ia pati ona lima ia te i tatou,", "he clappeth his hands among us,"], ["ua ia faateleina foi ana upu i le Atua.", "and multiplieth his words against God."]]},
];
renderVerseSet(job_ch_34_Verses, 'job-ch34-verses');

var job_ch_35_Verses = [
  {num:1,words:[["Ua tali mai pea Eliu, ua faapea mai,", "Elihu spake moreover,"], ["E te manatu ea ua tonu lenei mea, ina ua e fai mai,", "and said,"]]},
  {num:2,words:[["E sili la'u amiotonu i lo le Atua?", "Thinkest thou this to be right, that thou saidst, My righteousness is more than God's?"]]},
  {num:3,words:[["Auā ua e fai mai,", "For thou saidst, What advantage will it be unto thee? and,"], ["Se a le aoga ia te oe? Se a foi le aoga ia te au pe a leai sa'u agasala?", "What profit shall I have, if I be cleansed from my sin?"]]},
  {num:4,words:[["Ou te tali atu ia te oe,", "I will answer thee,"], ["atoa ma au uo faatasi ma oe.", "and thy companions with thee."]]},
  {num:5,words:[["Ia e tepa ae i le lagi,", "Look unto the heavens,"], ["ma ia e vaai;", "and see;"], ["ia e matamata foi i ao ua maualuga lava i ou luga.", "and behold the clouds which are higher than thou."]]},
  {num:6,words:[["Afai ua e agasala,", "If thou sinnest,"], ["se a se mea ua e fai ia te ia? Afai foi ua faateleina ou solitulafono,", "what doest thou against him? or if thy transgressions be multiplied,"], ["se a se mea ua e fai ia te ia?", "what doest thou unto him?"]]},
  {num:7,words:[["Afai ua e amiotonu,", "If thou be righteous,"], ["se a se mea ua e avatua ia te ia? Se a foi se mea ua ia maua mai lou lima?", "what givest thou him? or what receiveth he of thine hand?"]]},
  {num:8,words:[["Ai e leaga le tagata e pei o oe i lau amio leaga;", "Thy wickedness may hurt a man as thou art;"], ["ai e aoga foi i le tagata o lau amiotonu.", "and thy righteousness may profit the son of man."]]},
  {num:9,words:[["O le tele o sauaga ua alalaga ai tagata;", "By reason of the multitude of oppressions they make the oppressed to cry:"], ["ua uio i latou ona o le lima o e malolosi.", "they cry out by reason of the arm of the mighty."]]},
  {num:10,words:[["A e leai se na te fai mai,", "But none saith, Where is God my maker,"], ["Po o ifea o i ai le Atua o le na faia a'u? O le ua au mai pese i le po.", "who giveth songs in the night;"]]},
  {num:11,words:[["O le a'oa'o mai ia te i tatou e sili i manu e tataa,", "Who teacheth us more than the beasts of the earth,"], ["ma na faapopotoina i tatou e sili i manu felelei.", "and maketh us wiser than the fowls of heaven?"]]},
  {num:12,words:[["Ua latou alalaga ai,", "There they cry,"], ["a e le tali atu o ia,", "but none giveth answer,"], ["ona o le faamaualuga o e amio leaga.", "because of the pride of evil men."]]},
  {num:13,words:[["E le faafofogaina lava e le Atua le tatalo faatauvaa;", "Surely God will not hear vanity,"], ["e le silasila foi i ai Le e ona le malosi uma lava.", "neither will the Almighty regard it."]]},
  {num:14,words:[["E ui lava ina e fai mai e te le iloa atu o ia,", "Although thou sayest thou shalt not see him,"], ["a e ia te ia le faamasinoga;", "yet judgment is before him;"], ["o lea ia e faatalitali ai ia te ia.", "therefore trust thou in him."]]},
  {num:15,words:[["A o lenei,", "But now,"], ["ina ua le asiasi mai lona toasa,", "because it is not so, he hath visited in his anger;"], ["ma ua le silasila o ia i le agasala e matuā tele lava;", "yet he knoweth it not in great extremity:"]]},
  {num:16,words:[["o le mea lea ua tautala fua mai ai Iopu,", "Therefore doth Job open his mouth in vain;"], ["ua faateleina upu i lona le iloa.", "he multiplieth words without knowledge."]]},
  {num:17,words:[["A", "but"], ["ua e 763", "by 763"]]},
];
renderVerseSet(job_ch_35_Verses, 'job-ch35-verses');

var job_ch_36_Verses = [
  {num:1,words:[["Ua toe fai mai foi Eliu,", "Elihu also proceeded,"], ["Ia e onosai mai pea teisi ia te au,", "and said,"]]},
  {num:2,words:[["ou te faaali atu ai ia te oe,", "Suffer me a little,"], ["auā ua totoe pea upu mo le Atua.", "and I will shew thee that I have yet to speak on God's behalf."]]},
  {num:3,words:[["Ou te aumaia lo'u poto ai le mea mamao,", "I will fetch my knowledge from afar,"], ["ou te ta'uamiotonuina foi le na faia a'u.", "and will ascribe righteousness to my Maker."]]},
  {num:4,words:[["Auā e moni lava, e le pepelo a'u upu;", "For truly my words shall not be false:"], ["ua ia te oe le tasi ua faamaoni lona poto.", "he that is perfect in knowledge is with thee."]]},
  {num:5,words:[["Faauta,", "Behold,"], ["ua silisili ese le Atua,", "God is mighty,"], ["a e le 'ino'ino o ia i se tasi ,", "and despiseth not any:"], ["ua silisili ese le malosi o lona finagalo.", "he is mighty in strength and wisdom."]]},
  {num:6,words:[["Na te le faaola i le ua amio leaga;", "He preserveth not the life of the wicked:"], ["a e faia e ia le faamasinoga mo e ua puapuagatia.", "but giveth right to the poor."]]},
  {num:7,words:[["Na te le 'alo ona fofoga i e ua amiotonu;", "He withdraweth not his eyes from the righteous:"], ["a e silasila i tupu i nofoālii;", "but with kings are they on the throne;"], ["na te faatumauina foi i latou e faavavau,", "yea, he doth establish them for ever,"], ["ua faasilisiliina foi i latou.", "and they are exalted."]]},
  {num:8,words:[["Afai foi ua noanoatia i latou i maea uamea,", "And if they be bound in fetters,"], ["ma lavelavea i latou i maea o le puapuaga,", "and be holden in cords of affliction;"]]},
  {num:9,words:[["ona faaali ai lea e ia ia te i latou o mea ua latou faia, ma o latou solitulafono,", "Then he sheweth them their work,"], ["ina ua tele lava.", "and their transgressions that they have exceeded."]]},
  {num:10,words:[["Ua ia faafaalogoina foi o latou taliga i aoaiga; ma fetalai atu,", "He openeth also their ear to discipline,"], ["ia latou foi mai nai le amio leaga.", "and commandeth that they return from iniquity."]]},
  {num:11,words:[["Afai latou te faalogo ma auauna ia te ia ,", "If they obey and serve him,"], ["ona faauma ai lea o latou aso o manuia,", "they shall spend their days in prosperity,"], ["ma o latou tausaga o fiafia.", "and their years in pleasures."]]},
  {num:12,words:[["A e afai latou te le faalogo,", "But if they obey not,"], ["ona faaumatia ai lea o i latou i le tao,", "they shall perish by the sword,"], ["e oti foi i latou e le popoto.", "and they shall die without knowledge."]]},
  {num:13,words:[["A o e ua loto faalematau, ua latou faaputuina le toasa;", "But the hypocrites in heart heap up wrath:"], ["latou te le alalaga ia te ia pe a noanoatia i latou e ia.", "they cry not when he bindeth them."]]},
  {num:14,words:[["E oti i latou a o taulelea;", "They die in youth,"], ["e iu foi o latou ola faatasi ma e ua faasotoma.", "and their life is among the unclean."]]},
  {num:15,words:[["Na te laveaiina le ua puapuagatia nai ona puapuaga;", "He delivereth the poor in his affliction,"], ["na te faafaalogoina foi o latou taliga a o sauaina i latou .", "and openeth their ears in oppression."]]},
  {num:16,words:[["E faapea foi ona ia ta'ita'ieseina o oe ai le mea va apiapi i le mea lautele e le o i ai se va apiapi;", "Even so would he have removed thee out of the strait into a broad place, where there is no straitness;"], ["o le mea foi e laulauina i lau laoai e soona lololo lea .", "and that which should be set on thy table should be full of fatness."]]},
  {num:17,words:[["A ua e faaatoatoaina le faamasinoga a e amio leaga;", "But thou hast fulfilled the judgment of the wicked:"], ["e mulimuli le faasala i le faamasinoga.", "judgment and justice take hold on thee."]]},
  {num:18,words:[["Auā ua i ai le toasa,", "Because there is wrath,"], ["ia oe, ne'i aveesea oe e ia i le sasa;", "beware lest he take thee away with his stroke:"], ["ona le faasaoina ai lea oe i se togiola tele.", "then a great ransom cannot deliver thee."]]},
  {num:19,words:[["Na te finagalo ea i au oloa? Na te le finagalo lava i auro,", "Will he esteem thy riches? no, not gold,"], ["po o faulaigāoa uma lava.", "nor all the forces of strength."]]},
  {num:20,words:[["Aua e te manao i le po,", "Desire not the night,"], ["e avae ai nuu ai le mea o loo latou i ai.", "when people are cut off in their place."]]},
  {num:21,words:[["Ia oe,", "Take heed,"], ["ne'i e loto atu i le amio leaga;", "regard not iniquity:"], ["auā ua sili lou loto i lea mea i lou loto i le puapuaga.", "for this hast thou chosen rather than affliction."]]},
  {num:22,words:[["Faauta,", "Behold,"], ["ua silisili ese le Atua i lona malosi;", "God exalteth by his power:"], ["o ai na te a'oa'o e faapei o ia?", "who teacheth like him?"]]},
  {num:23,words:[["Po o ai ua togia ia te ia lona ala? O ai foi na te fai atu,", "Who hath enjoined him his way? or who can say,"], ["Ua e faia amioletonu?", "Thou hast wrought iniquity?"]]},
  {num:24,words:[["Ia e manatua ona vivii i ana galuega o loo vaai i ai tagata;", "Remember that thou magnify his work, which men behold."]]},
  {num:25,words:[["ua matamata i ai tagata uma lava,", "Every man may see it;"], ["ua iloa mamao atu e tagata.", "man may behold it afar off."]]},
  {num:26,words:[["Faauta,", "Behold,"], ["ua silisili ese le Atua,", "God is great,"], ["tatou te le iloa foi o ia;", "and we know him not,"], ["e le masino foi le faitau o ona tausaga.", "neither can the number of his years be searched out."]]},
  {num:27,words:[["Auā e aveina ae e ia faaafuafu o vai; e totō ifo le ua e sui a'i lona ausa,", "For he maketh small the drops of water:"], ["e mauluulu mai ai i ao;", "they pour down rain according to the vapour thereof:"]]},
  {num:28,words:[["e totō tele mai ai i luga o tagata.", "Which the clouds do drop and distil upon man abundantly."]]},
  {num:29,words:[["E iloa foi ea se tasi ona fofola o le ao,", "Also can any understand the spreadings of the clouds,"], ["ma le taalili mai o lona fale apitaga?", "or the noise of his tabernacle?"]]},
  {num:30,words:[["Faauta,", "Behold,"], ["ua ia fofola i ona luga lona malamalama;", "he spreadeth his light upon it,"], ["ua ia ufiufi foi le iliti tai.", "and covereth the bottom of the sea."]]},
  {num:31,words:[["Auā o ia mea ua ia faasalaina ai nuu;", "For by them judgeth he the people;"], ["ua ia foai mai ai foi mea e 'ai e tele.", "he giveth meat in abundance."]]},
  {num:32,words:[["Ua ia ufitia ona aao i le uila,", "With clouds he covereth the light;"], ["na te poloai i ai i se mea e paū i ai.", "and commandeth it not to shine by the cloud that cometh betwixt."]]},
  {num:33,words:[["Ua ia faailoa mai lona faititili i luga o tagata ,", "The noise thereof sheweth concerning it,"], ["i luga o lafu atoa ma mea e tutupu.", "the cattle also concerning the vapour."]]},
];
renderVerseSet(job_ch_36_Verses, 'job-ch36-verses');

var job_ch_37_Verses = [
  {num:1,words:[["O le mea foi lenei ua gatete ai lo'u loto,", "At this also my heart trembleth,"], ["ua sapotuvale ai foi i le mea o i ai.", "and is moved out of his place."]]},
  {num:2,words:[["Ina matuā faalogologo atu ia i le taalili o lona siufofoga,", "Hear attentively the noise of his voice,"], ["ma le gogolo ua oo atu nai lona fofoga.", "and the sound that goeth out of his mouth."]]},
  {num:3,words:[["Ua ia ta'ita'iina ai i lalo o le lagi atoa uma,", "He directeth it under the whole heaven,"], ["ma lona uila foi e oo i tuluiga o le lalolagi.", "and his lightning unto the ends of the earth."]]},
  {num:4,words:[["E mulimuli ane ai,", "After it a voice roareth:"], ["ona taalili mai ai lea o le leo; ua ia faapā mai le faititili i lona siufofoga silisili;", "he thundereth with the voice of his excellency;"], ["ua ia le taofi foi i ai pe a lagona lona siufofoga.", "and he will not stay them when his voice is heard."]]},
  {num:5,words:[["Ua faapā mai e le Atua le faititili silisili ese i lona siufofoga;", "God thundereth marvellously with his voice; great things doeth he,"], ["e faia e ia mea tetele e le mailoa e i tatou.", "which we cannot comprehend."]]},
  {num:6,words:[["Auā e fetalai ane o ia i le kiona,", "For he saith to the snow,"], ["Ina to ia oe i le laueleele;", "Be thou on the earth;"], ["ua faapea foi i le timuga,", "likewise to the small rain,"], ["ma ona uaga e matuā tetele.", "and to the great rain of his strength."]]},
  {num:7,words:[["Na te taofi lima o tagata uma,", "He sealeth up the hand of every man;"], ["ina ia iloa e tagata uma lana galuega.", "that all men may know his work."]]},
  {num:8,words:[["Ona o ai lea o manu feai i mea latou te fale ai,", "Then the beasts go into dens,"], ["ma taooto i o latou ana.", "and remain in their places."]]},
  {num:9,words:[["E sau le asiosio mai le itu i toga,", "Out of the south cometh the whirlwind:"], ["ma le maalili mai le itu i matu.", "and cold out of the north."]]},
  {num:10,words:[["O le mānava mai o le Atua e au mai ai le vaito'a;", "By the breath of God frost is given:"], ["e faaitiitiina ai foi le lautele o vai.", "and the breadth of the waters is straitened."]]},
  {num:11,words:[["O lona pupula foi e to ifo ai le ao uliuli;", "Also by watering he wearieth the thick cloud:"], ["o lona malamalama e taapeape ai ao.", "he scattereth his bright cloud:"]]},
  {num:12,words:[["E feaveaiina ai e ia faataamilomilo i lana pule,", "And it is turned round about by his counsels:"], ["ina ia fai ai mea uma ua ia finagalo i ai i luga o le atu laulau uma lava.", "that they may do whatsoever he commandeth them upon the face of the world in the earth."]]},
  {num:13,words:[["Na te faaooina mai ai,", "He causeth it to come,"], ["po o le aoaiga,", "whether for correction,"], ["po o lona laueleele,", "or for his land,"], ["po o le alofa.", "or for mercy."]]},
  {num:14,words:[["Iopu e,", "Hearken unto this,"], ["faafofoga mai ia i lenei mea;", "O Job:"], ["ina tulai mai ia,", "stand still,"], ["ma mafaufau i vavega o le Atua.", "and consider the wondrous works of God."]]},
  {num:15,words:[["Ua e iloa ea pe faapefea ona saunia o ia mea e le Atua,", "Dost thou know when God disposed them,"], ["ma faaemoina mai e ia le uila o lona ao?", "and caused the light of his cloud to shine?"]]},
  {num:16,words:[["Ua e iloa ea le fuatia o le mamafa o ao uliuli,", "Dost thou know the balancings of the clouds,"], ["o vavega o Le e ona le poto atoatoa?", "the wondrous works of him which is perfect in knowledge?"]]},
  {num:17,words:[["Pe faapefea foi ona vevela ai ou ofu ina ua faamaninoaina e ia le lalolagi i le matagi mai le itu i toga?", "How thy garments are warm, when he quieteth the earth by the south wind?"]]},
  {num:18,words:[["Na oulua fofola faatasi ea ma ia le lagi,", "Hast thou with him spread out the sky, which is strong,"], ["ua mălōlō e pei o se faaata 'apa memea?", "and as a molten looking glass?"]]},
  {num:19,words:[["Ina e faailoa mai ia pe se a se upu matou te fai atu ai ia te ia;", "Teach us what we shall say unto him;"], ["matou te le mafai ona sauni atu ai ona o le pouliuli.", "for we cannot order our speech by reason of darkness."]]},
  {num:20,words:[["E ta'uina atu ea ia te ia ua ou tautala? Afai e tautala atu se tasi,", "Shall it be told him that I speak? if a man speak,"], ["e fano ai lava o ia.", "surely he shall be swallowed up."]]},
  {num:21,words:[["O lenei,", "And now men see not the bright light which is in the clouds:"], ["e le vaaia le malamalama pupula o loo i ao o le lagi; a e agi mai le matagi,", "but the wind passeth,"], ["ona matafitafi ai lea.", "and cleanseth them."]]},
  {num:22,words:[["E sau le pupula faaauro mai le itu i matu;", "Fair weather cometh out of the north:"], ["o loo i le Atua le mamalu matautia.", "with God is terrible majesty."]]},
  {num:23,words:[["A o Le e ona le malosi uma lava,", "Touching the Almighty,"], ["tatou te le mafai ona iloa o ia;", "we cannot find him out:"], ["e silisili ese lona malosi ma lona faamasinoga,", "he is excellent in power, and in judgment,"], ["e sili foi lana amiotonu,", "and in plenty of justice:"], ["na te le agaleaga.", "he will not afflict."]]},
  {num:24,words:[["O le mea lea e matatau ai tagata ia te ia;", "Men do therefore fear him:"], ["na te le silasila i se tasi o e o popoto o latou loto.", "he respecteth not any that are wise of heart."]]},
];
renderVerseSet(job_ch_37_Verses, 'job-ch37-verses');

var job_ch_38_Verses = [
  {num:1,words:[["Ona tali mai ai lea o Ieova ia Iopu mai le afā,", "Then the LORD answered Job out of the whirlwind,"], ["ua faapea mai,", "and said,"]]},
  {num:2,words:[["O ai ea lenei ua na faapouliuligia la'u pule i upu e le o i ai le poto?", "Who is this that darkeneth counsel by words without knowledge?"]]},
  {num:3,words:[["Ina fusi ia lou sulugatiti e pei o le tagata malosi;", "Gird up now thy loins like a man;"], ["ou te fesili atu foi ia te oe,", "for I will demand of thee,"], ["ina e faailoa mai ia ia te au.", "and answer thou me."]]},
  {num:4,words:[["O ifea sa e i ai ina o ou faavaeina le lalolagi? Ina faaali mai ia pe afai ua e iloa mafaufau.", "Where wast thou when I laid the foundations of the earth? declare, if thou hast understanding."]]},
  {num:5,words:[["O ai ea na ia fuafuaina ai,", "Who hath laid the measures thereof,"], ["pe afai ua e iloa? O ai foi ua na faataoto i ai le fua?", "if thou knowest? or who hath stretched the line upon it?"]]},
  {num:6,words:[["Ua tuuina ea ona faavae i luga o le a? O ai ea foi na na tuuina ifo lona maa tulimanu;", "Whereupon are the foundations thereof fastened? or who laid the corner stone thereof;"]]},
  {num:7,words:[["ina o pepese faatasi fetu o le taeao,", "When the morning stars sang together,"], ["ma alalaga fiafia atalii uma o le Atua.", "and all the sons of God shouted for joy?"]]},
  {num:8,words:[["O ai foi na ia pupuni le sami i puipui ina ua oo mai e peiseai na sau mai le manava?", "Or who shut up the sea with doors, when it brake forth, as if it had issued out of the womb?"]]},
  {num:9,words:[["Ina ua ou faia le ao mona ofu,", "When I made the cloud the garment thereof,"], ["ma le pogisa ma mea e aui ai;", "and thick darkness a swaddlingband for it,"]]},
  {num:10,words:[["ina ua ou tuu atu i ai foi ona tuaoi,", "And brake up for it my decreed place,"], ["ma avane i ai faamaufaalava ma puipui;", "and set bars and doors,"]]},
  {num:11,words:[["ma ou fai atu i ai ,", "And said,"], ["E te oo mai iinei,", "Hitherto shalt thou come,"], ["ae e te le sopoia;", "but no further:"], ["o iinei foi e pau mai ai ou galu faamaualuluga.", "and here shall thy proud waves be stayed?"]]},
  {num:12,words:[["Talu le amataga o ou aso ua e pule ea i le taeao? Ua e faasino atu ea i le tafa o ata le mea e aliali mai ai,", "Hast thou commanded the morning since thy days; and caused the dayspring to know his place;"]]},
  {num:13,words:[["ina ia tago atu i tuluiga o le lalolagi,", "That it might take hold of the ends of the earth,"], ["ma ia lulueseina ai o e amio leaga?", "that the wicked might be shaken out of it?"]]},
  {num:14,words:[["E liua o ia e pei o le omea i le faamaufaailoga,", "It is turned as clay to the seal;"], ["ona latou tutū mai ai lea e pei se ofu.", "and they stand as a garment."]]},
  {num:15,words:[["E aveesea foi i e amio leaga lo latou malamalama,", "And from the wicked their light is withholden,"], ["ua gauia foi le lima o le ua faamaualuga.", "and the high arm shall be broken."]]},
  {num:16,words:[["Ua e oo atu ea i puna o le sami? Po ua e fealualuai ea i mea loloto o le moana?", "Hast thou entered into the springs of the sea? or hast thou walked in the search of the depth?"]]},
  {num:17,words:[["Ua faaalia ea ia te oe faitotoa o le oti? Po ua e iloa ea faitotoa o le ata o le oti?", "Have the gates of death been opened unto thee? or hast thou seen the doors of the shadow of death?"]]},
  {num:18,words:[["Ua e mafaufau ea i le lautele o le lalolagi? Ina faaali mai ia, pe afai ua e iloa ia mea uma.", "Hast thou perceived the breadth of the earth? declare if thou knowest it all."]]},
  {num:19,words:[["O ifea le ala i le mea e nofo ai le malamalama? O le pouliuli foi o ifea le mea e mau ai ia,", "Where is the way where light dwelleth? and as for darkness, where is the place thereof,"]]},
  {num:20,words:[["ina ia e momoli atu ai i lona tuaoi,", "That thou shouldest take it to the bound thereof,"], ["ina ia e iloa foi le ala i lona fale?", "and that thou shouldest know the paths to the house thereof?"]]},
  {num:21,words:[["Ua e iloa ea ia mea ina ua fanau mai oe i ia ona po,", "Knowest thou it,"], ["ina ua tele foi le faitau o ou aso?", "because thou wast then born? or because the number of thy days is great?"]]},
  {num:22,words:[["Ua e ulu atu ea i mea e teu ai le kiona? Ua e vaaia ea foi mea e teu ai le uato'a?", "Hast thou entered into the treasures of the snow? or hast thou seen the treasures of the hail,"]]},
  {num:23,words:[["O mea ia ua ou tuu ma ona po o le puapuaga,", "Which I have reserved against the time of trouble,"], ["ma le aso e tau ai le taua.", "against the day of battle and war?"]]},
  {num:24,words:[["O i fea le ala e vaevaeina atu ai le malamalama,", "By what way is the light parted,"], ["e faasalalauina ai le matagi mai sasae i luga o le lalolagi?", "which scattereth the east wind upon the earth?"]]},
  {num:25,words:[["O ai ua vaevaeina o alāvai mo uaga,", "Who hath divided a watercourse for the overflowing of waters,"], ["ma le ala mo le uila o le faititili?", "or a way for the lightning of thunder;"]]},
  {num:26,words:[["Ina ia to mai le ua i le laueleele,", "To cause it to rain on the earth,"], ["e le o iai se tagata;", "where no man is;"], ["ma le vao,", "on the wilderness,"], ["e le āina e tagata,", "wherein there is no man;"]]},
  {num:27,words:[["ina ia mălie ai le mea ua taaligoligoa ma le mea ua gaogao;", "To satisfy the desolate and waste ground;"], ["ina ia faatupuina ai foi le vaoiti.", "and to cause the bud of the tender herb to spring forth?"]]},
  {num:28,words:[["E ai ea se tamā o le ua? Po o ai ua fanaua le suāsau?", "Hath the rain a father? or who hath begotten the drops of dew?"]]},
  {num:29,words:[["E sau ea le vaito'a mai le manava o ai? O le sauto'a foi mai le lagi o ai ea na na fanaua?", "Out of whose womb came the ice? and the hoary frost of heaven, who hath gendered it?"]]},
  {num:30,words:[["Ua ufitia le vai e peiseai se maa,", "The waters are hid as with a stone,"], ["ua to'a foi le fogātai.", "and the face of the deep is frozen."]]},
  {num:31,words:[["E te mafai ea ona nonoa i noataga o Kima? Pe te mafaia foi ona tatala i fusi o Kisila?", "Canst thou bind the sweet influences of Pleiades, or loose the bands of Orion?"]]},
  {num:32,words:[["E te mafaia ea ona faaooina mai o Masarota i ona lava po? Pe te mafaia foi ona ta'ita'iina o Asa faatasi ma lana fanau?", "Canst thou bring forth Mazzaroth in his season? or canst thou guide Arcturus with his sons?"]]},
  {num:33,words:[["Ua e iloa ea tulafono i le lagi? Pe na e tuuina atu ea lana pule i le lalolagi?", "Knowest thou the ordinances of heaven? canst thou set the dominion thereof in the earth?"]]},
  {num:34,words:[["E te mafaia ea ona faaooina atu lou leo i ao,", "Canst thou lift up thy voice to the clouds,"], ["ia lofia ai oe i vai e tele?", "that abundance of waters may cover thee?"]]},
  {num:35,words:[["E te mafaia ea ona aauina atu o uila,", "Canst thou send lightnings,"], ["latou te o ai,", "that they may go,"], ["ma latou fai mai ia te oe, Faauta,", "and say unto thee,"], ["o i matou nei?", "Here we are?"]]},
  {num:36,words:[["O ai ea ua tuuina atu le poto i totonu o le tagata? Po ai foi ua na avatu le mafaufau i le loto?", "Who hath put wisdom in the inward parts? or who hath given understanding to the heart?"]]},
  {num:37,words:[["O ai na te mafaia ona faitau o ao i lona poto? Po ai foi na te mafaia ona liligi ifo o fagu o le lagi,", "Who can number the clouds in wisdom? or who can stay the bottles of heaven,"]]},
  {num:38,words:[["pe a liu palapala le efuefu,", "When the dust groweth into hardness,"], ["ma ua pipii faatasi le eleele?", "and the clods cleave fast together?"]]},
  {num:39,words:[["E te mafaia ea ona tuli o se manu ia saeia mā le leona? Pe e te faamaoona i leona taanoa,", "Wilt thou hunt the prey for the lion? or fill the appetite of the young lions,"]]},
  {num:40,words:[["ao latou faapuna i o latou ana,", "When they couch in their dens,"], ["ma nofo lamalama i mea latou te fale ai?", "and abide in the covert to lie in wait?"]]},
  {num:41,words:[["O ai ea na te sauni mā le oreva lana mea e 'ai, pe a fetagisi atu ana tama i le Atua,", "Who provideth for the raven his food? when his young ones cry unto God,"], ["ao sē i latou ina ua leai se mea e 'ai?", "they wander for lack of meat."]]},
];
renderVerseSet(job_ch_38_Verses, 'job-ch38-verses');

var job_ch_39_Verses = [
  {num:1,words:[["Ua e iloa ea ona po e fanau ai le 'oti o le vao o i mato? E le tausia ea aila pe a fananau i latou?", "Knowest thou the time when the wild goats of the rock bring forth? or canst thou mark when the hinds do calve?"]]},
  {num:2,words:[["E te mafaia ea ona faitauina le atoatoa o masina o a latou to? Po o ua e iloa ona po e fananau ai i latou?", "Canst thou number the months that they fulfil? or knowest thou the time when they bring forth?"]]},
  {num:3,words:[["Latou te tootuli,", "They bow themselves,"], ["latou te fananau mai a latou tama,", "they bring forth their young ones,"], ["latou te faateaina o latou tiga.", "they cast out their sorrows."]]},
  {num:4,words:[["E malolosi a latou tama,", "Their young ones are in good liking,"], ["e tutupu,", "they grow up with corn;"], ["i latou i le vao; e o ese atu i latou,", "they go forth,"], ["a e le toe foi mai ia te i latou.", "and return not unto them."]]},
  {num:5,words:[["O ai ea ua auina atu le asini o le vao ia saoloto? O ai ea ua tatalaina mea e noata'i le asini o le vao?", "Who hath sent out the wild ass free? or who hath loosed the bands of the wild ass?"]]},
  {num:6,words:[["O le ua ou tuuina atu i ai le nuu naumati mona fale,", "Whose house I have made the wilderness,"], ["ma le vao lafulafua ma mea e tataa ai?", "and the barren land his dwellings."]]},
  {num:7,words:[["Na te 'ata i le pisapisao o le aai;", "He scorneth the multitude of the city,"], ["na te le faalogo i le alaga o le ta'ita'i asini .", "neither regardeth he the crying of the driver."]]},
  {num:8,words:[["O le mea ua maua i mauga o lana mea e 'ai lea,", "The range of the mountains is his pasture,"], ["ua ia sailiili atu foi i laau iti lauolaola uma.", "and he searcheth after every green thing."]]},
  {num:9,words:[["E mafai ea le rema ona auauna ia te oe? Pe moe i le po i lou fale povi?", "Will the unicorn be willing to serve thee, or abide by thy crib?"]]},
  {num:10,words:[["E te mafai ea ona nonoa o le rema i le atu pue i sona maea? Pe mulimuli o ia ia te oe e faamaluluina ai vanu?", "Canst thou bind the unicorn with his band in the furrow? or will he harrow the valleys after thee?"]]},
  {num:11,words:[["E te faatuatua ea ia te ia ina ua tele lona malosi? Pe e te tuuina atu ia te ia lau galuega?", "Wilt thou trust him, because his strength is great? or wilt thou leave thy labour to him?"]]},
  {num:12,words:[["E te manatu i ai ea na te aumaia au saito,", "Wilt thou believe him, that he will bring home thy seed,"], ["ma faaputuina i lau mea e sasa ai saito?", "and gather it into thy barn?"]]},
  {num:13,words:[["E sausau apaau o le renani, o le apaau ea ma fulufulu o le kasita?", "Gavest thou the goodly wings unto the peacocks? or wings and feathers unto the ostrich?"]]},
  {num:14,words:[["Na te tuu ana fua i le eleele,", "Which leaveth her eggs in the earth,"], ["ma ua faamafanafanaina ai i le efuefu.", "and warmeth them in dust,"]]},
  {num:15,words:[["A ua galo ia te ia pe solia e se vae,", "And forgetteth that the foot may crush them,"], ["pe solipalaina e se manu feai.", "or that the wild beast may break them."]]},
  {num:16,words:[["Ua agavale ia i ana tama,", "She is hardened against her young ones,"], ["e peiseai e le ni ana;", "as though they were not hers:"], ["ua fai fua lana galuega e leai sona atuatuvale.", "her labour is in vain without fear;"]]},
  {num:17,words:[["Auā ua le tuuina atu e le Atua le poto ia te ia;", "Because God hath deprived her of wisdom,"], ["ua ia le tufa atu i ai foi le mafaufau.", "neither hath he imparted to her understanding."]]},
  {num:18,words:[["Pe a tātā ae i luga ona apaau ,", "What time she lifteth up herself on high,"], ["ua 'ata o ia i le solofanua ma le o tietie i ai.", "she scorneth the horse and his rider."]]},
  {num:19,words:[["Na e avatua ea i le solofanua le malosi? Ua e faaofu ea i lona ua i fulufulu maveve?", "Hast thou given the horse strength? hast thou clothed his neck with thunder?"]]},
  {num:20,words:[["Ua e mafai ea ona faaosooso ia te ia e pei o le sē akerise? E maeu le matautia o lona faafogifogi.", "Canst thou make him afraid as a grasshopper? the glory of his nostrils is terrible."]]},
  {num:21,words:[["Ua eli lava ia i le vanu,", "He paweth in the valley,"], ["ua fiafia foi i le malosi;", "and rejoiceth in his strength:"], ["ua alu atu e faafetaiai i le auupega.", "he goeth on to meet the armed men."]]},
  {num:22,words:[["E 'ata o ia i le fefe,", "He mocketh at fear,"], ["e le mata'u lava o ia;", "and is not affrighted;"], ["e le liliu ese foi i le pelu.", "neither turneth he back from the sword."]]},
  {num:23,words:[["Ua taalili i ai le utu e tuu ai u, le tao pupula,", "The quiver rattleth against him,"], ["ma le tao.", "the glittering spear and the shield."]]},
  {num:24,words:[["O le taalili ma le feasofa'i, ua ia folo ai le eleele;", "He swalloweth the ground with fierceness and rage:"], ["e le toe tu filemu pe a lagona le leo o le pu.", "neither believeth he that it is the sound of the trumpet."]]},
  {num:25,words:[["A ilia le pu,", "He saith among the trumpets,"], ["ua ia fai ane ai,", "Ha,"], ["Ue! Ua sogisogi mamao atu foi le taua,", "ha; and he smelleth the battle afar off,"], ["ma le pisapisao o e ta'ita'i 'au,", "the thunder of the captains,"], ["ma le alalaga.", "and the shouting."]]},
  {num:26,words:[["O le atamai ea mai ia te oe, e lele ai le nesa,", "Doth the hawk fly by thy wisdom,"], ["ma fālō atu ai ona apaau i le itu i toga?", "and stretch her wings toward the south?"]]},
  {num:27,words:[["O lau upu ea e lele maualuga ai le aeto,", "Doth the eagle mount up at thy command,"], ["ma fai ai lona ofaga i le mea maualuga?", "and make her nest on high?"]]},
  {num:28,words:[["E nofo o ia ma mau pea i le mato,", "She dwelleth and abideth on the rock,"], ["i luga o le tumutumu o le mato,", "upon the crag of the rock,"], ["ma le tumutumu o le mauga.", "and the strong place."]]},
  {num:29,words:[["Ua ia vaavaai atu mai lea mea i le mea e 'ai,", "From thence she seeketh the prey,"], ["ua vaai mamao atu ai ona mata.", "and her eyes behold afar off."]]},
  {num:30,words:[["E inu lava le toto e ana tama;", "Her young ones also suck up blood:"], ["o le mea foi e i ai le fasi,", "and where the slain are,"], ["o i ai lava ia.", "there is she."]]},
];
renderVerseSet(job_ch_39_Verses, 'job-ch39-verses');

var job_ch_40_Verses = [
  {num:1,words:[["Ua tali mai pea Ieova ia Iopu,", "Moreover the LORD answered Job,"], ["ua faapea mai,", "and said,"]]},
  {num:2,words:[["O lē finau ma Le e ona le malosi uma lava, na te aoai mai ea? O lē faatonu mai i le Atua,", "Shall he that contendeth with the Almighty instruct him? he that reproveth God,"], ["ia tali mai o ia i lea mea.", "let him answer it."]]},
  {num:3,words:[["Ona tali atu ai lea o Iopu ia Ieova,", "Then Job answered the LORD,"], ["ua faapea atu,", "and said,"]]},
  {num:4,words:[["Faauta,", "Behold,"], ["ua faatauvaa lava a'u,", "I am vile;"], ["se a se mea ou te tali atu ai ia te oe? Ou te tuu ae lo'u lima i lo'u gutu.", "what shall I answer thee? I will lay mine hand upon my mouth."]]},
  {num:5,words:[["Ua ou tautala atu faatasi,", "Once have I spoken;"], ["a e ou te le toe tali atu;", "but I will not answer:"], ["ua faalua foi,", "yea, twice;"], ["a e ou te le toe faaopoopo i ai.", "but I will proceed no further."]]},
  {num:6,words:[["Ona tali mai ai lea o Ieova ia Iopu mai le afā,", "Then answered the LORD unto Job out of the whirlwind,"], ["ua faapea mai,", "and said,"]]},
  {num:7,words:[["Ina fusi ia lou sulugatiti e pei o le tagata malosi;", "Gird up thy loins now like a man:"], ["ou te fesili atu ia te oe,", "I will demand of thee,"], ["ina e faailoa mai ia ia te au.", "and declare thou unto me."]]},
  {num:8,words:[["E te faaleaogaina ea la'u lava faatonuga? E te faasala ea ia te au,", "Wilt thou also disannul my judgment? wilt thou condemn me,"], ["ina ia ta'uamiotonuina oe?", "that thou mayest be righteous?"]]},
  {num:9,words:[["Ua ia te oe ea le lima e pei o lo le Atua? Pe e te faititili ea ma le leo e pei o ia?", "Hast thou an arm like God? or canst thou thunder with a voice like him?"]]},
  {num:10,words:[["Ina e teteu ia oe i le mamalu ma le malualii;", "Deck thyself now with majesty and excellency;"], ["ma ia e ofu i le viiga ma le matagofie.", "and array thyself with glory and beauty."]]},
  {num:11,words:[["Ina sasaa solo atu ia le tele o lou ita;", "Cast abroad the rage of thy wrath:"], ["ia e vaai atu foi i e faamaualuga uma lava,", "and behold every one that is proud,"], ["ma ia e faamaulaloina i latou,", "and abase him."]]},
  {num:12,words:[["Vaai atu ia i e faamaualuga uma,", "Look on every one that is proud,"], ["ma ia e faatoilaloina i latou;", "and bring him low;"], ["ia e solipalaina foi o e amio leaga i le mea o i ai i latou.", "and tread down the wicked in their place."]]},
  {num:13,words:[["Ia e tanumia i latou faatasi i le eleele;", "Hide them in the dust together;"], ["ia e fusi o latou mata i le mea lilo.", "and bind their faces in secret."]]},
  {num:14,words:[["Ona ou ta'utino atu ai lea ia te oe, ua mafai ona faaolaina oe i lou lima taumatau.", "Then will I also confess unto thee that thine own right hand can save thee."]]},
  {num:15,words:[["Faauta ea i le pemota,", "Behold now behemoth,"], ["o le na ou faia faatasi ma oe,", "which I made with thee;"], ["na te 'aina le mutia e pei o le povi.", "he eateth grass as an ox."]]},
  {num:16,words:[["Faauta,", "Lo now,"], ["ua i ai lona malosi i lona papātua,", "his strength is in his loins,"], ["ma lona malosi foi ua i ai i mea mălōlō o i lona manava.", "and his force is in the navel of his belly."]]},
  {num:17,words:[["Ua ia faamalo'u i lona iu e pei o le arasi,", "He moveth his tail like a cedar:"], ["ua felavasa'i ua o lona tulaiu.", "the sinews of his stones are wrapped together."]]},
  {num:18,words:[["O ona ivi, o ivi 'apa memea ia;", "His bones are as strong pieces of brass;"], ["o ona ivi e pei o se 'oso uamea.", "his bones are like bars of iron."]]},
  {num:19,words:[["O le sili ia o mea na faia e le Atua;", "He is the chief of the ways of God:"], ["o le na faia o ia ua ia tuu atu i ai lana pelu.", "he that made him can make his sword to approach unto him."]]},
  {num:20,words:[["Auā ua fua mai mea e 'ai mā ia i mauga,", "Surely the mountains bring him forth food,"], ["ua taaalo ai manu feai uma o le vao.", "where all the beasts of the field play."]]},
  {num:21,words:[["Na te taoto i lalo o laau paolo,", "He lieth under the shady trees, in the covert of the reed,"], ["i mea lilo o i ai u ma palapala.", "and fens."]]},
  {num:22,words:[["Ua maluia o ia i le paolo o laau paolo;", "The shady trees cover him with their shadow;"], ["ua siomia o ia i garava i le alia.", "the willows of the brook compass him about."]]},
  {num:23,words:[["Faauta,", "Behold,"], ["a osofia auvai o le vaitafe,", "he drinketh up a river,"], ["na te le sola lava;", "and hasteth not:"], ["e ui ina oso mai Ioritana i lona gutu e le fefe lava ia.", "he trusteth that he can draw up Jordan into his mouth."]]},
  {num:24,words:[["O ai se na te mafaia ona pue ia te ia a o vaai mai? Pe tuia lona isu ao lavea i mailei?", "He taketh it with his eyes: his nose pierceth through snares."]]},
];
renderVerseSet(job_ch_40_Verses, 'job-ch40-verses');

var job_ch_41_Verses = [
  {num:1,words:[["E te mafaia ea ona sisi o leviatana i se mātau, pe taomi lona laulaufaiva i se maea?", "Canst thou draw out leviathan with an hook? or his tongue with a cord which thou lettest down?"]]},
  {num:2,words:[["E te mafaia ea ona tuu se maea i lona isu? Pe tui lona auvae i se mātau?", "Canst thou put an hook into his nose? or bore his jaw through with a thorn?"]]},
  {num:3,words:[["Na te faateleina ea ni tatalo ia te oe? Pe tautala faaoleole ia te oe?", "Will he make many supplications unto thee? will he speak soft words unto thee?"]]},
  {num:4,words:[["Lua te osi ea se feagaiga ma ia? E te avea ea o ia e fai ma auauna e faavavau?", "Will he make a covenant with thee? wilt thou take him for a servant for ever?"]]},
  {num:5,words:[["Lua le taaalo ea ma ia e pei o se manu lele? Pe e te nonoa ia te ia mo outou teine?", "Wilt thou play with him as with a bird? or wilt thou bind him for thy maidens?"]]},
  {num:6,words:[["Pe fai a'i ea se tausamiga e uo? Latou te tufatufa atu ea ia te ia e faatauoa?", "Shall the companions make a banquet of him? shall they part him among the merchants?"]]},
  {num:7,words:[["E te mafaia ea ona velosia ia lilo lona pa'u i mea maamaai? Ma lona ulu i tao so'a i'a?", "Canst thou fill his skin with barbed irons? or his head with fish spears?"]]},
  {num:8,words:[["Tuu atu ia lou lima i luga ia te ia,", "Lay thine hand upon him,"], ["ia manatua le taua;", "remember the battle,"], ["e te le toe faia.", "do no more."]]},
  {num:9,words:[["Faauta,", "Behold,"], ["e fai fua le faamoemoe e maua ia;", "the hope of him is in vain:"], ["e le paū ea foi se tasi i le vaai atu ia te ia?", "shall not one be cast down even at the sight of him?"]]},
  {num:10,words:[["E leai se na te faamalosi e faatei ia te ia;", "None is so fierce that dare stir him up:"], ["o ai foi se tu mai i o'u luma?", "who then is able to stand before me?"]]},
  {num:11,words:[["O ai se na muai aumaia ni mea ia te au,", "Who hath prevented me,"], ["ou te toe taui atu ai? O mea uma lava o i lalo o le lagi o a'u mea ia.", "that I should repay him? whatsoever is under the whole heaven is mine."]]},
  {num:12,words:[["Ou te le natia ona itu tino,", "I will not conceal his parts,"], ["ma le tala i lona malosi,", "nor his power,"], ["ma le matagofie o lona ofutau.", "nor his comely proportion."]]},
  {num:13,words:[["O ai se susue lona ofu aupito i tua? O ai se oo atu i ona atu nifo e lua?", "Who can discover the face of his garment? or who can come to him with his double bridle?"]]},
  {num:14,words:[["O ai se tatala puipui o lona gutu? E matautia ona atu nifo faataaliolio.", "Who can open the doors of his face? his teeth are terrible round about."]]},
  {num:15,words:[["E maeu le malosi o ona talita,", "His scales are his pride,"], ["ua punimau i le faamaufaailoga.", "shut up together as with a close seal."]]},
  {num:16,words:[["Ua sosoo le tasi i le tasi,", "One is so near to another,"], ["e le sao le savili i o latou va.", "that no air can come between them."]]},
  {num:17,words:[["Ua fepiitai le tasi i le tasi,", "They are joined one to another,"], ["ua fesootai,", "they stick together,"], ["ua le mafai ona faatea eseese.", "that they cannot be sundered."]]},
  {num:18,words:[["O ona mafatua ua pupula ai le malamalama;", "By his neesings a light doth shine,"], ["o ona mata foi e pei o laumata o le taeao.", "and his eyes are like the eyelids of the morning."]]},
  {num:19,words:[["E o atu sulu ai lona gutu,", "Out of his mouth go burning lamps,"], ["e oso mai ai aloiafi.", "and sparks of fire leap out."]]},
  {num:20,words:[["E alu atu le asu ai ona pogaiisu e pei o se pani ua tapili i ai le afi ,", "Out of his nostrils goeth smoke,"], ["po o se ulo ua vevela.", "as out of a seething pot or caldron."]]},
  {num:21,words:[["O lana mānava e mu ai malala,", "His breath kindleth coals,"], ["e alu atu foi le afi mumū ai lona gutu.", "and a flame goeth out of his mouth."]]},
  {num:22,words:[["E i ai le malosi i lona ua,", "In his neck remaineth strength,"], ["e saa foi le mata'u i ona luma.", "and sorrow is turned into joy before him."]]},
  {num:23,words:[["Ua maopoopo le aano o lona manava;", "The flakes of his flesh are joined together:"], ["ua maaa lea,", "they are firm in themselves;"], ["e le mafaagaeetia.", "they cannot be moved."]]},
  {num:24,words:[["Ua maaa lona fatumanava e pei o se maa,", "His heart is as firm as a stone; yea,"], ["ua maaa lava e pei o se maaolo aupito i lalo.", "as hard as a piece of the nether millstone."]]},
  {num:25,words:[["A tulai o ia,", "When he raiseth up himself,"], ["ona fefefe ai lea o toa;", "the mighty are afraid:"], ["ua sese i latou ina ua matautuia.", "by reason of breakings they purify themselves."]]},
  {num:26,words:[["E taututa le pelu o lē faasaga atu ia te ia,", "The sword of him that layeth at him cannot hold:"], ["faapea foi le tao,", "the spear,"], ["ma le u fanafana,", "the dart,"], ["ma le tao so'a i'a.", "nor the habergeon."]]},
  {num:27,words:[["Ua tusa ia te ia le uamea ma le 'au o saito,", "He esteemeth iron as straw,"], ["o le 'apa memea o le laau pala lea.", "and brass as rotten wood."]]},
  {num:28,words:[["E le sola o ia i le u fanafana,", "The arrow cannot make him flee:"], ["o maa o le maatā e avea ia ma tagutugutu o saito ia te ia.", "slingstones are turned with him into stubble."]]},
  {num:29,words:[["Ua tusa ia te ia le uatogi ma tagutugutu o saito;", "Darts are counted as stubble:"], ["ua ia 'ata foi i le apoapo o le tao.", "he laugheth at the shaking of a spear."]]},
  {num:30,words:[["Ua i ona lalo fāsi ipu omea maamaai;", "Sharp stones are under him:"], ["na te fofolaina mea matuitui i luga o le palapala.", "he spreadeth sharp pointed things upon the mire."]]},
  {num:31,words:[["Ua ia faapupuna le moana e pei o se ulo;", "He maketh the deep to boil like a pot:"], ["ua ia fai le sami e pei o se ipu uu.", "he maketh the sea like a pot of ointment."]]},
  {num:32,words:[["Ua ia faapupula le ala ua na tuanai;", "He maketh a path to shine after him;"], ["e manatu ai se tasi ua ulusina le moana.", "one would think the deep to be hoary."]]},
  {num:33,words:[["E leai se tasi e tusa ma ia i luga o le laueleele,", "Upon earth there is not his like,"], ["ina ua faia ua leai sona mata'u.", "who is made without fear."]]},
  {num:34,words:[["Ua vaai ifo o ia i mea maualuluga uma;", "He beholdeth all high things:"], ["o ia o le tupu o manu feai uma lava.", "he is a king over all the children of pride."]]},
];
renderVerseSet(job_ch_41_Verses, 'job-ch41-verses');

var job_ch_42_Verses = [
  {num:1,words:[["Ona tali atu ai lea o Iopu ia Ieova,", "Then Job answered the LORD,"], ["ua faapea atu,", "and said,"]]},
  {num:2,words:[["Ua ou iloa e te mafaia mea uma,", "I know that thou canst do every thing,"], ["e le mafai foi ona vaoia se mea e te finagalo i ai.", "and that no thought can be withholden from thee."]]},
  {num:3,words:[["O ai ea lenei ua na faapouliuligia lau pule ma le le iloa? Auā ua ou tautala atu ma lo'u le mafaufau,", "Who is he that hideth counsel without knowledge? therefore have I uttered that I understood not;"], ["o mea ua sili ona faigata ia te au,", "things too wonderful for me,"], ["na ou le iloa lava.", "which I knew not."]]},
  {num:4,words:[["Ia e faafofoga mai,", "Hear,"], ["o a'u ou te tautala atu ai;", "I beseech thee,"], ["ou te fesili atu ia te oe,", "and I will speak: I will demand of thee,"], ["a ia e faailoa mai ia te au.", "and declare thou unto me."]]},
  {num:5,words:[["Sa ou faalogo ia te oe i le faalogo o o'u taliga; a o lenei,", "I have heard of thee by the hearing of the ear:"], ["ua vaai atu o'u mata ia te oe;", "but now mine eye seeth thee."]]},
  {num:6,words:[["o le mea lea ua ou 'ino'ino ai ia te au ,", "Wherefore I abhor myself,"], ["ua ou salamo foi i le efuefu ma le lefulefu.", "and repent in dust and ashes."]]},
  {num:7,words:[["Ua mavae ona fetalai mai e Ieova o ia upu ia Iopu,", "And it was so,"], ["ona faapea ane lea o Ieova ia Elifasa le Timanu,", "that after the LORD had spoken these words unto Job,"], ["Ua tupu lo'u ita ia te oe,", "the LORD said to Eliphaz the Temanite, My wrath is kindled against thee,"], ["ma au uo e toalua;", "and against thy two friends:"], ["ina ua outou le tautalatala ma le tonu ia te au,", "for ye have not spoken of me the thing that is right,"], ["e faapei o la'u auauna o Iopu.", "as my servant Job hath."]]},
  {num:8,words:[["O le mea lea ia outou ave ai povi poa taanoa e fitu,", "Therefore take unto you now seven bullocks and seven rams,"], ["ma mamoe poa e fitu,", "and go to my servant Job,"], ["ma outou o ane i la'u auauna o Iopu;", "and offer up for yourselves a burnt offering;"], ["ia outou fai a'i le taulaga mu mo outou;", "and my servant Job shall pray for you:"], ["ona tatalo lea la'u auauna o Iopu mo outou; auā ou te talia o ia;", "for him will I accept:"], ["ina ne'i ou taui atu ia te outou lo outou valea,", "lest I deal with you after your folly,"], ["auā ua outou le tautalatala ma le tonu ia te au,", "in that ye have not spoken of me the thing which is right,"], ["e faapei o la'u auauna o Iopu.", "like my servant Job."]]},
  {num:9,words:[["Ona o ane ai lea o Elifasa le Timanu,", "So Eliphaz the Temanite and Bildad the Shuhite and Zophar the Naamathite went,"], ["ma Pilitati le Sua, ma Sofara le Naama,", "and did according as the LORD commanded them:"], ["ma latou faia e tusa ma mea na fetalai ane ai Ieova ia te i latou. Ua talia foi Iopu e Ieova.", "the LORD also accepted Job."]]},
  {num:10,words:[["Ua uma ona tatalo Iopu mo ana uo,", "And the LORD turned the captivity of Job,"], ["ona faaae ai lea e Ieova o lana tafeaga. Ua toe au mai foi e Ieova o mea ia Iopu ua faateleina,", "when he prayed for his friends:"], ["ua lua mea i mea uma na muai ia te ia.", "also the LORD gave Job twice as much as he had before."]]},
  {num:11,words:[["Ona o mai lea ia te ia ona uso uma,", "Then came there unto him all his brethren,"], ["ma ona tuafafine uma,", "and all his sisters,"], ["ma i latou uma sa muai masani ma ia;", "and all they that had been of his acquaintance before,"], ["ua latou aai foi faatasi ma ia o mea e ai i lona fale;", "and did eat bread with him in his house: and they bemoaned him,"], ["ua latou faamafanafana foi ia te ia,", "and comforted him over all the evil that the LORD had brought upon him:"], ["ma faamatalaloto ia te ia ona o mala uma na faaoo mai e Ieova ia te ia. Ua foai mai foi ia te ia e i latou taitoatasi le tupe e tasi,", "every man also gave him a piece of money,"], ["taitoatasi foi ma le mama auro e tasi.", "and every one an earring of gold."]]},
  {num:12,words:[["Ua sili foi ona faamanuia e Ieova o le gataaga o Iopu i lona amataga;", "So the LORD blessed the latter end of Job more than his beginning:"], ["auā sa ia te ia mamoe e sefulu afe ma afe e fa,", "for he had fourteen thousand sheep,"], ["ma kamela e ono afe,", "and six thousand camels,"], ["ma povi e lua afe,", "and a thousand yoke of oxen,"], ["ma asini fafine e tasi le afe.", "and a thousand she asses."]]},
  {num:13,words:[["Sa ia te ia foi atalii e toafitu, ma afafine e toatolu.", "He had also seven sons and three daughters."]]},
  {num:14,words:[["Ua ia faaigoa foi le tasi o Iemaima,", "And he called the name of the first, Jemima;"], ["ma le igoa o lona lua o Kesia,", "and the name of the second, Kezia;"], ["ma le igoa o lona toatolu o Kerenapuka.", "and the name of the third, Keren-happuch."]]},
  {num:15,words:[["E lei iloa foi i le nuu uma ni fafine lalelei e tusa ma afafine o Iopu. Ua avatu foi ia te i latou e lo latou tamā o tofi faatasi ma o latou tuagane.", "And in all the land were no women found so fair as the daughters of Job: and their father gave them inheritance among their brethren."]]},
  {num:16,words:[["Ona ola pea lea o Iopu,", "After this lived Job an hundred and forty years,"], ["ina ua mavae o ia mea,", "and saw his sons,"], ["o tausaga e tasi le selau ma le fa o sefulu. Ua ia iloa foi ona atalii, ma atalii o ona atalii,", "and his sons' sons,"], ["e oo atu i tupulaga e fa.", "even four generations."]]},
  {num:17,words:[["Ona oti lea o Iopu, ua toeaina,", "So Job died,"], ["ma ua tuutulu'i lona ola.", "being old and full of days."]]},
];
renderVerseSet(job_ch_42_Verses, 'job-ch42-verses');

